import { RawNote, StrettoCandidate, StrettoError, StrettoGrade } from '../../types';
import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel } from './midiSpelling';

const SEMIS_P8 = 12;
const SEMIS_P5 = 7;
const SEMIS_P4 = 5;

// Strict counterpoint intervals
const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7 (P4 handled conditionally)
const PERFECT_CONSONANCES = [0, 7]; // P1, P5 (P8 is 0 mod 12)

interface VoiceEvent {
    tick: number;
    pitch1: number; // Subject
    pitch2: number; // Answer (Transposed Subject)
    hasAttack1: boolean;
    hasAttack2: boolean;
}

function getVerticalIntervals(subject: RawNote[], answer: RawNote[]): VoiceEvent[] {
    // 1. Collect all unique time points where anything happens (attack or release)
    // Actually, we mostly care about attacks and sustain checks.
    // Let's create a timeline map.
    const timePoints = new Set<number>();
    [...subject, ...answer].forEach(n => {
        timePoints.add(n.ticks);
        // Also add points where notes might end if we need to check passing resolution?
        // For simple strict checks, checking at attack points is usually sufficient, 
        // plus maybe check on beat if we want to be very strict.
    });

    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);
    const events: VoiceEvent[] = [];

    sortedPoints.forEach(t => {
        const n1 = subject.find(n => n.ticks <= t && (n.ticks + n.durationTicks) > t);
        const n2 = answer.find(n => n.ticks <= t && (n.ticks + n.durationTicks) > t);

        if (n1 && n2) {
            events.push({
                tick: t,
                pitch1: n1.midi,
                pitch2: n2.midi,
                hasAttack1: n1.ticks === t,
                hasAttack2: n2.ticks === t
            });
        }
    });

    return events;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    // Simple logic: Measure start or half-measure in 4/4
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;

    if (pos === 0) return true; // Downbeat

    // Beat 3 in 4/4
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;

    // Beat 1 in 3/4 (already caught)

    return false; 
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number }
): StrettoCandidate {

    // 1. Create Answer Voice
    const answer: RawNote[] = subject.map(n => ({
        ...n,
        ticks: n.ticks + delayTicks,
        midi: n.midi + intervalSemis,
        name: getStrictPitchName(n.midi + intervalSemis),
        voiceIndex: 1
    }));

    // 2. Identify Overlap Period
    // We only analyze the period where BOTH voices are active
    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(...subject.map(n => n.ticks + n.durationTicks));
    const endOverlap = subjectEnd; // The stretto is valid until the subject finishes, typically

    if (startOverlap >= endOverlap) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [{ tick: 0, timeFormatted: '-', type: 'Consecutive Dissonance', details: 'No overlap', severity: 'fatal' }],
            notes: []
        };
    }

    const events = getVerticalIntervals(subject, answer);
    const errors: StrettoError[] = [];

    let consecutiveDissCount = 0;
    let prevDissType: string | null = null;
    let prevInterval: number | null = null;
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    events.forEach(ev => {
        // Skip check if before delay (though getVerticalIntervals handles this)
        if (ev.tick < startOverlap) return;

        const p1 = ev.pitch1;
        const p2 = ev.pitch2;
        const interval = Math.abs(p1 - p2);
        const intervalClass = interval % 12;

        const isBass1 = p1 < p2;
        // P4 is dissonant if against bass
        const isP4 = intervalClass === 5;
        const isDiss = DISSONANT_INTERVALS.includes(intervalClass) || isP4; // Treat all P4 as dissonant for strictness or assume bass check?
        // Let's assume strict 2-part writing: P4 is dissonant.

        const timeStr = getFormattedTime(ev.tick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(ev.tick, ppq, ts.num, ts.den);

        // --- CHECK 1: PARALLELISM ---
        if (prevInterval !== null && prevP1 !== null && prevP2 !== null) {
            const isParallelMotion = (p1 - prevP1) * (p2 - prevP2) > 0; // Same direction
            const isPerfect = intervalClass === 0 || intervalClass === 7; // P1, P8, P5

            if (isPerfect && isParallelMotion) {
                // Check if previous was also the same perfect interval
                const prevClass = prevInterval % 12;
                if (prevClass === intervalClass) {
                    const type = intervalClass === 0 ? 'Parallel 8ve' : 'Parallel 5th';
                    // Strict Rule: No parallels at all
                    errors.push({
                        tick: ev.tick, timeFormatted: timeStr, type: type as any,
                        details: `${getStrictPitchName(p1)}/${getStrictPitchName(p2)} moves parallel to perfect interval.`,
                        severity: onStrong ? 'fatal' : 'warning' // Strong beat parallels are fatal
                    });
                }
            }

            // --- CHECK 2: DIRECT 5ths/8ves ---
            if (isPerfect && isParallelMotion && onStrong) {
                // Direct motion into perfect on strong beat
                // Check soprano leap (Upper voice)
                const upperVoiceMove = isBass1 ? Math.abs(p2 - prevP2) : Math.abs(p1 - prevP1);
                if (upperVoiceMove > 2) { // Leap > Major 2nd
                    const type = intervalClass === 0 ? 'Direct 8ve' : 'Direct 5th';
                    errors.push({
                        tick: ev.tick, timeFormatted: timeStr, type: type as any,
                        details: `Similar motion into perfect interval with leap in upper voice.`,
                        severity: 'warning' // "Strong Stretto" forbids this
                    });
                }
            }
        }

        // --- CHECK 3: DISSONANCE ---
        if (isDiss) {
            consecutiveDissCount++;

            // Consecutive Unresolved Dissonance on Beat
            if (onStrong && prevDissType === 'dissonance') {
                 errors.push({
                    tick: ev.tick, timeFormatted: timeStr, type: 'Unresolved Dissonance',
                    details: `Consecutive dissonance on strong beat.`,
                    severity: 'fatal'
                });
            }

            if (consecutiveDissCount > 2) {
                 errors.push({
                    tick: ev.tick, timeFormatted: timeStr, type: 'Consecutive Dissonance',
                    details: `More than 2 consecutive dissonant events.`,
                    severity: 'fatal'
                });
            }

            prevDissType = 'dissonance';
        } else {
            consecutiveDissCount = 0;
            prevDissType = 'consonance';
        }

        prevInterval = interval;
        prevP1 = p1;
        prevP2 = p2;
    });

    // Grading Logic
    let grade: StrettoGrade = 'STRONG';

    // Fatal errors -> Invalid
    if (errors.some(e => e.severity === 'fatal')) {
        grade = 'INVALID';
    } 
    // Warnings (like Direct 5ths or off-beat parallels if loose) -> Viable
    else if (errors.length > 0) {
        grade = 'VIABLE';
    }

    let intLabel = getIntervalLabel(Math.abs(intervalSemis));
    if (intervalSemis < 0) intLabel = '-' + intLabel;
    else if (intervalSemis > 0) intLabel = '+' + intLabel;

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: [...subject, ...answer]
    };
}

import { RawNote } from '../../types';

// Simple map for note names to MIDI, centered on C4 = 60
const BASE_MIDI: Record<string, number> = {
    'C': 60, 'D': 62, 'E': 64, 'F': 65, 'G': 67, 'A': 69, 'B': 71,
    'c': 72, 'd': 74, 'e': 76, 'f': 77, 'g': 79, 'a': 81, 'b': 83
};

export function parseSimpleAbc(abcString: string, ppq: number = 480): RawNote[] {
    // This is a very rudimentary parser designed for single-voice subjects
    // Handles: Pitch (C, c, c', C,), Accidentals (^, _, =), Length (2, /2, 3/2)

    const clean = abcString.replace(/\|/g, '').replace(/\s+/g, ' '); // Remove bars and extra whitespace

    // Regex to match ABC token: 
    // [Accidental][Note][Octave][Length]
    // Accidental: ^, ^^, _, __, =
    // Note: A-G, a-g
    // Octave: ', ,, 
    // Length: number, /number, number/number

    const regex = /([\^=_]*)?([a-gA-G])([,']*)?([0-9]*\/?[0-9]*)?/g;

    const notes: RawNote[] = [];
    let currentTick = 0;
    let match;

    // Default L:1/4 assumed for now if not parsed from header
    // We treat 1 unit = 1 quarter note = ppq
    const defaultDuration = ppq; 

    while ((match = regex.exec(clean)) !== null) {
        if (match[0] === '') continue;

        const accStr = match[1] || '';
        const letter = match[2];
        const octStr = match[3] || '';
        const lenStr = match[4] || '';

        let midi = BASE_MIDI[letter];

        // Accidentals
        if (accStr.includes('^^')) midi += 2;
        else if (accStr.includes('^')) midi += 1;
        else if (accStr.includes('__')) midi -= 2;
        else if (accStr.includes('_')) midi -= 1;
        // Natural '=' does nothing in this simple parser context (relative to C major)

        // Octaves
        if (octStr) {
            const up = (octStr.match(/'/g) || []).length;
            const down = (octStr.match(/,/g) || []).length;
            midi += (up * 12) - (down * 12);
        }

        // Duration
        let mult = 1.0;
        if (lenStr) {
            if (lenStr === '/') mult = 0.5;
            else if (lenStr.includes('/')) {
                const [n, d] = lenStr.split('/');
                const num = n === '' ? 1 : parseFloat(n);
                const den = d === '' ? 2 : parseFloat(d);
                mult = num / den;
            } else {
                mult = parseFloat(lenStr);
            }
        }

        const durationTicks = Math.round(defaultDuration * mult);

        notes.push({
            midi,
            ticks: currentTick,
            durationTicks,
            velocity: 0.8,
            name: `${letter}${accStr}${octStr}`,
            isOrnament: false
        });

        currentTick += durationTicks;
    }

    return notes;
}

import React, { useState, useMemo } from 'react';
import { RawNote, StrettoConfig, StrettoCandidate } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate } from './services/strettoCore';
import { PlayIcon, StopIcon } from './Icons';
import { playTrack, stopPlayback } from './midiPlaybackService';

interface StrettoViewProps {
    notes: RawNote[]; // From MIDI
    ppq: number;
    ts: { num: number, den: number };
}

const INTERVAL_OPTIONS = [
    { label: 'Unison (P1)', val: 0 },
    { label: '+ Octave (P8)', val: 12 },
    { label: '- Octave (P8)', val: -12 },
    { label: '+ 2 Octaves', val: 24 },
    { label: '- 2 Octaves', val: -24 },
    { label: '+ Perf 5th', val: 7 },
    { label: '- Perf 5th', val: -7 },
    { label: '+ Perf 4th', val: 5 },
    { label: '- Perf 4th', val: -5 },
];

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("c2 G c d e f g3 a b c'2");
    const [config, setConfig] = useState<number[]>([0, 12, -12, 7, -7]);
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [isPlaying, setIsPlaying] = useState(false);

    // Prepare Subject
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; // Use track notes
    }, [mode, abcInput, initialNotes, ppq]);

    // Run Analysis
    const results = useMemo(() => {
        if (subjectNotes.length === 0) return [];

        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        const beatTicks = ppq; // Assume quarter beat for search step

        config.forEach(interval => {
            // Search every beat
            for (let d = beatTicks; d <= maxDelay; d += beatTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, d, ppq, ts));
            }
        });

        return candidates;
    }, [subjectNotes, config, ppq, ts]);

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }

        // Construct a mock MIDI object structure for the player
        const mockMidi: any = {
            header: { tempos: [{ bpm: 120 }], ppq },
            tracks: [{
                notes: notes.map(n => ({
                    ...n,
                    time: n.ticks * (0.5 / ppq), // Rough approx for player
                    duration: n.durationTicks * (0.5 / ppq)
                }))
            }]
        };

        playTrack(mockMidi, () => setIsPlaying(false));
        setIsPlaying(true);
    };

    const handleGenerateChain = () => {
        const strong = results.filter(r => r.grade === 'STRONG');
        const prompt = `
I have a fugal subject (ABC): ${abcInput || "(MIDI Data)"}
I need a stretto maestrale chain.
Here are valid overlap options verified by code:
${strong.slice(0, 5).map(r => `- Interval ${r.intervalLabel} at ${r.delayBeats} beats delay`).join('\n')}

Please construct a continuous 4-voice stretto chain in ABC notation using these overlaps.
        `.trim();
        navigator.clipboard.writeText(prompt);
        alert("Prompt copied to clipboard! Paste into Gemini.");
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up">
            <h2 className="text-2xl font-bold text-gray-light mb-6">Stretto Assembly Lab</h2>

            {/* Input Selection */}
            <div className="flex gap-4 mb-6">
                <button onClick={() => setMode('midi')} className={`px-4 py-2 rounded ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-800 text-gray-400'}`}>Use Selected MIDI Track</button>
                <button onClick={() => setMode('abc')} className={`px-4 py-2 rounded ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-800 text-gray-400'}`}>Use ABC Notation</button>
            </div>

            {mode === 'abc' && (
                <div className="mb-6">
                    <label className="block text-sm text-gray-400 mb-2">Subject ABC</label>
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-white font-mono h-24"
                    />
                </div>
            )}

            {/* Config */}
            <div className="mb-6 p-4 bg-gray-800 rounded border border-gray-700">
                <h3 className="text-sm font-bold text-gray-300 mb-2">Search Intervals</h3>
                <div className="flex flex-wrap gap-2">
                    {INTERVAL_OPTIONS.map(opt => (
                        <label key={opt.val} className="flex items-center bg-gray-900 px-3 py-1 rounded cursor-pointer border border-gray-700 hover:border-gray-500">
                            <input 
                                type="checkbox" 
                                checked={config.includes(opt.val)}
                                onChange={e => {
                                    if(e.target.checked) setConfig([...config, opt.val]);
                                    else setConfig(config.filter(c => c !== opt.val));
                                }}
                                className="mr-2"
                            />
                            <span className="text-sm text-gray-300">{opt.label}</span>
                        </label>
                    ))}
                </div>
            </div>

            {/* Matrix / Results */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* List View of Candidates */}
                <div className="bg-gray-900 border border-gray-700 rounded h-[500px] overflow-y-auto p-2">
                    <h3 className="text-lg font-bold text-gray-300 mb-4 sticky top-0 bg-gray-900 pb-2 border-b border-gray-700">Candidates ({results.length})</h3>
                    <div className="grid grid-cols-4 gap-2 mb-2 text-xs text-gray-500 px-2">
                        <span>Interval</span><span>Delay</span><span>Grade</span><span>Errors</span>
                    </div>
                    {results.map((r, i) => (
                        <div 
                            key={i}
                            onClick={() => setSelectedCandidate(r)}
                            className={`grid grid-cols-4 gap-2 p-2 rounded cursor-pointer border-b border-gray-800 hover:bg-gray-800 transition-colors ${selectedCandidate === r ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                        >
                            <span className="font-bold text-brand-primary">{r.intervalLabel}</span>
                            <span className="text-gray-300">{r.delayBeats} beats</span>
                            <span className={`text-xs font-bold px-1 rounded w-fit ${r.grade === 'STRONG' ? 'bg-green-900 text-green-300' : r.grade === 'VIABLE' ? 'bg-yellow-900 text-yellow-300' : 'bg-red-900 text-red-300'}`}>
                                {r.grade}
                            </span>
                            <span className="text-xs text-gray-500">{r.errors.length} errs</span>
                        </div>
                    ))}
                </div>

                {/* Inspector */}
                <div className="bg-gray-800 border border-gray-700 rounded p-4 flex flex-col">
                    {selectedCandidate ? (
                        <>
                            <div className="flex justify-between items-start mb-4">
                                <div>
