import React, { useState, useMemo } from 'react';
import { RawNote, StrettoConfig, StrettoCandidate, PianoRollTrackData } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate } from './services/strettoCore';
import { PlayIcon, StopIcon } from './Icons';
import { playTrack, stopPlayback } from './midiPlaybackService';
import PianoRoll from './PianoRoll';

interface StrettoViewProps {
    notes: RawNote[]; // From MIDI
    ppq: number;
    ts: { num: number, den: number };
}

const INTERVAL_OPTIONS = [
    { label: 'Unison (P1)', val: 0 },
    { label: '+ Octave (P8)', val: 12 },
    { label: '- Octave (P8)', val: -12 },
    { label: '+ 2 Octaves', val: 24 },
    { label: '- 2 Octaves', val: -24 },
    { label: '+ Perf 5th', val: 7 },
    { label: '- Perf 5th', val: -7 },
    { label: '+ Perf 4th', val: 5 },
    { label: '- Perf 4th', val: -5 },
];

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("c2 G c d e f g3 a b c'2");
    const [config, setConfig] = useState<number[]>([0, 12, -12, 7, -7]);
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
    const [isPlaying, setIsPlaying] = useState(false);

    // Prepare Subject
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; // Use track notes
    }, [mode, abcInput, initialNotes, ppq]);

    // Run Analysis
    const results = useMemo(() => {
        if (subjectNotes.length === 0) return [];

        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        const beatTicks = ppq; // Assume quarter beat for search step

        config.forEach(interval => {
            // Search every beat
            for (let d = beatTicks; d <= maxDelay; d += beatTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, d, ppq, ts));
            }
        });

        return candidates;
    }, [subjectNotes, config, ppq, ts]);

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }

        // Construct a mock MIDI object structure for the player
        const mockMidi: any = {
            header: { tempos: [{ bpm: 120 }], ppq },
            tracks: [{
                notes: notes.map(n => ({
                    ...n,
                    time: n.ticks * (0.5 / ppq), // Rough approx for player
                    duration: n.durationTicks * (0.5 / ppq)
                }))
            }]
        };

        playTrack(mockMidi, () => setIsPlaying(false));
        setIsPlaying(true);
    };

    const handleGenerateChain = () => {
        // Collect either the checked items OR the single selected item (if nothing checked)
        const activeIds = checkedIds.size > 0 ? Array.from(checkedIds) : (selectedCandidate ? [selectedCandidate.id] : []);
        const activeCandidates = results.filter(r => activeIds.includes(r.id));

        if (activeCandidates.length === 0) {
            alert("Please select at least one stretto candidate to assemble.");
            return;
        }

        const prompt = `
I have a fugal subject (ABC): ${abcInput || "(MIDI Data)"}
I need a stretto maestrale chain.
Here are the selected valid overlap options verified by code:
${activeCandidates.map(r => `- Interval ${r.intervalLabel} at ${r.delayBeats} beats delay (${r.grade})`).join('\n')}

Please construct a continuous multi-voice stretto chain in ABC notation using a combination of these overlaps.
        `.trim();
        navigator.clipboard.writeText(prompt);
        alert(`Prompt for ${activeCandidates.length} candidates copied to clipboard!`);
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    // Construct visualization data for the inspector
    const pianoRollData: PianoRollTrackData | null = useMemo(() => {
        if (!selectedCandidate) return null;
        return {
            name: `Stretto ${selectedCandidate.intervalLabel}`,
            ppq,
            timeSignature: { numerator: ts.num, denominator: ts.den },
            notes: selectedCandidate.notes.map(n => ({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: n.velocity,
                name: n.name,
                // Assign explicit voice index: 0 for subject (first half), 1 for answer (second half)
                // note: selectedCandidate.notes is [...subject, ...answer]
                voiceIndex: n.voiceIndex ?? 0, 
                isOrnament: false
            }))
        };
    }, [selectedCandidate, ppq, ts]);

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up">
            <h2 className="text-2xl font-bold text-gray-light mb-6">Stretto Assembly Lab</h2>

            {/* Input Selection */}
            <div className="flex gap-4 mb-6">
                <button onClick={() => setMode('midi')} className={`px-4 py-2 rounded ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-800 text-gray-400'}`}>Use Selected MIDI Track</button>
                <button onClick={() => setMode('abc')} className={`px-4 py-2 rounded ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-800 text-gray-400'}`}>Use ABC Notation</button>
            </div>

            {mode === 'abc' && (
                <div className="mb-6">
                    <label className="block text-sm text-gray-400 mb-2">Subject ABC</label>
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-white font-mono h-24"
                    />
                </div>
            )}

            {/* Config */}
            <div className="mb-6 p-4 bg-gray-800 rounded border border-gray-700">
                <h3 className="text-sm font-bold text-gray-300 mb-2">Search Intervals</h3>
                <div className="flex flex-wrap gap-2">
                    {INTERVAL_OPTIONS.map(opt => (
                        <label key={opt.val} className="flex items-center bg-gray-900 px-3 py-1 rounded cursor-pointer border border-gray-700 hover:border-gray-500">
                            <input 
                                type="checkbox" 
                                checked={config.includes(opt.val)}
                                onChange={e => {
                                    if(e.target.checked) setConfig([...config, opt.val]);
                                    else setConfig(config.filter(c => c !== opt.val));
                                }}
                                className="mr-2"
                            />
                            <span className="text-sm text-gray-300">{opt.label}</span>
                        </label>
                    ))}
                </div>
            </div>

            {/* Matrix / Results */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* List View of Candidates */}
                <div className="bg-gray-900 border border-gray-700 rounded h-[600px] overflow-y-auto p-2">
                    <h3 className="text-lg font-bold text-gray-300 mb-4 sticky top-0 bg-gray-900 pb-2 border-b border-gray-700 z-10 flex justify-between items-center">
                        <span>Candidates ({results.length})</span>
                        {checkedIds.size > 0 && <span className="text-xs text-brand-primary">{checkedIds.size} selected</span>}
                    </h3>
                    <div className="grid grid-cols-12 gap-2 mb-2 text-xs text-gray-500 px-2 font-bold">
                        <span className="col-span-1 text-center">Sel</span>
                        <span className="col-span-3">Interval</span>
                        <span className="col-span-3">Delay</span>
                        <span className="col-span-2">Grade</span>
                        <span className="col-span-3">Errors</span>
                    </div>
                    {results.map((r, i) => (
                        <div 
                            key={i}
                            onClick={() => setSelectedCandidate(r)}
                            className={`grid grid-cols-12 gap-2 p-2 rounded cursor-pointer border-b border-gray-800 hover:bg-gray-800 transition-colors items-center ${selectedCandidate === r ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                        >
                            <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                <input 
                                    type="checkbox" 
                                    checked={checkedIds.has(r.id)} 
                                    onChange={() => toggleCheck(r.id)}
                                    className="rounded bg-gray-700 border-gray-600 text-brand-primary focus:ring-0"
                                />
                            </div>
                            <span className="col-span-3 font-bold text-brand-primary">{r.intervalLabel}</span>
                            <span className="col-span-3 text-gray-300">{r.delayBeats} beats</span>
                            <div className="col-span-2">
                                <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded w-fit ${r.grade === 'STRONG' ? 'bg-green-900 text-green-300' : r.grade === 'VIABLE' ? 'bg-yellow-900 text-yellow-300' : 'bg-red-900 text-red-300'}`}>
                                    {r.grade}
                                </span>
                            </div>
                            <span className="col-span-3 text-xs text-gray-500">{r.errors.length > 0 ? `${r.errors.length} issues` : '-'}</span>
                        </div>
                    ))}
                </div>

                {/* Inspector */}
                <div className="bg-gray-800 border border-gray-700 rounded p-4 flex flex-col h-[600px]">
                    {selectedCandidate && pianoRollData ? (
                        <>
                            <div className="flex justify-between items-start mb-4">
                                <div>
                                    <h3 className="text-xl font-bold text-white">
                                        Stretto: {selectedCandidate.intervalLabel} @ {selectedCandidate.delayBeats}B
                                    </h3>
                                    <p className={`text-sm font-bold ${selectedCandidate.grade === 'STRONG' ? 'text-green-400' : selectedCandidate.grade === 'VIABLE' ? 'text-yellow-400' : 'text-red-400'}`}>
                                        Verdict: {selectedCandidate.grade}
                                    </p>
                                </div>
                                <button onClick={() => handlePlay(selectedCandidate.notes)} className="bg-brand-primary p-2 rounded-full hover:bg-brand-secondary transition-transform active:scale-95">
                                    {isPlaying ? <StopIcon className="w-6 h-6 text-white"/> : <PlayIcon className="w-6 h-6 text-white"/>}
                                </button>
                            </div>

                            {/* Piano Roll Visualization */}
                            <div className="h-48 bg-gray-900 rounded border border-gray-700 mb-4 overflow-hidden shadow-inner relative">
                                <PianoRoll trackData={pianoRollData} />
                                <div className="absolute top-2 right-2 flex flex-col gap-1 text-[10px] bg-black/50 p-1.5 rounded">
                                    <span className="text-blue-400 font-bold">■ Subject</span>
                                    <span className="text-red-400 font-bold">■ Answer</span>
                                </div>
                            </div>

                            {/* Error Log */}
                            <div className="flex-grow overflow-y-auto mb-4 bg-gray-900 rounded p-2 border border-gray-700">
                                {selectedCandidate.errors.length === 0 ? (
                                    <div className="text-green-400 flex items-center justify-center h-full flex-col opacity-70">
                                        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-12 h-12 mb-2">
                                          <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75L11.25 15 15 9.75M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                                        </svg>
                                        <p>No Counterpoint Errors</p>
                                    </div>
                                ) : (
                                    <ul className="space-y-2">
                                        {selectedCandidate.errors.map((e, idx) => (
                                            <li key={idx} className="text-sm border-l-2 pl-2 border-red-500 bg-red-900/10 p-1 rounded-r">
                                                <div className="flex justify-between">
                                                    <span className="text-red-300 font-bold">{e.type}</span>
                                                    <span className="text-gray-500 font-mono text-xs">[{e.timeFormatted}]</span>
                                                </div>
                                                <p className="text-gray-400 text-xs">{e.details}</p>
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>

                            <button onClick={handleGenerateChain} className="w-full py-3 bg-gray-700 hover:bg-gray-600 text-white font-bold rounded shadow-lg border border-gray-600">
                                {checkedIds.size > 0 
                                    ? `Assemble Chain from ${checkedIds.size} Selected` 
                                    : "Assemble Chain from Current Candidate"}
                            </button>
                        </>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-gray-500">
                            <span className="text-4xl mb-2">🎹</span>
                            <p>Select a candidate to visualize.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

