import { useState, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { StrettoCandidate, RawNote } from '../types';
import { parseSimpleAbc } from '../components/services/abcBridge';

interface UseStrettoAssemblyProps {
    notes: RawNote[];
    ppq: number;
}

export const useStrettoAssembly = ({ notes: subjectNotes, ppq }: UseStrettoAssemblyProps) => {
    const [isAssembling, setIsAssembling] = useState(false);
    const [assemblyStatus, setAssemblyStatus] = useState<string>('');
    const [assemblyResult, setAssemblyResult] = useState<string>('');
    const [assemblyLog, setAssemblyLog] = useState<string[]>([]);
    const [attemptCount, setAttemptCount] = useState(0);

    const runAssembly = useCallback(async (
        candidates: StrettoCandidate[], 
        abcInput: string
    ) => {
        if (candidates.length === 0) {
            alert("Please select at least one stretto candidate.");
            return;
        }

        setIsAssembling(true);
        setAssemblyLog([]);
        setAttemptCount(1);
        setAssemblyResult('');

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const systemPrompt = `You are a master of fugal counterpoint. 
Task: Assemble a 4-voice stretto maestrale chain in ABC notation.
Rules:
1. Use the provided Subject ABC as the theme.
2. You MUST use the specific validated overlap intervals and delays provided.
3. Separate voices clearly using V:1, V:2, etc.
4. Output ONLY valid ABC notation. No conversational text.`;

        let currentInput = `Subject ABC: ${abcInput}\nValidated Overlaps:\n${candidates.map(r => `- ${r.intervalLabel} at ${r.delayBeats} beats`).join('\n')}\n\nConstruct the chain now.`;

        try {
            for (let i = 1; i <= 3; i++) {
                setAttemptCount(i);
                setAssemblyStatus(`Attempt ${i}: Querying Gemini...`);

                const response = await ai.models.generateContent({
                    model: 'gemini-3-pro-preview',
                    contents: currentInput,
                    config: { systemInstruction: systemPrompt }
                });

                const generatedAbc = response.text || '';
                setAssemblyResult(generatedAbc);
                setAssemblyStatus(`Attempt ${i}: Verifying counterpoint...`);

                // Algorithmic Verification (Basic Parse Check)
                const genNotes = parseSimpleAbc(generatedAbc, ppq);
                const errors: string[] = [];

                // Heuristic: Result length should roughly match subject length * num_voices
                if (genNotes.length < subjectNotes.length * 1.5) {
                    errors.push("Output seems truncated or empty.");
                }

                if (errors.length === 0 || i === 3) {
                    setAssemblyLog(prev => [...prev, `Pass ${i}: ${errors.length === 0 ? "Verified Successful" : "Final Attempt Reached"}`]);
                    setAssemblyStatus('Assembly Complete');
                    break;
                } else {
                    setAssemblyLog(prev => [...prev, `Pass ${i}: Failed verification. Issues: ${errors.join(', ')}`]);
                    currentInput = `The previous ABC had the following issues: ${errors.join('. ')}. Please correct and try again.\n\nPrevious ABC:\n${generatedAbc}`;
                }
            }
        } catch (err) {
            console.error(err);
            setAssemblyStatus('Error during assembly.');
            setAssemblyLog(prev => [...prev, `Error: ${err instanceof Error ? err.message : String(err)}`]);
        } finally {
            setIsAssembling(false);
        }
    }, [ppq, subjectNotes]);

    return {
        isAssembling,
        assemblyStatus,
        assemblyResult,
        assemblyLog,
        attemptCount,
        setAssemblyResult,
        runAssembly
    };
};

import * as Tone from 'tone';
import { Midi } from '@tonejs/midi';

// We use a union type for the instrument to handle both Sampler and Synth
let instrument: Tone.Sampler | Tone.PolySynth | null = null;
let currentPart: Tone.Part | null = null;

// Public domain piano samples (lightweight)
const PIANO_SAMPLES = {
    'A0': 'A0.mp3', 'C1': 'C1.mp3', 'D#1': 'Ds1.mp3', 'F#1': 'Fs1.mp3', 'A1': 'A1.mp3',
    'C2': 'C2.mp3', 'D#2': 'Ds2.mp3', 'F#2': 'Fs2.mp3', 'A2': 'A2.mp3',
    'C3': 'C3.mp3', 'D#3': 'Ds3.mp3', 'F#3': 'Fs3.mp3', 'A3': 'A3.mp3',
    'C4': 'C4.mp3', 'D#4': 'Ds4.mp3', 'F#4': 'Fs4.mp3', 'A4': 'A4.mp3',
    'C5': 'C5.mp3', 'D#5': 'Ds5.mp3', 'F#5': 'Fs5.mp3', 'A5': 'A5.mp3',
    'C6': 'C6.mp3', 'D#6': 'Ds6.mp3', 'F#6': 'Fs6.mp3', 'A6': 'A6.mp3',
    'C7': 'C7.mp3', 'D#7': 'Ds7.mp3', 'F#7': 'Fs7.mp3', 'A7': 'A7.mp3',
    'C8': 'C8.mp3'
};
const SAMPLE_BASE_URL = "https://tonejs.github.io/audio/salamander/";

async function initializeInstrument(): Promise<Tone.Sampler | Tone.PolySynth> {
  if (instrument) return instrument;

  return new Promise((resolve) => {
      // Attempt to load piano samples
      const sampler = new Tone.Sampler({
          urls: PIANO_SAMPLES,
          baseUrl: SAMPLE_BASE_URL,
          onload: () => {
              console.log("Piano samples loaded.");
              sampler.toDestination();
              instrument = sampler;
              resolve(sampler);
          },
          onerror: () => {
              console.warn("Failed to load piano samples. Falling back to synth.");
              createFallbackSynth();
              resolve(instrument!);
          }
      });

      // Fallback if loading takes too long (e.g. 3 seconds)
      setTimeout(() => {
          if (!sampler.loaded) {
              console.log("Sample loading timed out, using fallback.");
              createFallbackSynth();
              resolve(instrument!);
          }
      }, 3000);
  });
}

function createFallbackSynth() {
    if (instrument instanceof Tone.PolySynth) return;

    // Configured to sound slightly more like an electric piano than a raw wave
    instrument = new Tone.PolySynth(Tone.Synth, {
        oscillator: { type: "triangle" },
        envelope: {
            attack: 0.005,
            decay: 0.3,
            sustain: 0.4,
            release: 1.2,
        },
        volume: -6
    }).toDestination();
}

export async function playTrack(processedMidi: Midi, onEnded: () => void): Promise<void> {
  stopPlayback();

  if (processedMidi.tracks.length === 0) {
    onEnded();
    return;
  }

  const track = processedMidi.tracks[0];
  if (!track.notes || track.notes.length === 0) {
    onEnded();
    return;
  }

  const inst = await initializeInstrument();
  await Tone.start();

  // Reset Transport
  Tone.Transport.stop();
  Tone.Transport.position = 0;
  Tone.Transport.bpm.value = processedMidi.header.tempos[0]?.bpm || 120;

  currentPart = new Tone.Part(
    (time, note) => {
      inst.triggerAttackRelease(note.name, note.duration, time, note.velocity);
    },
    track.notes.map(note => ({
      time: note.time,
      name: note.name,
      duration: note.duration,
      velocity: note.velocity,
    }))
  );

  currentPart.loop = false;
  Tone.Transport.on('stop', () => {
    currentPart?.dispose();
    currentPart = null;
    onEnded();
  });

  currentPart.start(0);
  Tone.Transport.start();

  // Stop slightly after the last note
  const lastNote = track.notes[track.notes.length - 1];
  const endTime = lastNote.time + lastNote.duration + 1;

  Tone.Transport.scheduleOnce(() => {
    Tone.Transport.stop();
  }, endTime);
}

// New helper for spot-checking specific notes (e.g. from Piano Roll clicks)
export async function playSpecificNotes(notes: { name: string, duration: number, velocity: number }[]) {
    const inst = await initializeInstrument();
    await Tone.start();

    const now = Tone.now();
    notes.forEach(n => {
        inst.triggerAttackRelease(n.name, n.duration, now, n.velocity);
    });
}

export function stopPlayback(): void {
  if (Tone.Transport.state === 'started') {
    Tone.Transport.stop();
    Tone.Transport.cancel(); // Clear scheduled events
  }
  if (currentPart) {
    currentPart.dispose();
    currentPart = null;
  }
  if (instrument instanceof Tone.PolySynth) {
      instrument.releaseAll();
  } else if (instrument instanceof Tone.Sampler) {
      instrument.releaseAll();
  }
}

