const NOTE_HEIGHT = 14;
const MIN_MIDI = 21; 
const MAX_MIDI = 108; 
const NUM_NOTES = MAX_MIDI - MIN_MIDI + 1;
const KEY_WIDTH = 60;
const RULER_HEIGHT = 32;

const VOICE_COLORS = [
    '#3b82f6', // Blue
    '#ef4444', // Red
    '#10b981', // Green
    '#f59e0b', // Amber
    '#8b5cf6', // Violet
    '#ec4899', // Pink
    '#6366f1', // Indigo
    '#14b8a6', // Teal
];

const isBlackKey = (midi: number) => {
  const note = midi % 12;
  return note === 1 || note === 3 || note === 6 || note === 8 || note === 10;
};

const getRegionColor = (type: HarmonicRegion['type']): string => {
    switch (type) {
        case 'perfect_consonance': return '#2dd4bf'; // Turquoise
        case 'imperfect_consonance': return '#a3e635'; // Lime Green
        case 'dissonance_1': return '#4338ca'; // Deep Bluish Purple
        case 'dissonance_consecutive': return '#701a75'; // Reddish Purple
        default: return 'transparent';
    }
};

const PianoRoll: React.FC<PianoRollProps> = ({ trackData, onRegionClick }) => {
  const { notes, ppq, timeSignature, harmonicRegions } = trackData;
  const gridContainerRef = useRef<HTMLDivElement>(null);
