            <div className="absolute bottom-0 left-0 right-0 bg-gray-800 border-t border-brand-primary p-4 rounded-b-2xl shadow-2xl z-20 flex items-center justify-between">
                <div className="text-xs text-gray-400">
                    <span className="text-brand-primary font-bold">{checkedIds.size}</span> Intervals Selected for Assembly
                </div>
                <button 
                    onClick={triggerAssembly} 
                    disabled={isAssembling || checkedIds.size === 0}
                    className="flex items-center gap-2 px-6 py-3 bg-brand-primary hover:bg-brand-secondary disabled:opacity-50 disabled:bg-gray-600 text-white font-bold rounded shadow-lg transition-all"
                >
                    {isAssembling ? (
                        <><Spinner className="w-5 h-5" /> Assembling...</>
                    ) : (
                        <>Send to Gemini for Assembly &rarr;</>
                    )}
                </button>
            </div>
        </div>
    );
}

// Spelling Maps adapted from standard theory
const SPELLING_MAPS: { [keyRoot: number]: string[] } = {
    0: ['C', 'C#', 'D', 'Eb', 'E', 'F', 'F#', 'G', 'G#', 'A', 'Bb', 'B'], // C
    1: ['C', 'Db', 'D', 'Eb', 'E', 'F', 'Gb', 'G', 'Ab', 'A', 'Bb', 'B'], // Db
    2: ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'], // D
    3: ['C', 'Db', 'D', 'Eb', 'E', 'F', 'F#', 'G', 'Ab', 'A', 'Bb', 'B'], // Eb
    4: ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'], // E
    5: ['C', 'C#', 'D', 'Eb', 'E', 'F', 'F#', 'G', 'Ab', 'A', 'Bb', 'B'], // F
    6: ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'], // F#
    7: ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'Bb', 'B'], // G
    8: ['C', 'Db', 'D', 'Eb', 'E', 'F', 'Gb', 'G', 'Ab', 'A', 'Bb', 'B'], // Ab
    9: ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'], // A
    10: ['C', 'C#', 'D', 'Eb', 'E', 'F', 'F#', 'G', 'Ab', 'A', 'Bb', 'B'], // Bb
    11: ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'], // B
};

export function getPitchName(midi: number, root: number = 0, mode: string = 'Major'): string {
    const r = (root % 12 + 12) % 12;
    // Determine effective root for spelling based on parallel major/relative minor concepts
    // For simplicity here, we use the root provided.
    // Ideally, we select the map that minimizes accidentals for the key.

    let mapKey = r;
    // Simple logic: if minor, use relative major map for accidentals preference?
    // Actually, fixed maps per root are safer for generic display.

    const spellingMap = SPELLING_MAPS[mapKey] || SPELLING_MAPS[0];
    const midiInt = Math.round(midi);
    const noteIndex = (midiInt % 12 + 12) % 12; // Handle negative indices correctly
    const noteName = spellingMap[noteIndex];

    if (!noteName) return `N${midiInt}`; // Safe fallback

    const octave = Math.floor(midiInt / 12) - 1;
    return `${noteName}${octave}`;
}

// Fallback strict for legacy or unspecified contexts
export function getStrictPitchName(midi: number): string {
    return getPitchName(midi, 0); 
}

export function getIntervalLabel(semitones: number): string {
    const abs = Math.abs(semitones);

    // Reduce to simple interval (modulo 12)
    // 0 = P1 (Unison)
    // 12, 24, 36 = P8 (Octave)

    if (abs === 0) return 'P1';

    const simple = abs % 12;
    if (simple === 0) return 'P8'; // Multiples of 12 are treated as Octaves

    const map: Record<number, string> = {
        1: 'm2', 2: 'M2', 3: 'm3', 4: 'M3', 5: 'P4', 6: 'TT', 
        7: 'P5', 8: 'm6', 9: 'M6', 10: 'm7', 11: 'M7'
    };
    return map[simple] || `${simple}`;
}

export function getRhythmAbbreviation(durationTicks: number, ppq: number): string {
    const quarter = ppq;
    const ratio = durationTicks / quarter;
    const closeTo = (val: number, target: number) => Math.abs(val - target) < 0.05;

    if (closeTo(ratio, 4.0)) return 'w'; 
    if (closeTo(ratio, 3.0)) return 'h.'; 
    if (closeTo(ratio, 2.0)) return 'h'; 
    if (closeTo(ratio, 1.5)) return 'q.'; 
    if (closeTo(ratio, 1.0)) return 'q'; 
    if (closeTo(ratio, 0.75)) return 'e.'; 
    if (closeTo(ratio, 0.5)) return 'e'; 
    if (closeTo(ratio, 0.375)) return 's.'; 
    if (closeTo(ratio, 0.25)) return 's'; 
    if (closeTo(ratio, 0.125)) return 't'; // 32nd
    if (closeTo(ratio, 0.333)) return 'et'; 
    if (closeTo(ratio, 0.166)) return 'st'; 
    if (closeTo(ratio, 0.666)) return 'qt'; 

    return '?'; 
}

