import * as Tone from 'tone';
import { Midi } from '@tonejs/midi';

// We use a union type for the instrument to handle both Sampler and Synth
let instrument: Tone.Sampler | Tone.PolySynth | null = null;
let currentPart: Tone.Part | null = null;
let activeSourceNodes: Tone.ToneAudioNode[] = []; // Track active nodes for manual stop

// Public domain piano samples (lightweight)
const PIANO_SAMPLES = {
    'A0': 'A0.mp3', 'C1': 'C1.mp3', 'D#1': 'Ds1.mp3', 'F#1': 'Fs1.mp3', 'A1': 'A1.mp3',
    'C2': 'C2.mp3', 'D#2': 'Ds2.mp3', 'F#2': 'Fs2.mp3', 'A2': 'A2.mp3',
    'C3': 'C3.mp3', 'D#3': 'Ds3.mp3', 'F#3': 'Fs3.mp3', 'A3': 'A3.mp3',
    'C4': 'C4.mp3', 'D#4': 'Ds4.mp3', 'F#4': 'Fs4.mp3', 'A4': 'A4.mp3',
    'C5': 'C5.mp3', 'D#5': 'Ds5.mp3', 'F#5': 'Fs5.mp3', 'A5': 'A5.mp3',
    'C6': 'C6.mp3', 'D#6': 'Ds6.mp3', 'F#6': 'Fs6.mp3', 'A6': 'A6.mp3',
    'C7': 'C7.mp3', 'D#7': 'Ds7.mp3', 'F#7': 'Fs7.mp3', 'A7': 'A7.mp3',
    'C8': 'C8.mp3'
};
const SAMPLE_BASE_URL = "https://tonejs.github.io/audio/salamander/";

async function initializeInstrument(): Promise<Tone.Sampler | Tone.PolySynth> {
  if (instrument) return instrument;

  return new Promise((resolve) => {
      // Attempt to load piano samples
      const sampler = new Tone.Sampler({
          urls: PIANO_SAMPLES,
          baseUrl: SAMPLE_BASE_URL,
          onload: () => {
              console.log("Piano samples loaded.");
              sampler.toDestination();
              instrument = sampler;
              resolve(sampler);
          },
          onerror: () => {
              console.warn("Failed to load piano samples. Falling back to synth.");
              createFallbackSynth();
              resolve(instrument!);
          }
      });

      // Fallback if loading takes too long (e.g. 3 seconds)
      setTimeout(() => {
          if (!sampler.loaded) {
              console.log("Sample loading timed out, using fallback.");
              createFallbackSynth();
              resolve(instrument!);
          }
      }, 3000);
  });
}

function createFallbackSynth() {
    if (instrument instanceof Tone.PolySynth) return;

    // Configured to sound slightly more like an electric piano than a raw wave
    instrument = new Tone.PolySynth(Tone.Synth, {
        oscillator: { type: "triangle" },
        envelope: {
            attack: 0.005,
            decay: 0.3,
            sustain: 0.4,
            release: 1.2,
        },
        volume: -6
    }).toDestination();
}

export async function playTrack(processedMidi: Midi, onEnded: () => void): Promise<void> {
  stopPlayback();

  if (processedMidi.tracks.length === 0) {
    onEnded();
    return;
  }

  const track = processedMidi.tracks[0];
  if (!track.notes || track.notes.length === 0) {
    onEnded();
    return;
  }

  const inst = await initializeInstrument();
  await Tone.start();

  // Reset Transport
  Tone.Transport.stop();
  Tone.Transport.position = 0;
  Tone.Transport.bpm.value = processedMidi.header.tempos[0]?.bpm || 120;

  currentPart = new Tone.Part(
    (time, note) => {
      if (note.name && !note.name.startsWith('undefined') && !note.name.startsWith('N-')) {
          inst.triggerAttackRelease(note.name, note.duration, time, note.velocity);
      }
    },
    track.notes.map(note => ({
      time: note.time,
      name: note.name,
      duration: note.duration,
      velocity: note.velocity,
    }))
  );

  currentPart.loop = false;
  Tone.Transport.on('stop', () => {
    currentPart?.dispose();
    currentPart = null;
    onEnded();
  });

  currentPart.start(0);
  Tone.Transport.start();

  // Stop slightly after the last note
  const lastNote = track.notes[track.notes.length - 1];
  const endTime = lastNote.time + lastNote.duration + 1;

  Tone.Transport.scheduleOnce(() => {
    Tone.Transport.stop();
  }, endTime);
}

// Robust sequencer for simple playbacks that doesn't rely on global Transport state
export async function playSequence(notes: { name: string, time: number, duration: number, velocity: number }[], onEnded?: () => void) {
    stopPlayback();
    const inst = await initializeInstrument();
    await Tone.start();
    const now = Tone.now();
    let maxTime = 0;

    notes.forEach(n => {
        if (n.name && !n.name.startsWith('undefined') && !n.name.startsWith('N-')) {
            try {
                inst.triggerAttackRelease(n.name, n.duration, now + n.time, n.velocity);
                if ((n.time + n.duration) > maxTime) maxTime = n.time + n.duration;
            } catch (e) {
                console.warn(`Skipping invalid note: ${n.name}`, e);
            }
        }
    });

    if (onEnded) {
        setTimeout(onEnded, maxTime * 1000 + 500); 
    }
}

// New helper for spot-checking specific notes (e.g. from Piano Roll clicks)
export async function playSpecificNotes(notes: { name: string, duration: number, velocity: number }[]) {
    const inst = await initializeInstrument();
    await Tone.start();

    const now = Tone.now();
    notes.forEach(n => {
        if (n.name && !n.name.startsWith('undefined') && !n.name.startsWith('N-')) {
            try {
                inst.triggerAttackRelease(n.name, n.duration, now, n.velocity);
            } catch (e) {
                console.warn(`Skipping invalid note: ${n.name}`, e);
            }
        }
    });
}

export function stopPlayback(): void {
  if (Tone.Transport.state === 'started') {
    Tone.Transport.stop();
    Tone.Transport.cancel(); 
  }
  if (currentPart) {
    currentPart.dispose();
    currentPart = null;
  }
  if (instrument instanceof Tone.PolySynth) {
      instrument.releaseAll();
  } else if (instrument instanceof Tone.Sampler) {
      instrument.releaseAll();
  }
}

import React, { useState, useMemo } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate, PianoRollTrackData, HarmonicRegion } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate } from './services/strettoCore';
import { PlayIcon, StopIcon, Spinner, CheckIcon, DownloadIcon } from './Icons';
import { playSequence, stopPlayback, playSpecificNotes } from './midiPlaybackService';
import PianoRoll from './PianoRoll';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
}

const INTERVAL_OPTIONS = [
    { label: 'Unison (P1)', val: 0 },
    { label: '+ Octave (P8)', val: 12 },
    { label: '- Octave (P8)', val: -12 },
    { label: '+ 2 Octaves', val: 24 },
    { label: '- 2 Octaves', val: -24 },
    { label: '+ Perf 5th', val: 7 },
    { label: '- Perf 5th', val: -7 },
    { label: '+ Perf 4th', val: 5 },
    { label: '- Perf 4th', val: -5 },
];

type SearchResolution = 'half' | 'full' | 'double';

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("c2 G c d e f g3 a b c'2");
    const [config, setConfig] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
    const [isPlaying, setIsPlaying] = useState(false);

    // SoC: Use Custom Hook for Logic
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq });

    const results = useMemo(() => {
        if (subjectNotes.length === 0) return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        config.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, config, ppq, ts, searchRes]);

    const getSelectedCandidates = () => {
        return results.filter(r => checkedIds.has(r.id));
    };

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }

        // Convert to sequence for robust player
        const seq = notes.map(n => ({
            name: n.name,
            time: n.ticks * (0.5 / ppq), // 120 bpm assumption for preview
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));

        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const handleDownloadMidi = () => {
        const selected = getSelectedCandidates();
        if (selected.length === 0) return;

        const newMidi = new Midi();
        newMidi.header.ppq = ppq;
        newMidi.header.tempos.push({ bpm: 120, ticks: 0 });
        newMidi.header.timeSignatures.push({ timeSignature: [ts.num, ts.den], ticks: 0 });

        selected.forEach((cand) => {
            const track = newMidi.addTrack();
            track.name = `${cand.intervalLabel} @ ${cand.delayBeats}B`;
            track.instrument.name = "Acoustic Grand Piano";

            cand.notes.forEach(n => {
                track.addNote({
                    midi: n.midi,
                    ticks: n.ticks,
                    durationTicks: n.durationTicks,
                    velocity: n.velocity
                });
            });
        });

        downloadMidiFile(newMidi, `Stretto_Candidates_${selected.length}.mid`);
    };

    const handleDownloadChainMidi = () => {
        if (!assemblyResult) return;

        // Naive parsing of multi-voice ABC from Gemini
        const newMidi = new Midi();
        newMidi.header.ppq = ppq;
        newMidi.header.tempos.push({ bpm: 120, ticks: 0 });
        newMidi.header.timeSignatures.push({ timeSignature: [ts.num, ts.den], ticks: 0 });

        // Split by Voice headers (V:1, V:2, etc)
        const parts = assemblyResult.split(/V:\s*\d+/g);
        // First part is header, subsequent are voices.
        // We assume voices are listed in order V:1, V:2... 

        // If split doesn't find V tags, try whole string
        const voiceContents = parts.length > 1 ? parts.slice(1) : [assemblyResult];

        voiceContents.forEach((content, idx) => {
            const track = newMidi.addTrack();
            track.name = `Chain Voice ${idx + 1}`;
            track.instrument.name = "String Ensemble 1";

            // Re-use simple parser
            const notes = parseSimpleAbc(content, ppq);
            notes.forEach(n => track.addNote({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: 0.8
            }));
        });

        downloadMidiFile(newMidi, `Gemini_Stretto_Chain.mid`);
    };

    const downloadMidiFile = (midi: Midi, filename: string) => {
        const midiBytes = midi.toArray();
        const blob = new Blob([midiBytes], { type: 'audio/midi' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const handleRegionClick = (region: HarmonicRegion) => {
        if (!selectedCandidate) return;
        const activeNotes = selectedCandidate.notes.filter(n => 
            n.ticks < region.endTick && (n.ticks + n.durationTicks) > region.startTick
        );

        if (activeNotes.length > 0) {
            const notesToPlay = activeNotes.map(n => ({
                name: n.name,
                duration: n.durationTicks * (0.5 / ppq), 
                velocity: n.velocity
            }));
            playSpecificNotes(notesToPlay);
        }
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) {
                next.delete(id);
            } else {
                next.add(id);
                const candidate = results.find(r => r.id === id);
                if (candidate) setSelectedCandidate(candidate);
            }
            return next;
        });
    };

    const pianoRollData: PianoRollTrackData | null = useMemo(() => {
        if (!selectedCandidate) return null;
        return {
            name: `Stretto ${selectedCandidate.intervalLabel}`,
            ppq,
            timeSignature: { numerator: ts.num, denominator: ts.den },
            notes: selectedCandidate.notes.map(n => ({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: n.velocity,
                name: n.name,
                voiceIndex: n.voiceIndex ?? 0, 
                isOrnament: false
            })),
            harmonicRegions: selectedCandidate.regions 
        };
    }, [selectedCandidate, ppq, ts]);

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-wrap gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 items-center justify-between">
                <div className="flex gap-2">
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>
                <div className="text-xs text-gray-500 font-mono">
                    Mode: {mode === 'midi' ? 'Track Analysis' : 'Text Input'}
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6">
                    <label className="block text-sm text-gray-400 mb-2 font-bold uppercase tracking-wider">Subject ABC</label>
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="Enter ABC notation melody..."
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            {/* Config Panels */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                    <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest">Search Intervals</h3>
                    <div className="flex flex-wrap gap-2">
                        {INTERVAL_OPTIONS.map(opt => (
                            <label key={opt.val} className={`flex items-center px-3 py-1.5 rounded cursor-pointer border transition-all ${config.includes(opt.val) ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                                <input 
                                    type="checkbox" 
                                    checked={config.includes(opt.val)}
                                    onChange={e => {
                                        if(e.target.checked) {
                                            if(!config.includes(opt.val)) setConfig([...config, opt.val]);
                                        } else {
                                            setConfig(config.filter(c => c !== opt.val));
                                        }
                                    }}
                                    className="sr-only"
                                />
                                <span className="text-xs font-bold">{opt.label}</span>
                            </label>
                        ))}
                    </div>
                </div>

                <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                    <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest">Search Frequency</h3>
                    <div className="grid grid-cols-3 gap-2">
                        {(['half', 'full', 'double'] as SearchResolution[]).map(res => (
                            <button 
                                key={res}
                                onClick={() => setSearchRes(res)}
                                className={`px-2 py-2 rounded text-xs font-bold border transition-all ${searchRes === res ? 'bg-brand-primary text-white border-brand-primary shadow-lg' : 'bg-gray-900 border-gray-700 text-gray-500 hover:bg-gray-800'}`}
                            >
                                {res === 'half' ? '1/2 Beat' : res === 'full' ? 'Beat' : '2 Beats'}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* Matrix / Results */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">

                {/* List View */}
                <div className="bg-gray-900 border border-gray-700 rounded h-[600px] overflow-y-auto p-2 shadow-inner relative">
                    <div className="sticky top-0 bg-gray-900 z-10 border-b border-gray-700 pb-2 mb-2 px-2 flex justify-between items-center pt-2">
                        <span className="font-bold text-gray-300">Candidates ({results.length})</span>
                        {checkedIds.size > 0 && <span className="text-xs text-brand-primary font-bold">{checkedIds.size} Selected</span>}
                    </div>
                    {results.length === 0 ? (
                        <div className="py-20 text-center text-gray-600">No candidates match current search settings.</div>
                    ) : (
                        results.map((r, i) => (
                            <div 
                                key={i}
                                onClick={() => setSelectedCandidate(r)}
                                className={`grid grid-cols-12 gap-2 p-2 rounded cursor-pointer border-b border-gray-800 hover:bg-gray-800 transition-colors items-center ${selectedCandidate?.id === r.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                            >
                                <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                    <input 
                                        type="checkbox" 
                                        checked={checkedIds.has(r.id)} 
                                        onChange={() => toggleCheck(r.id)}
                                        className="rounded bg-gray-700 border-gray-600 text-brand-primary focus:ring-0 w-4 h-4"
                                    />
                                </div>
                                <span className="col-span-3 font-bold text-brand-primary">{r.intervalLabel}</span>
                                <span className="col-span-3 text-gray-300">{r.delayBeats} beats</span>
                                <div className="col-span-2">
                                    <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded w-fit ${r.grade === 'STRONG' ? 'bg-green-900 text-green-300' : r.grade === 'VIABLE' ? 'bg-yellow-900 text-yellow-300' : 'bg-red-900 text-red-300'}`}>
                                        {r.grade}
                                    </span>
                                </div>
                                <span className="col-span-3 text-xs text-gray-500">{r.errors.length > 0 ? `${r.errors.length} issues` : '-'}</span>
                            </div>
                        ))
                    )}
                </div>

                {/* Inspector & Assembly Results */}
                <div className="bg-gray-800 border border-gray-700 rounded p-4 flex flex-col h-[600px] shadow-lg relative overflow-hidden">

                    {/* Gemini Assembly Overlay */}
                    {assemblyResult && (
                        <div className="absolute inset-0 bg-gray-800 z-30 p-4 flex flex-col animate-fade-in">
                            <div className="flex justify-between items-center mb-4 border-b border-gray-700 pb-2">
                                <h3 className="font-bold text-brand-primary">Gemini Stretto Chain</h3>
                                <button onClick={() => setAssemblyResult('')} className="text-gray-500 hover:text-white">✕ Close</button>
                            </div>
                            <div className="flex-grow flex flex-col gap-4 overflow-hidden">
                                <div className="flex-1 bg-black rounded p-3 font-mono text-xs text-gray-300 overflow-auto border border-gray-700 whitespace-pre-wrap">
                                    {assemblyResult}
                                </div>
                                <div className="grid grid-cols-2 gap-2">
                                    <button 
                                        onClick={handleDownloadChainMidi}
                                        className="w-full py-2 bg-brand-secondary text-white font-bold rounded flex items-center justify-center gap-2 hover:bg-brand-primary transition-colors"
                                    >
                                        <DownloadIcon className="w-4 h-4"/> Download Chain MIDI
                                    </button>
                                    <button 
                                        onClick={() => {
                                            navigator.clipboard.writeText(assemblyResult);
                                            alert("ABC Chain copied to clipboard!");
                                        }}
                                        className="w-full py-2 bg-gray-700 text-white font-bold rounded hover:bg-gray-600 transition-colors"
                                    >
                                        Copy ABC Text
                                    </button>
                                </div>
                                <div className="h-24 bg-gray-900 rounded p-2 border border-gray-700 overflow-auto text-[10px]">
                                    <h4 className="font-bold text-gray-500 uppercase mb-1">Verification History</h4>
                                    {assemblyLog.map((log, i) => (
                                        <div key={i} className="border-l border-gray-700 pl-2 mb-1 text-gray-400">{log}</div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}

                    {selectedCandidate && pianoRollData ? (
                        <>
                            <div className="flex justify-between items-start mb-4">
                                <div>
                                    <h3 className="text-xl font-bold text-white">
                                        Stretto: {selectedCandidate.intervalLabel} @ {selectedCandidate.delayBeats}B
                                    </h3>
                                    <p className={`text-sm font-bold ${selectedCandidate.grade === 'STRONG' ? 'text-green-400' : selectedCandidate.grade === 'VIABLE' ? 'text-yellow-400' : 'text-red-400'}`}>
                                        Verdict: {selectedCandidate.grade}
                                    </p>
                                </div>
                                <button onClick={() => handlePlay(selectedCandidate.notes)} className="bg-brand-primary p-2 rounded-full hover:bg-brand-secondary transition-transform active:scale-95 shadow-md">
                                    {isPlaying ? <StopIcon className="w-6 h-6 text-white"/> : <PlayIcon className="w-6 h-6 text-white"/>}
                                </button>
                            </div>

                            {/* Piano Roll Visualization */}
                            <div className="h-96 min-h-[400px] flex-grow bg-gray-900 rounded border border-gray-700 mb-4 overflow-hidden shadow-inner relative">
                                <PianoRoll trackData={pianoRollData} onRegionClick={handleRegionClick} />
                                <div className="absolute top-2 right-2 flex flex-col gap-1 text-[10px] bg-black/50 p-1.5 rounded backdrop-blur-sm pointer-events-none">
                                    <span className="text-blue-400 font-bold">■ Subject</span>
                                    <span className="text-red-400 font-bold">■ Answer</span>
                                    <div className="mt-1 pt-1 border-t border-gray-600 flex flex-col gap-0.5">
                                        <div className="flex items-center gap-1"><span className="w-2 h-2 bg-teal-400 rounded-sm opacity-50"></span> P Cons</div>
                                        <div className="flex items-center gap-1"><span className="w-2 h-2 bg-lime-400 rounded-sm opacity-50"></span> I Cons</div>
                                        <div className="flex items-center gap-1"><span className="w-2 h-2 bg-indigo-700 rounded-sm opacity-50"></span> Diss 1</div>
                                        <div className="flex items-center gap-1"><span className="w-2 h-2 bg-fuchsia-900 rounded-sm opacity-50"></span> Diss 2+</div>
                                    </div>
                                </div>
                            </div>

                            {/* Error Log */}
                            <div className="h-32 overflow-y-auto mb-4 bg-gray-900 rounded p-2 border border-gray-700 shadow-inner flex-shrink-0">
                                {selectedCandidate.errors.length === 0 ? (
                                    <div className="text-green-400 flex items-center justify-center h-full flex-col opacity-70">
                                        <CheckIcon className="w-12 h-12 mb-2" />
                                        <p className="font-bold uppercase tracking-wider text-xs">Strong Counterpoint</p>
                                    </div>
                                ) : (
                                    <ul className="space-y-2">
                                        {selectedCandidate.errors.map((e, idx) => (
                                            <li key={idx} className="text-sm border-l-2 pl-2 border-red-500 bg-red-900/10 p-2 rounded-r">
                                                <div className="flex justify-between items-center mb-1">
                                                    <span className="text-red-300 font-bold">{e.type}</span>
                                                    <span className="text-gray-500 font-mono text-[10px] px-1.5 py-0.5 bg-gray-800 rounded">{e.timeFormatted}</span>
                                                </div>
                                                <p className="text-gray-400 text-xs leading-tight">{e.details}</p>
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                        </>
                    ) : (
                        <div className="flex flex-col items-center justify-center h-full text-gray-500">
                            <span className="text-4xl mb-4 opacity-50">🎹</span>
                            <p className="font-bold text-gray-400">Select a candidate to visualize.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* STICKY FOOTER ACTION BAR */}
            <div className="absolute bottom-0 left-0 right-0 bg-gray-800 border-t border-brand-primary p-4 rounded-b-2xl shadow-2xl z-20">
                <div className="flex flex-col md:flex-row items-center justify-between gap-4">
                    <div className="flex-grow w-full md:w-auto overflow-hidden">
                        <div className="flex justify-between items-center mb-2">
                            <div className="text-xs text-brand-primary font-bold">SELECTED FOR ASSEMBLY ({checkedIds.size}):</div>
                            <div className="flex gap-2">
                                {checkedIds.size > 0 && (
                                    <button 
                                        onClick={handleDownloadMidi}
                                        className="text-[10px] text-gray-400 hover:text-white flex items-center gap-1 bg-gray-700 px-2 py-1 rounded"
                                    >
                                        <DownloadIcon className="w-3 h-3" /> Selected Tracks
                                    </button>
                                )}
                            </div>
                        </div>
                        <div className="flex flex-wrap gap-2 max-h-16 overflow-y-auto">
                            {checkedIds.size > 0 ? (
                                getSelectedCandidates().map(c => (
                                    <div key={c.id} className="inline-flex items-center gap-1 bg-brand-primary/20 border border-brand-primary/50 rounded-full px-2 py-1">
                                        <span className="text-xs font-bold text-brand-primary">{c.intervalLabel}</span>
                                        <span className="text-[10px] text-brand-secondary bg-black/20 px-1 rounded">@{c.delayBeats}B</span>
                                        <button onClick={() => toggleCheck(c.id)} className="ml-1 text-brand-primary hover:text-white">×</button>
                                    </div>
                                ))
                            ) : (
                                <span className="text-xs text-gray-500 italic">No candidates selected. Check box to add.</span>
                            )}
                        </div>
                    </div>

                    <div className="flex gap-2 flex-shrink-0">
                        <button 
                            onClick={triggerAssembly} 
                            disabled={isAssembling || checkedIds.size === 0}
                            className="flex items-center gap-2 px-6 py-3 bg-brand-primary hover:bg-brand-secondary disabled:opacity-50 disabled:bg-gray-600 text-white font-bold rounded shadow-lg transition-all"
                        >
                            {isAssembling ? (
                                <><Spinner className="w-5 h-5" /> Assembling...</>
                            ) : (
                                <>Assemble Chain &rarr;</>
                            )}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useMemo } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate, PianoRollTrackData, HarmonicRegion, StrettoGrade } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate } from './services/strettoCore';
import { PlayIcon, StopIcon, Spinner, CheckIcon, DownloadIcon, FilterIcon } from './Icons';
import { playSequence, stopPlayback, playSpecificNotes } from './midiPlaybackService';
import PianoRoll from './PianoRoll';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
}

const INTERVAL_OPTIONS = [
    { label: 'Unison (P1)', val: 0 },
    { label: '+ Octave (P8)', val: 12 },
    { label: '- Octave (P8)', val: -12 },
    { label: '+ 2 Octaves', val: 24 },
    { label: '- 2 Octaves', val: -24 },
    { label: '+ Perf 5th', val: 7 },
    { label: '- Perf 5th', val: -7 },
    { label: '+ Perf 4th', val: 5 },
    { label: '- Perf 4th', val: -5 },
];

type SearchResolution = 'half' | 'full' | 'double';
type SortKey = 'grade' | 'delay' | 'interval';

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("c2 G c d e f g3 a b c'2");
    const [config, setConfig] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
    const [isPlaying, setIsPlaying] = useState(false);

    // Filter & Sort State
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');
    const [gradeFilter, setGradeFilter] = useState<Record<StrettoGrade, boolean>>({
        'STRONG': true,
        'VIABLE': true,
        'INVALID': false
    });

    // SoC: Use Custom Hook for Logic
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq });

    const results = useMemo(() => {
        if (subjectNotes.length === 0) return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        config.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, config, ppq, ts, searchRes]);

    const processedResults = useMemo(() => {
        let res = results.filter(r => gradeFilter[r.grade]);

        res.sort((a, b) => {
            let diff = 0;
            if (sortKey === 'grade') {
                const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                diff = score[a.grade] - score[b.grade];
            } else if (sortKey === 'delay') {
                diff = a.delayTicks - b.delayTicks;
            } else if (sortKey === 'interval') {
                diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [results, gradeFilter, sortKey, sortDir]);

    const getSelectedCandidates = () => {
        return results.filter(r => checkedIds.has(r.id));
    };

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }

        // Convert to sequence for robust player
        const seq = notes.map(n => ({
            name: n.name,
            time: n.ticks * (0.5 / ppq), // 120 bpm assumption for preview
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));

        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const handleDownloadMidi = () => {
        const selected = getSelectedCandidates();
        if (selected.length === 0) return;

        const newMidi = new Midi();
        newMidi.header.ppq = ppq;
        newMidi.header.tempos.push({ bpm: 120, ticks: 0 });
        newMidi.header.timeSignatures.push({ timeSignature: [ts.num, ts.den], ticks: 0 });

        selected.forEach((cand) => {
            const track = newMidi.addTrack();
            track.name = `${cand.intervalLabel} @ ${cand.delayBeats}B`;
            track.instrument.name = "Acoustic Grand Piano";

            cand.notes.forEach(n => {
                track.addNote({
                    midi: n.midi,
                    ticks: n.ticks,
                    durationTicks: n.durationTicks,
                    velocity: n.velocity
                });
            });
        });

        downloadMidiFile(newMidi, `Stretto_Candidates_${selected.length}.mid`);
    };

    const handleDownloadChainMidi = () => {
        if (!assemblyResult) return;

        // Naive parsing of multi-voice ABC from Gemini
        const newMidi = new Midi();
        newMidi.header.ppq = ppq;
        newMidi.header.tempos.push({ bpm: 120, ticks: 0 });
        newMidi.header.timeSignatures.push({ timeSignature: [ts.num, ts.den], ticks: 0 });

        // Split by Voice headers (V:1, V:2, etc)
        const parts = assemblyResult.split(/V:\s*\d+/g);
        // First part is header, subsequent are voices.
        // We assume voices are listed in order V:1, V:2... 

        // If split doesn't find V tags, try whole string
        const voiceContents = parts.length > 1 ? parts.slice(1) : [assemblyResult];

        voiceContents.forEach((content, idx) => {
            const track = newMidi.addTrack();
            track.name = `Chain Voice ${idx + 1}`;
            track.instrument.name = "String Ensemble 1";

            // Re-use simple parser
            const notes = parseSimpleAbc(content, ppq);
            notes.forEach(n => track.addNote({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: 0.8
            }));
        });

        downloadMidiFile(newMidi, `Gemini_Stretto_Chain.mid`);
    };

    const downloadMidiFile = (midi: Midi, filename: string) => {
        const midiBytes = midi.toArray();
        const blob = new Blob([midiBytes], { type: 'audio/midi' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const handleRegionClick = (region: HarmonicRegion) => {
        if (!selectedCandidate) return;
        const activeNotes = selectedCandidate.notes.filter(n => 
            n.ticks < region.endTick && (n.ticks + n.durationTicks) > region.startTick
        );

        if (activeNotes.length > 0) {
            const notesToPlay = activeNotes.map(n => ({
                name: n.name,
                duration: n.durationTicks * (0.5 / ppq), 
                velocity: n.velocity
            }));
            playSpecificNotes(notesToPlay);
        }
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) {
                next.delete(id);
            } else {
                next.add(id);
                const candidate = results.find(r => r.id === id);
                if (candidate) setSelectedCandidate(candidate);
            }
            return next;
        });
    };

    const pianoRollData: PianoRollTrackData | null = useMemo(() => {
        if (!selectedCandidate) return null;
        return {
            name: `Stretto ${selectedCandidate.intervalLabel}`,
            ppq,
            timeSignature: { numerator: ts.num, denominator: ts.den },
            notes: selectedCandidate.notes.map(n => ({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: n.velocity,
                name: n.name,
                voiceIndex: n.voiceIndex ?? 0, 
                isOrnament: false
            })),
            harmonicRegions: selectedCandidate.regions 
        };
    }, [selectedCandidate, ppq, ts]);

    const toggleGradeFilter = (g: StrettoGrade) => {
        setGradeFilter(prev => ({ ...prev, [g]: !prev[g] }));
    };

    const handleSort = (key: SortKey) => {
        if (sortKey === key) {
            setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        } else {
            setSortKey(key);
            setSortDir(key === 'grade' ? 'desc' : 'asc'); // Default directions
        }
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-wrap gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 items-center justify-between">
                <div className="flex gap-2">
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>
                <div className="text-xs text-gray-500 font-mono">
                    Mode: {mode === 'midi' ? 'Track Analysis' : 'Text Input'}
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6">
                    <label className="block text-sm text-gray-400 mb-2 font-bold uppercase tracking-wider">Subject ABC</label>
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="Enter ABC notation melody..."
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            {/* Config Panels */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                    <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest">Search Intervals</h3>
                    <div className="flex flex-wrap gap-2">
                        {INTERVAL_OPTIONS.map(opt => (
                            <label key={opt.val} className={`flex items-center px-3 py-1.5 rounded cursor-pointer border transition-all ${config.includes(opt.val) ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                                <input 
                                    type="checkbox" 
                                    checked={config.includes(opt.val)}
                                    onChange={e => {
                                        if(e.target.checked) {
