import React from 'react';

const INTERVAL_OPTIONS = [
    { label: 'Unison (P1)', val: 0 },
    { label: '+ Octave (P8)', val: 12 },
    { label: '- Octave (P8)', val: -12 },
    { label: '+ 2 Octaves', val: 24 },
    { label: '- 2 Octaves', val: -24 },
    { label: '+ Perf 5th', val: 7 },
    { label: '- Perf 5th', val: -7 },
    { label: '+ Perf 4th', val: 5 },
    { label: '- Perf 4th', val: -5 },
];

export type SearchResolution = 'half' | 'full' | 'double';

interface StrettoConfigProps {
    selectedIntervals: number[];
    setSelectedIntervals: (vals: number[]) => void;
    searchRes: SearchResolution;
    setSearchRes: (res: SearchResolution) => void;
}

export default function StrettoConfig({ selectedIntervals, setSelectedIntervals, searchRes, setSearchRes }: StrettoConfigProps) {

    const toggleInterval = (val: number, checked: boolean) => {
        if (checked) {
            if (!selectedIntervals.includes(val)) setSelectedIntervals([...selectedIntervals, val]);
        } else {
            setSelectedIntervals(selectedIntervals.filter(c => c !== val));
        }
    };

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
            <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest">Search Intervals</h3>
                <div className="flex flex-wrap gap-2">
                    {INTERVAL_OPTIONS.map(opt => (
                        <label key={opt.val} className={`flex items-center px-3 py-1.5 rounded cursor-pointer border transition-all ${selectedIntervals.includes(opt.val) ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                            <input 
                                type="checkbox" 
                                checked={selectedIntervals.includes(opt.val)}
                                onChange={e => toggleInterval(opt.val, e.target.checked)}
                                className="sr-only"
                            />
                            <span className="text-xs font-bold">{opt.label}</span>
                        </label>
                    ))}
                </div>
            </div>

            <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest">Search Frequency</h3>
                <div className="grid grid-cols-3 gap-2">
                    {(['half', 'full', 'double'] as SearchResolution[]).map(res => (
                        <button 
                            key={res}
                            onClick={() => setSearchRes(res)}
                            className={`px-2 py-2 rounded text-xs font-bold border transition-all ${searchRes === res ? 'bg-brand-primary text-white border-brand-primary shadow-lg' : 'bg-gray-900 border-gray-700 text-gray-500 hover:bg-gray-800'}`}
                        >
                            {res === 'half' ? '1/2 Beat' : res === 'full' ? 'Beat' : '2 Beats'}
                        </button>
                    ))}
                </div>
            </div>
        </div>
    );
}

import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval';

export default function StrettoList({ candidates, selectedId, onSelect, checkedIds, onToggleCheck }: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');
    const [gradeFilter, setGradeFilter] = useState<Record<StrettoGrade, boolean>>({
        'STRONG': true,
        'VIABLE': true,
        'INVALID': false
    });

    const toggleGradeFilter = (g: StrettoGrade) => {
        setGradeFilter(prev => ({ ...prev, [g]: !prev[g] }));
    };

    const handleSort = (key: SortKey) => {
        if (sortKey === key) {
            setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        } else {
            setSortKey(key);
            setSortDir(key === 'grade' ? 'desc' : 'asc');
        }
    };

    const processedResults = useMemo(() => {
        let res = candidates.filter(r => gradeFilter[r.grade]);

        res.sort((a, b) => {
            let diff = 0;
            if (sortKey === 'grade') {
                const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                diff = score[a.grade] - score[b.grade];
            } else if (sortKey === 'delay') {
                diff = a.delayTicks - b.delayTicks;
            } else if (sortKey === 'interval') {
                diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [candidates, gradeFilter, sortKey, sortDir]);

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">

            {/* Toolbar for List */}
            <div className="p-2 border-b border-gray-700 bg-gray-800 flex flex-col gap-2">
                <div className="flex justify-between items-center">
                    <div className="flex gap-2">
                        <button onClick={() => toggleGradeFilter('STRONG')} className={`px-2 py-1 text-[10px] rounded font-bold transition-colors ${gradeFilter.STRONG ? 'bg-green-900 text-green-300 border border-green-700' : 'bg-gray-900 text-gray-500 border border-gray-700'}`}>Strong</button>
                        <button onClick={() => toggleGradeFilter('VIABLE')} className={`px-2 py-1 text-[10px] rounded font-bold transition-colors ${gradeFilter.VIABLE ? 'bg-yellow-900 text-yellow-300 border border-yellow-700' : 'bg-gray-900 text-gray-500 border border-gray-700'}`}>Viable</button>
                        <button onClick={() => toggleGradeFilter('INVALID')} className={`px-2 py-1 text-[10px] rounded font-bold transition-colors ${gradeFilter.INVALID ? 'bg-red-900 text-red-300 border border-red-700' : 'bg-gray-900 text-gray-500 border border-gray-700'}`}>Invalid</button>
                    </div>
                    <div className="text-[10px] text-gray-400">
                        {processedResults.length} / {candidates.length}
                    </div>
                </div>

                <div className="flex gap-1 bg-gray-900 p-1 rounded">
                    <button onClick={() => handleSort('grade')} className={`flex-1 text-[10px] py-1 rounded transition-colors ${sortKey === 'grade' ? 'bg-gray-700 text-white font-bold' : 'text-gray-500 hover:text-gray-300'}`}>
                        Quality {sortKey === 'grade' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('delay')} className={`flex-1 text-[10px] py-1 rounded transition-colors ${sortKey === 'delay' ? 'bg-gray-700 text-white font-bold' : 'text-gray-500 hover:text-gray-300'}`}>
                        Distance {sortKey === 'delay' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('interval')} className={`flex-1 text-[10px] py-1 rounded transition-colors ${sortKey === 'interval' ? 'bg-gray-700 text-white font-bold' : 'text-gray-500 hover:text-gray-300'}`}>
                        Interval {sortKey === 'interval' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-2">
                {processedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600">No candidates match current filters.</div>
                ) : (
                    processedResults.map((r, i) => (
                        <div 
                            key={i}
                            onClick={() => onSelect(r)}
                            className={`grid grid-cols-12 gap-2 p-2 rounded cursor-pointer border-b border-gray-800 hover:bg-gray-800 transition-colors items-center ${selectedId === r.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                        >
                            <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                <input 
                                    type="checkbox" 
                                    checked={checkedIds.has(r.id)} 
                                    onChange={() => onToggleCheck(r.id)}
                                    className="rounded bg-gray-700 border-gray-600 text-brand-primary focus:ring-0 w-4 h-4"
                                />
                            </div>
                            <span className="col-span-3 font-bold text-brand-primary">{r.intervalLabel}</span>
                            <span className="col-span-3 text-gray-300">{r.delayBeats} beats</span>
                            <div className="col-span-2">
                                <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded w-fit ${r.grade === 'STRONG' ? 'bg-green-900 text-green-300' : r.grade === 'VIABLE' ? 'bg-yellow-900 text-yellow-300' : 'bg-red-900 text-red-300'}`}>
                                    {r.grade}
                                </span>
                            </div>
                            <span className="col-span-3 text-xs text-gray-500">{r.errors.length > 0 ? `${r.errors.length} issues` : '-'}</span>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

import React, { useMemo } from 'react';
import { StrettoCandidate, PianoRollTrackData, HarmonicRegion, RawNote } from '../../types';
import { PlayIcon, StopIcon, CheckIcon, DownloadIcon } from '../Icons';
import PianoRoll from '../PianoRoll';
import { playSpecificNotes } from '../midiPlaybackService';

interface StrettoInspectorProps {
    candidate: StrettoCandidate | null;
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    assemblyResult: string;
    assemblyLog: string[];
    onClearAssembly: () => void;
    onDownloadChain: () => void;
}

export default function StrettoInspector({ 
    candidate, ppq, ts, isPlaying, onPlay, 
    assemblyResult, assemblyLog, onClearAssembly, onDownloadChain 
}: StrettoInspectorProps) {

    const pianoRollData: PianoRollTrackData | null = useMemo(() => {
        if (!candidate) return null;
        return {
            name: `Stretto ${candidate.intervalLabel}`,
            ppq,
            timeSignature: { numerator: ts.num, denominator: ts.den },
            notes: candidate.notes.map(n => ({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: n.velocity,
                name: n.name,
                voiceIndex: n.voiceIndex ?? 0, 
                isOrnament: false
            })),
            harmonicRegions: candidate.regions 
        };
    }, [candidate, ppq, ts]);

    const handleRegionClick = (region: HarmonicRegion) => {
        if (!candidate) return;
        const activeNotes = candidate.notes.filter(n => 
            n.ticks < region.endTick && (n.ticks + n.durationTicks) > region.startTick
        );

        if (activeNotes.length > 0) {
            const notesToPlay = activeNotes.map(n => ({
                name: n.name,
                duration: n.durationTicks * (0.5 / ppq), 
                velocity: n.velocity
            }));
            playSpecificNotes(notesToPlay);
        }
    };

    return (
        <div className="bg-gray-800 border border-gray-700 rounded p-4 flex flex-col h-[600px] shadow-lg relative overflow-hidden">

            {/* Gemini Assembly Overlay */}
            {assemblyResult && (
                <div className="absolute inset-0 bg-gray-800 z-30 p-4 flex flex-col animate-fade-in">
