                selectedCandidates={getSelectedCandidates()}
                onDownloadMidi={handleDownloadSelectedMidi}
                onAssemble={triggerAssembly}
                isAssembling={isAssembling}
                onRemoveCandidate={toggleCheck}
            />
        </div>
    );
}

import { useState, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { StrettoCandidate, RawNote } from '../types';
import { parseSimpleAbc } from '../components/services/abcBridge';

interface UseStrettoAssemblyProps {
    notes: RawNote[];
    ppq: number;
}

export const useStrettoAssembly = ({ notes: subjectNotes, ppq }: UseStrettoAssemblyProps) => {
    const [isAssembling, setIsAssembling] = useState(false);
    const [assemblyStatus, setAssemblyStatus] = useState<string>('');
    const [assemblyResult, setAssemblyResult] = useState<string>('');
    const [assemblyLog, setAssemblyLog] = useState<string[]>([]);
    const [attemptCount, setAttemptCount] = useState(0);

    const runAssembly = useCallback(async (
        candidates: StrettoCandidate[], 
        abcInput: string
    ) => {
        if (candidates.length === 0) {
            alert("Please select at least one stretto candidate.");
            return;
        }

        setIsAssembling(true);
        setAssemblyLog([]);
        setAttemptCount(1);
        setAssemblyResult('');

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        const totalEntries = candidates.length + 1; // Candidates + Original Subject

        const systemPrompt = `You are a master of fugal counterpoint. 
Task: Assemble a ${totalEntries}-voice stretto maestrale chain in ABC notation.

CRITICAL INSTRUCTIONS:
1. **Full Subject Usage**: Where possible, make use of the **ENTIRE** subject for every entry. Do not truncate the subject prematurely unless absolutely necessary for the final cadence.
2. **Original Subject**: You MUST include the Original Subject (P1) starting at Beat 0 as the foundation.
3. **Stretto Entries**: You MUST use all the additional stretto entries listed in the prompt.
4. Provide an "Assembly Order" section before the ABC.
5. Separate voices clearly using V:1, V:2, etc.
6. Use the provided Subject ABC as the theme.

Output Format:
[ASSEMBLY ORDER]
1. Original Subject at 0 beats
2. {Interval} at {Delay} beats
...

[ABC]
X:1
T: Stretto Chain
...
`;

        // We explicitly add the Original Subject as Entry 1
        const candidateList = candidates.map((r, i) => `Entry ${i+2}: ${r.intervalLabel} entering after ${r.delayBeats} beats`).join('\n');

        let currentInput = `Subject ABC: ${abcInput}

Required Entries (Use ALL ${totalEntries}):
Entry 1: Original Subject (P1) starting at Beat 0. (Do not modify intervals).
${candidateList}

Construct the chain now. Remember: Let every voice complete the full subject if the counterpoint allows.`;

        try {
            for (let i = 1; i <= 3; i++) {
                setAttemptCount(i);
                setAssemblyStatus(`Attempt ${i}: Querying Gemini...`);

                const response = await ai.models.generateContent({
                    model: 'gemini-3-pro-preview',
                    contents: currentInput,
                    config: { systemInstruction: systemPrompt }
                });

                const generatedText = response.text || '';

                // Extract ABC part if mixed with text
                let abcContent = generatedText;
                if (generatedText.includes('[ABC]')) {
                    abcContent = generatedText.split('[ABC]')[1].trim();
                } else if (generatedText.includes('X:1')) {
                    const parts = generatedText.split('X:1');
                    abcContent = 'X:1' + parts[1];
                }

                setAssemblyResult(generatedText); // Save full text to show Order + ABC
                setAssemblyStatus(`Attempt ${i}: Verifying counterpoint...`);

                // Algorithmic Verification (Basic Parse Check)
                const genNotes = parseSimpleAbc(abcContent, ppq);
                const errors: string[] = [];

                if (genNotes.length < subjectNotes.length * totalEntries * 0.7) {
                    errors.push("Output seems truncated (notes count too low for full subject usage).");
                }

                if (errors.length === 0 || i === 3) {
                    setAssemblyLog(prev => [...prev, `Pass ${i}: ${errors.length === 0 ? "Verified Successful" : "Final Attempt Reached"}`]);
                    setAssemblyStatus('Assembly Complete');
                    break;
                } else {
                    setAssemblyLog(prev => [...prev, `Pass ${i}: Failed verification. Issues: ${errors.join(', ')}`]);
                    currentInput = `The previous ABC had the following issues: ${errors.join('. ')}. Please correct and try again. Ensure you use the FULL subject for all voices.\n\nPrevious Output:\n${generatedText}`;
                }
            }
        } catch (err) {
            console.error(err);
            setAssemblyStatus('Error during assembly.');
            setAssemblyLog(prev => [...prev, `Error: ${err instanceof Error ? err.message : String(err)}`]);
        } finally {
            setIsAssembling(false);
        }
    }, [ppq, subjectNotes]);

    return {
        isAssembling,
        assemblyStatus,
        assemblyResult,
        assemblyLog,
        attemptCount,
        setAssemblyResult,
        runAssembly
    };
};

import { RawNote } from '../../types';

// Simple map for note names to MIDI, centered on C4 = 60
const BASE_MIDI: Record<string, number> = {
    'C': 60, 'D': 62, 'E': 64, 'F': 65, 'G': 67, 'A': 69, 'B': 71,
    'c': 72, 'd': 74, 'e': 76, 'f': 77, 'g': 79, 'a': 81, 'b': 83
};

export function parseSimpleAbc(abcString: string, ppq: number = 480): RawNote[] {
    // This is a very rudimentary parser designed for single-voice subjects
    // Handles: Pitch (C, c, c', C,), Accidentals (^, _, =), Length (2, /2, 3/2), Rests (z, Z, x, X)

    const clean = abcString.replace(/\|/g, '').replace(/\s+/g, ' '); // Remove bars and extra whitespace

    // Regex to match ABC token: 
    // [Accidental][Note/Rest][Octave][Length]
    // Accidental: ^, ^^, _, __, =
    // Note: A-G, a-g, z, Z, x, X
    // Octave: ', ,, 
    // Length: number, /number, number/number

    const regex = /([\^=_]*)?([a-gA-GzZxX])([,']*)?([0-9]*\/?[0-9]*)?/g;

    const notes: RawNote[] = [];
    let currentTick = 0;
    let match;

    // Default L:1/4 assumed for now if not parsed from header
    // We treat 1 unit = 1 quarter note = ppq
    const defaultDuration = ppq; 

    while ((match = regex.exec(clean)) !== null) {
        if (match[0] === '') continue;

        const accStr = match[1] || '';
        const letter = match[2];
        const octStr = match[3] || '';
        const lenStr = match[4] || '';

        // Parsing Duration (Shared logic for Notes and Rests)
        let mult = 1.0;
        if (lenStr) {
            if (lenStr === '/') mult = 0.5;
            else if (lenStr.includes('/')) {
                const [n, d] = lenStr.split('/');
                const num = n === '' ? 1 : parseFloat(n);
                const den = d === '' ? 2 : parseFloat(d);
                mult = num / den;
            } else {
                mult = parseFloat(lenStr);
            }
        }

        const durationTicks = Math.round(defaultDuration * mult);

        // Handle Rests (z/Z for standard, x/X for invisible)
        if (['z', 'Z', 'x', 'X'].includes(letter)) {
            currentTick += durationTicks;
            continue;
        }

        // Handle Notes
        let midi = BASE_MIDI[letter];
        if (midi === undefined) continue; // Skip if invalid

        // Accidentals
        if (accStr.includes('^^')) midi += 2;
        else if (accStr.includes('^')) midi += 1;
        else if (accStr.includes('__')) midi -= 2;
        else if (accStr.includes('_')) midi -= 1;
        // Natural '=' does nothing in this simple parser context (relative to C major)

        // Octaves
        if (octStr) {
            const up = (octStr.match(/'/g) || []).length;
            const down = (octStr.match(/,/g) || []).length;
            midi += (up * 12) - (down * 12);
        }

        notes.push({
            midi,
            ticks: currentTick,
            durationTicks,
            velocity: 0.8,
            name: `${letter}${accStr}${octStr}`,
            isOrnament: false
        });

        currentTick += durationTicks;
    }

    return notes;
}

import React, { useState, useMemo } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate } from './services/strettoCore';
import { Spinner } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
}

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("c2 G c d e f g3 a b c'2");

    // Configuration State
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');

    // Selection State
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
    const [isPlaying, setIsPlaying] = useState(false);

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // Analysis Core Loop
    const results = useMemo(() => {
        if (subjectNotes.length === 0) return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        configIntervals.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, ppq, ts, searchRes]);

    const getSelectedCandidates = () => {
        return results.filter(r => checkedIds.has(r.id));
    };

    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.map(n => ({
            name: n.name,
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) {
                next.delete(id);
            } else {
                next.add(id);
                const candidate = results.find(r => r.id === id);
                if (candidate) setSelectedCandidate(candidate);
            }
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    const handleDownloadSelectedMidi = () => {
        const selected = getSelectedCandidates();
        if (selected.length === 0) return;

        const newMidi = new Midi();
        // newMidi.header.ppq is read-only. We must scale our ticks to match it.
        const exportPpq = newMidi.header.ppq;
        const scale = exportPpq / ppq;

        newMidi.header.tempos.push({ bpm: 120, ticks: 0 });
        newMidi.header.timeSignatures.push({ timeSignature: [ts.num, ts.den], ticks: 0 });

        selected.forEach((cand) => {
            const track = newMidi.addTrack();
            track.name = `${cand.intervalLabel} @ ${cand.delayBeats}B`;
            track.instrument.name = "Acoustic Grand Piano";

            cand.notes.forEach(n => {
                track.addNote({
                    midi: n.midi,
                    ticks: Math.round(n.ticks * scale),
                    durationTicks: Math.round(n.durationTicks * scale),
                    velocity: n.velocity
                });
            });
        });

        const midiBytes = newMidi.toArray();
        const blob = new Blob([midiBytes], { type: 'audio/midi' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Stretto_Candidates_${selected.length}.mid`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const handleDownloadChainMidi = () => {
        if (!assemblyResult) return;
        const newMidi = new Midi();
        // Use the default PPQ of the new file
        const exportPpq = newMidi.header.ppq;

        newMidi.header.tempos.push({ bpm: 120, ticks: 0 });
        newMidi.header.timeSignatures.push({ timeSignature: [ts.num, ts.den], ticks: 0 });

        const parts = assemblyResult.split(/V:\s*\d+/g);
        const voiceContents = parts.length > 1 ? parts.slice(1) : [assemblyResult];

        voiceContents.forEach((content, idx) => {
            const track = newMidi.addTrack();
            track.name = `Chain Voice ${idx + 1}`;
            track.instrument.name = "String Ensemble 1";

            // Parse ABC using the export PPQ directly so no scaling is needed later
            const notes = parseSimpleAbc(content, exportPpq);

            notes.forEach(n => track.addNote({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: 0.8
            }));
        });

        const midiBytes = newMidi.toArray();
        const blob = new Blob([midiBytes], { type: 'audio/midi' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Gemini_Stretto_Chain.mid`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-wrap gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 items-center justify-between">
                <div className="flex gap-2">
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>
                <div className="text-xs text-gray-500 font-mono">
                    Mode: {mode === 'midi' ? 'Track Analysis' : 'Text Input'}
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6">
                    <label className="block text-sm text-gray-400 mb-2 font-bold uppercase tracking-wider">Subject ABC</label>
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="Enter ABC notation melody..."
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            <StrettoConfig 
                selectedIntervals={configIntervals} 
                setSelectedIntervals={setConfigIntervals} 
                searchRes={searchRes} 
                setSearchRes={setSearchRes} 
            />

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                <StrettoList 
                    candidates={results} 
                    selectedId={selectedCandidate?.id || null}
                    onSelect={setSelectedCandidate}
                    checkedIds={checkedIds}
                    onToggleCheck={toggleCheck}
                />

                <StrettoInspector 
                    candidate={selectedCandidate}
                    ppq={ppq}
                    ts={ts}
                    isPlaying={isPlaying}
                    onPlay={handlePlay}
                    assemblyResult={assemblyResult}
                    assemblyLog={assemblyLog}
                    onClearAssembly={() => setAssemblyResult('')}
                    onDownloadChain={handleDownloadChainMidi}
                />
            </div>

            <StrettoFooter 
                selectedCandidates={getSelectedCandidates()}
                onDownloadMidi={handleDownloadSelectedMidi}
                onAssemble={triggerAssembly}
                isAssembling={isAssembling}
                onRemoveCandidate={toggleCheck}
            />
        </div>
    );
}

import { useState, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { StrettoCandidate, RawNote } from '../types';
import { parseSimpleAbc } from '../components/services/abcBridge';

interface UseStrettoAssemblyProps {
    notes: RawNote[];
    ppq: number;
    ts?: { num: number, den: number };
}

export const useStrettoAssembly = ({ notes: subjectNotes, ppq, ts }: UseStrettoAssemblyProps) => {
    const [isAssembling, setIsAssembling] = useState(false);
    const [assemblyStatus, setAssemblyStatus] = useState<string>('');
    const [assemblyResult, setAssemblyResult] = useState<string>('');
    const [assemblyLog, setAssemblyLog] = useState<string[]>([]);
    const [attemptCount, setAttemptCount] = useState(0);

    const runAssembly = useCallback(async (
        candidates: StrettoCandidate[], 
        abcInput: string
    ) => {
        if (candidates.length === 0) {
            alert("Please select at least one stretto candidate.");
            return;
        }

        setIsAssembling(true);
        setAssemblyLog([]);
        setAttemptCount(1);
        setAssemblyResult('');

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        const totalEntries = candidates.length + 1; // Candidates + Original Subject
        const timeSigStr = ts ? `${ts.num}/${ts.den}` : '4/4';

        const systemPrompt = `You are a master of fugal counterpoint. 
Task: Assemble a ${totalEntries}-voice STRETTO (overlapping canon) in ABC notation.

CRITICAL INSTRUCTIONS:
1. **OVERLAP IS MANDATORY**: This is a Stretto. Voices MUST enter while previous voices are still playing. Do NOT chain them sequentially (do not wait for one to finish before starting the next).
2. **ENTRY TIMING**: Adhere strictly to the "Start Beat" specified for each voice. All Start Beats are relative to the beginning of the piece (Beat 0).
3. **FULL SUBJECT**: Where possible, let every voice play the ENTIRE subject duration. Do not truncate early unless necessary for a final cadence.
4. **Original Subject**: Voice 1 is always the Original Subject (P1) starting at Beat 0.
5. **Format**: Use standard ABC notation with multiple voices (V:1, V:2...).
6. **Spacing**: Ensure the "z" (rest) duration at the start of each voice perfectly matches the requested Start Beat.

Output Format:
[ASSEMBLY ORDER]
1. Voice 1: Original Subject at Beat 0
2. Voice 2: [Interval] at Beat [X]
...

[ABC]
X:1
T: Stretto Assembly
M: ${timeSigStr}
L: 1/8
K: C
V:1 name="Subject"
...
`;

        // Explicitly defining absolute start times for the LLM
        const candidateList = candidates.map((r, i) => {
            const startBeat = r.delayBeats;
            return `Voice ${i+2}: Transpose ${r.intervalLabel}. START BEAT: ${startBeat} (This voice enters ${startBeat} beats after the beginning of the piece).`;
        }).join('\n');

        let currentInput = `Subject ABC: ${abcInput}

Configuration (Total ${totalEntries} Voices):
Voice 1: Original Subject (P1). START BEAT: 0.
${candidateList}

Generate the ABC now. Ensure simultaneous playback (polyphony) by padding the start of voices with correct rests (z).`;

        try {
            for (let i = 1; i <= 3; i++) {
                setAttemptCount(i);
                setAssemblyStatus(`Attempt ${i}: Querying Gemini...`);

                const response = await ai.models.generateContent({
                    model: 'gemini-3-pro-preview',
                    contents: currentInput,
                    config: { systemInstruction: systemPrompt }
                });

                const generatedText = response.text || '';

                // Extract ABC part if mixed with text
                let abcContent = generatedText;
                if (generatedText.includes('[ABC]')) {
                    abcContent = generatedText.split('[ABC]')[1].trim();
                } else if (generatedText.includes('X:1')) {
                    const parts = generatedText.split('X:1');
                    abcContent = 'X:1' + parts[1];
                }

                setAssemblyResult(generatedText); // Save full text to show Order + ABC
                setAssemblyStatus(`Attempt ${i}: Verifying counterpoint...`);

                // Algorithmic Verification (Basic Parse Check)
                const genNotes = parseSimpleAbc(abcContent, ppq);
                const errors: string[] = [];

                // Verification: Check if it looks polyphonic (short overall duration relative to sum of parts)
                const subjectDuration = subjectNotes.reduce((max, n) => Math.max(max, n.ticks + n.durationTicks), 0);
                const generatedDuration = genNotes.reduce((max, n) => Math.max(max, n.ticks + n.durationTicks), 0);
                const sequentialDuration = subjectDuration * totalEntries;

                // If the generated duration is close to sequentialDuration, it failed to overlap
                if (generatedDuration > sequentialDuration * 0.8 && totalEntries > 1) {
                    errors.push("Output appears sequential (too long). Ensure voices overlap.");
                }

                if (genNotes.length < subjectNotes.length * totalEntries * 0.7) {
                    errors.push("Output seems truncated (note count too low).");
                }

                if (errors.length === 0 || i === 3) {
                    setAssemblyLog(prev => [...prev, `Pass ${i}: ${errors.length === 0 ? "Verified Successful" : "Final Attempt Reached"}`]);
                    setAssemblyStatus('Assembly Complete');
                    break;
                } else {
                    setAssemblyLog(prev => [...prev, `Pass ${i}: Failed verification. Issues: ${errors.join(', ')}`]);
                    currentInput = `The previous ABC had the following issues: ${errors.join('. ')}. Please correct and try again. Ensure you use the FULL subject for all voices and they OVERLAP in time.\n\nPrevious Output:\n${generatedText}`;
                }
            }
        } catch (err) {
            console.error(err);
            setAssemblyStatus('Error during assembly.');
            setAssemblyLog(prev => [...prev, `Error: ${err instanceof Error ? err.message : String(err)}`]);
        } finally {
            setIsAssembling(false);
        }
    }, [ppq, subjectNotes, ts]);

    return {
        isAssembling,
        assemblyStatus,
