import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption } from '../../types';
import { getIntervalLabel, getStrictPitchName } from './midiSpelling';

// Constants
const NOTE_NAMES = ['C','C#','D','D#','E','F','F#','G','G#','A','A#','B'];
const DISSONANT_SIMPLE = new Set([1, 2, 6, 10, 11]); // m2, M2, TT, m7, M7

// Transposition Sets
const TRAD_TRANS = new Set([0, 12, -12, 24, -24, 7, 19, -5, -17, 5, 17, -7, -19]);
const THIRD_SIXTH_TRANS = new Set([3, 4, 8, 9, -3, -4, -8, -9, 15, 16, 20, 21, -15, -16, -20, -21]);

// --- Helper Functions ---

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; // P4 against bass
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

// Inversion Logic
// Simple major scale map for now, centered on the pivot
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    // 1. Find step distance from pivot
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;

    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) {
        // Chromatic fallback: just invert across pivot
        return pivot - diff; 
    }

    const absStep = (octaves * 7) + scaleIndex;

    // 2. Invert step
    const invStep = -absStep;

    // 3. Convert back to pitch
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];

    return pivot + (invOctaves * 12) + invSemitone;
}

// --- Timeline & Validation ---

interface Timeline {
    [tick16: number]: { [voiceIdx: number]: number }; // tick -> voice -> pitch
}

interface InternalSubjectNote {
    relTick16: number; // 16th note grid relative to start
    dur16: number;
    pitch: number;
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalSubjectNote[] {
    const sorted = [...notes].sort((a,b) => a.ticks - b.ticks);
    if (sorted.length === 0) return [];
    const startTick = sorted[0].ticks;
    const ticksPer16 = ppq / 4;

    return sorted.map(n => ({
        relTick16: Math.round((n.ticks - startTick) / ticksPer16),
        dur16: Math.max(1, Math.round(n.durationTicks / ticksPer16)),
        pitch: n.midi
    }));
}

function getSubjectNotes(
    type: 'N' | 'I', 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    length16: number
): InternalSubjectNote[] {
    const source = type === 'N' ? baseSubject : invertedSubject;
    // Filter by length
    return source.filter(n => n.relTick16 < length16).map(n => ({
        ...n,
        dur16: Math.min(n.dur16, length16 - n.relTick16)
    }));
}

function buildTimeline(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[],
    ppq: number // Used only for debug/format if needed, logic is 16th based
): Timeline {
    const tl: Timeline = {};

    specs.forEach((spec, vIdx) => {
        const notes = getSubjectNotes(spec.type, baseSubject, invertedSubject, spec.length);
        const start16 = Math.round(spec.startBeat * 4); // beats to 16ths

        notes.forEach(n => {
            for (let t = 0; t < n.dur16; t++) {
                const absTick = start16 + n.relTick16 + t;
                if (!tl[absTick]) tl[absTick] = {};
                tl[absTick][vIdx] = n.pitch + spec.transposition;
            }
        });
    });

    return tl;
}

function checkRules(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): { valid: boolean, warnings: string[] } {

    const tl = buildTimeline(specs, baseSubject, invertedSubject, 480);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const warnings: string[] = [];

    const numVoices = specs.length;

    for (let i = 0; i < numVoices; i++) {
        for (let j = i + 1; j < numVoices; j++) {

            // Build interaction pairs
            const sounding: { t: number, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[i] !== undefined && v[j] !== undefined) {
                    sounding.push({ t, p1: v[i], p2: v[j] });
                }
            });

            if (sounding.length < 2) continue;

            // RULE 1: Parallel Perfect Intervals (Immediate Succession)
            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];

                // Only check if time is contiguous (<= 1 16th gap allowed by logic, but here discrete)
                if (curr.t - prev.t > 1) continue;

                // Only check on motion
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;

                const loPrev = Math.min(prev.p1, prev.p2);
                const hiPrev = Math.max(prev.p1, prev.p2);
                const loCurr = Math.min(curr.p1, curr.p2);
                const hiCurr = Math.max(curr.p1, curr.p2);

                if (isParallelPerfect(loPrev, hiPrev) && isParallelPerfect(loCurr, hiCurr)) {
                    const int1 = (hiPrev - loPrev) % 12;
                    const int2 = (hiCurr - loCurr) % 12;

                    if (int1 === int2) {
                        // Parallel 5th/8ve -> FATAL
                        return { valid: false, warnings: [] };
                    }

                    // Direct/Hidden checking (Warning only)
                    if (int1 !== int2 && (int2 === 0 || int2 === 7)) {
                        const v1Move = curr.p1 - prev.p1;
                        const v2Move = curr.p2 - prev.p2;
                        // Similar motion
                        if ((v1Move > 0 && v2Move > 0) || (v1Move < 0 && v2Move < 0)) {
                            // Check if upper voice leaped (simplified)
                            // warnings.push(`Direct ${getIntervalLabel(int2)} (V${i+1}-V${j+1})`);
                        }
                    }
                }
            }

            // RULE 2: Dissonance Runs
            // (Skipping for performance/brevity, handled by `strettoCore` usually)
        }
    }

    return { valid: true, warnings };
}

// --- Search Algorithm ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoChainResult[]> {

    // 1. Prepare Subjects
    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) return [];

    const subjectLen16 = Math.max(...baseSubject.map(n => n.relTick16 + n.dur16));
    const truncLen16 = Math.floor(subjectLen16 * 0.6); // Allow 40% truncation

    const invertedSubject: InternalSubjectNote[] = [];
    if (options.allowInversion) {
        baseSubject.forEach(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi);
            if (inv !== null) invertedSubject.push({ ...n, pitch: inv });
        });
    }

    const results: StrettoChainResult[] = [];
    const MAX_RESULTS = 50;

    // Transposition Sets
    const validTranspositions = new Set(TRAD_TRANS);
    if (options.allowThirdSixth) {
        THIRD_SIXTH_TRANS.forEach(t => validTranspositions.add(t));
    }

    // Recursive Search
    // state: current chain of options
    // constraints: remaining budget for inversion, truncation, 3rd/6th

    async function solve(chain: StrettoChainOption[], nInv: number, n3rd: number, nTrunc: number) {
        if (results.length >= MAX_RESULTS) return;

        // Valid Chain found?
        if (chain.length === options.targetVoices) {
            // Re-verify full matrix (optimization: we check incrementally, but full check ensures global constraints)
            const { valid, warnings } = checkRules(chain, baseSubject, invertedSubject);
            if (valid) {
                // Calc Score
                const dists = chain.map((c, i) => i === 0 ? 0 : c.startBeat - chain[i-1].startBeat);
                const distinctDists = new Set(dists.slice(1)).size;
                const score = distinctDists * 10 - warnings.length;

                results.push({
                    id: `chain-${Date.now()}-${results.length}`,
                    entries: [...chain],
                    warnings,
                    score
                });
            }
            return;
        }

        // Branch
        const lastEntry = chain[chain.length - 1];

        // Strategy: Try adding next voice
        // 1. Distance: 0.5 beat to 4.0 beats (increments of 0.5)
        // Optimization: Try to maintain or decrease distance slightly
        const lastDist = chain.length > 1 ? (chain[chain.length-1].startBeat - chain[chain.length-2].startBeat) : 4;
        const maxDist = Math.min(lastDist + 1, 8); 

        // Iterating distances (High to Low to favor spread?)
        for (let d = 1; d <= maxDist * 2; d++) {
            const distBeats = d * 0.5;
            const newStart = lastEntry.startBeat + distBeats;

            // Try Transpositions (Relative to V1 or Prev?)
            // Usually standard counterpoint relates to Subject 1 OR Local.
            // Let's iterate absolute transpositions that are valid relative to at least one neighbour

            const candidateTrans: number[] = [];
            validTranspositions.forEach(t => candidateTrans.push(t + lastEntry.transposition)); // Relative to prev

            for (const absTrans of candidateTrans) {
                // Constraints check
                const relToPrev = absTrans - lastEntry.transposition;
                const is3rd = THIRD_SIXTH_TRANS.has(relToPrev);

                if (is3rd && n3rd >= 1) continue; // Budget exhausted

                // Entry Types
                const types: {type: 'N'|'I', len: number, costInv: number, costTrunc: number}[] = [];

                // Normal Full
                types.push({ type: 'N', len: subjectLen16, costInv: 0, costTrunc: 0 });

                // Inverted Full
                if (options.allowInversion && nInv < 1) {
                    types.push({ type: 'I', len: subjectLen16, costInv: 1, costTrunc: 0 });
                }

                // Normal Truncated
                if (options.allowTruncation && nTrunc < 1) {
                    types.push({ type: 'N', len: truncLen16, costInv: 0, costTrunc: 1 });
                }

                for (const tOpt of types) {
                    const newEntry: StrettoChainOption = {
                        startBeat: newStart,
                        transposition: absTrans,
                        type: tOpt.type,
                        length: tOpt.len,
                        voiceIndex: chain.length
                    };

                    // Incremental Check (Prev vs Curr)
                    // Optimization: Check only against existing voices to fail fast
                    const testChain = [...chain, newEntry];
                    const { valid } = checkRules(testChain, baseSubject, invertedSubject);

                    if (valid) {
                        await solve(testChain, nInv + tOpt.costInv, n3rd + (is3rd?1:0), nTrunc + tOpt.costTrunc);
                    }

                    // Yield to event loop occasionally
                    if (results.length % 5 === 0) await new Promise(r => setTimeout(r, 0));
                    if (results.length >= MAX_RESULTS) return;
                }
            }
        }
    }

    // Start Search
    // V1 is always (0, 0, N, Full) OR (0, 12, N, Full)
    const roots = [0, 12];
    for (const r of roots) {
        await solve([{
            startBeat: 0,
            transposition: r,
            type: 'N',
            length: subjectLen16,
            voiceIndex: 0
        }], 0, 0, 0);
    }

    return results.sort((a,b) => b.score - a.score);
}

import React from 'react';
import { StrettoSearchOptions } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';

interface StrettoSearchPanelProps {
    options: StrettoSearchOptions;
    setOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
}

export default function StrettoSearchPanel({ options, setOptions, onSearch, isSearching }: StrettoSearchPanelProps) {

    const handleChange = (field: keyof StrettoSearchOptions, val: any) => {
        setOptions({ ...options, [field]: val });
    };

    return (
        <div className="bg-gray-800 border border-gray-700 rounded p-4 mb-6 shadow-sm">
            <div className="flex justify-between items-center mb-4 border-b border-gray-700 pb-2">
                <h3 className="text-sm font-bold text-gray-300 uppercase tracking-wider">Algorithmic Chain Finder</h3>
                {isSearching && <span className="text-xs text-brand-primary animate-pulse">Searching...</span>}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-4">
                {/* Target Voices */}
                <div>
                    <label className="block text-xs font-bold text-gray-500 mb-1">Target Entries</label>
                    <div className="flex items-center gap-2">
                        {[3, 4, 5, 6].map(num => (
                            <button
                                key={num}
                                onClick={() => handleChange('targetVoices', num)}
                                className={`w-8 h-8 rounded text-sm font-bold border transition-colors ${options.targetVoices === num ? 'bg-brand-primary text-white border-brand-primary' : 'bg-gray-900 text-gray-400 border-gray-600 hover:border-gray-400'}`}
                            >
                                {num}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Constraints */}
                <div className="flex flex-col gap-2">
                    <label className="flex items-center cursor-pointer">
                        <input 
                            type="checkbox" 
                            checked={options.allowTruncation}
                            onChange={(e) => handleChange('allowTruncation', e.target.checked)}
                            className="rounded bg-gray-900 border-gray-600 text-brand-primary focus:ring-0 mr-2"
                        />
                        <span className="text-xs text-gray-300">Allow 1 Truncated Entry</span>
                    </label>
                    <label className="flex items-center cursor-pointer">
                        <input 
                            type="checkbox" 
                            checked={options.allowThirdSixth}
                            onChange={(e) => handleChange('allowThirdSixth', e.target.checked)}
                            className="rounded bg-gray-900 border-gray-600 text-brand-primary focus:ring-0 mr-2"
                        />
                        <span className="text-xs text-gray-300">Allow 3rd/6th Transposition</span>
                    </label>
                </div>

                {/* Inversion Config */}
                <div className="col-span-1 md:col-span-2 bg-gray-900 p-3 rounded border border-gray-700">
                    <div className="flex items-center justify-between mb-2">
                        <label className="flex items-center cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={options.allowInversion}
                                onChange={(e) => handleChange('allowInversion', e.target.checked)}
                                className="rounded bg-gray-700 border-gray-500 text-brand-secondary focus:ring-0 mr-2"
                            />
                            <span className="text-xs font-bold text-gray-300">Enable Tonal Inversion</span>
                        </label>
                    </div>

                    <div className={`flex items-center gap-2 transition-opacity ${!options.allowInversion ? 'opacity-50 pointer-events-none' : ''}`}>
                        <span className="text-[10px] text-gray-500">Pivot Note:</span>
                        <select 
                            value={options.pivotMidi}
                            onChange={(e) => handleChange('pivotMidi', parseInt(e.target.value))}
                            className="bg-gray-800 border border-gray-600 text-xs rounded px-2 py-1 text-gray-300"
                        >
                            {Array.from({length: 12}).map((_, i) => {
                                const midi = 60 + i; // Middle C octave
                                return <option key={midi} value={midi}>{getStrictPitchName(midi)}</option>
                            })}
                        </select>
                        <span className="text-[10px] text-gray-500 italic">(Axis of symmetry)</span>
                    </div>
                </div>
            </div>

            <button 
                onClick={onSearch}
                disabled={isSearching}
                className="w-full py-2 bg-brand-primary hover:bg-brand-secondary text-white font-bold rounded shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
                {isSearching ? 'Processing...' : 'Run Search Algorithm'}
            </button>
        </div>
    );
}

import React from 'react';
import { StrettoChainResult } from '../../types';
import { getIntervalLabel } from '../services/midiSpelling';

interface StrettoResultsListProps {
    results: StrettoChainResult[];
    selectedId: string | null;
    onSelect: (res: StrettoChainResult) => void;
}

export default function StrettoResultsList({ results, selectedId, onSelect }: StrettoResultsListProps) {
    if (results.length === 0) {
        return <div className="text-center text-gray-500 py-10">No chains found yet. Run the search to begin.</div>;
    }

    return (
        <div className="overflow-y-auto max-h-[500px]">
            {results.map((res, i) => {
                const dists = res.entries.slice(1).map((e, idx) => (e.startBeat - res.entries[idx].startBeat).toFixed(1));
                const entryBadges = res.entries.map((e, idx) => {
                    const transLabel = idx === 0 ? 'P1' : getIntervalLabel(e.transposition - res.entries[idx-1].transposition);
                    let color = 'bg-gray-700';
                    if (e.type === 'I') color = 'bg-blue-900 text-blue-200';
                    if (e.length < 100) color = 'bg-orange-900 text-orange-200'; // heuristic for trunc
                    return (
                        <span key={idx} className={`text-[10px] px-1 rounded ${color} mr-1`}>
                            {transLabel}
                        </span>
                    );
                });

                return (
                    <div 
                        key={res.id}
                        onClick={() => onSelect(res)}
                        className={`p-3 border-b border-gray-700 cursor-pointer hover:bg-gray-800 transition-colors ${selectedId === res.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                    >
                        <div className="flex justify-between items-center mb-1">
                            <span className="font-bold text-gray-300 text-sm">Config #{i + 1}</span>
                            <span className="text-[10px] bg-black/30 px-2 rounded text-gray-500">Score: {res.score}</span>
                        </div>
                        <div className="flex flex-wrap mb-1">{entryBadges}</div>
                        <div className="text-[10px] text-gray-500 font-mono">
                            Distances: {dists.join(' -> ')}
                        </div>
                    </div>
                );
            })}
        </div>
    );
}

import React, { useState, useMemo } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; // Import Generator
import { Spinner } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoSearchPanel from './stretto/StrettoSearchPanel'; // Import Search Panel
import StrettoResultsList from './stretto/StrettoResultsList'; // Import Results List

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
}

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("c2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('pairwise'); // Toggle View

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        targetVoices: 4, allowTruncation: true, allowInversion: false, allowThirdSixth: false, pivotMidi: 65 // F4
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        configIntervals.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, ppq, ts, searchRes, viewMode]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSelectedChain(null);

        // Timeout to allow UI render
        setTimeout(async () => {
            try {
                const results = await searchStrettoChains(subjectNotes, searchOptions, ppq);
                setChainResults(results);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    // We reuse the Inspector by converting a Chain Result into a "Candidate" format temporarily
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        // Flatten all notes
        let allNotes: RawNote[] = [];
        // Helper to normalize subject
        const sortedSubj = [...subjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach(entry => {
            // Re-generate notes for this entry
            // This is a simplified reconstruction for visualization
            const entryStartTick = Math.round(entry.startBeat * ppq);
            // NOTE: Inversion logic duplication here - ideally share utility
            // For simple viz, we assume normal or simple chromatic inversion if type I
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                // Simple inversion around pivot if needed (replicate logic or simplify)
                if (entry.type === 'I') {
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, // Re-align time
                    midi: pitch,
                    name: "N", // Calc later
                    voiceIndex: entry.voiceIndex,
                    // Truncation check
                    durationTicks: n.durationTicks // Simplified, actual generator handles ticks precisely
                };
            });

            // Apply truncation by filtering end time
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            allNotes = [...allNotes, ...clipped];
        });

        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], // Visualization logic will recalculate regions
            notes: allNotes
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.map(n => ({
            name: n.name, // Name might need regeneration if not strict
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6">
                    <label className="block text-sm text-gray-400 mb-2 font-bold uppercase tracking-wider">Subject ABC</label>
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="Enter ABC notation melody..."
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            selectedId={selectedCandidate?.id || null}
                            onSelect={setSelectedCandidate}
                            checkedIds={checkedIds}
                            onToggleCheck={toggleCheck}
                        />

                        <StrettoInspector 
                            candidate={selectedCandidate}
                            ppq={ppq}
                            ts={ts}
                            isPlaying={isPlaying}
                            onPlay={handlePlay}
                            assemblyResult={assemblyResult}
                            assemblyLog={assemblyLog}
                            onClearAssembly={() => setAssemblyResult('')}
                            onDownloadChain={() => {}} // Not implemented for single pair yet
                        />
                    </div>

                    <StrettoFooter 
                        selectedCandidates={getSelectedCandidates()}
                        onDownloadMidi={() => {}}
                        onAssemble={triggerAssembly}
                        isAssembling={isAssembling}
                        onRemoveCandidate={toggleCheck}
                    />
                </>
            ) : (
                <>
                    <StrettoSearchPanel 
                        options={searchOptions} 
                        setOptions={setSearchOptions}
                        onSearch={handleChainSearch}
                        isSearching={isSearching}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                        <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                            <h3 className="p-3 text-xs font-bold text-gray-400 border-b border-gray-700 bg-gray-800">FOUND CHAINS ({chainResults.length})</h3>
                            <StrettoResultsList 
                                results={chainResults}
                                selectedId={selectedChain?.id || null}
                                onSelect={setSelectedChain}
                            />
                        </div>
                        <div className="lg:col-span-2">
                            <StrettoInspector 
                                candidate={chainToCandidate}
                                ppq={ppq}
                                ts={ts}
                                isPlaying={isPlaying}
                                onPlay={handlePlay}
                                assemblyResult={""}
                                assemblyLog={[]}
                                onClearAssembly={() => {}}
                                onDownloadChain={() => {
                                    // TODO: Implement Download for Chain
                                    alert("Download Chain not yet linked.");
                                }}
                            />
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

