                    <div className={`flex items-center gap-2 px-1 transition-opacity ${options.truncationMode === 'None' ? 'opacity-30 pointer-events-none' : ''}`}>
                        <span className="text-[10px] text-gray-500 w-16">Length:</span>
                        <input 
                            type="range" min="10" max="90" step="5"
                            value={options.truncationPercent}
                            onChange={(e) => handleChange('truncationPercent', parseInt(e.target.value))}
                            className="flex-grow h-1.5 bg-gray-600 rounded-lg appearance-none cursor-pointer accent-brand-primary"
                        />
                        <span className="text-[10px] font-mono text-brand-primary w-8 text-right">{options.truncationPercent}%</span>
                    </div>
                </div>

                {/* 3. Inversion (Col 3) */}
                <div className="lg:col-span-3 flex flex-col gap-2">
                    {renderConstraintSelector("Inverted Entries", "inversionMode", options.inversionMode)}
                    <div className={`flex items-center gap-2 px-1 transition-opacity ${options.inversionMode === 'None' ? 'opacity-30 pointer-events-none' : ''}`}>
                        <span className="text-[10px] text-gray-500">Pivot:</span>
                        <select 
                            value={options.pivotMidi}
                            onChange={(e) => handleChange('pivotMidi', parseInt(e.target.value))}
                            className="bg-gray-900 border border-gray-600 text-[10px] rounded px-1 py-0.5 text-gray-300 flex-grow"
                        >
                            {Array.from({length: 12}).map((_, i) => {
                                const midi = 60 + i; 
                                return <option key={midi} value={midi}>{getStrictPitchName(midi)}</option>
                            })}
                        </select>
                    </div>
                </div>

                {/* 4. Intervals (Col 3) */}
                <div className="lg:col-span-3">
                    {renderConstraintSelector("Intervals (from Prev)", "thirdSixthMode", options.thirdSixthMode)}
                    <p className="text-[9px] text-gray-500 mt-2 italic px-1">
                        Select "Unlimited" to allow 3rds/6ths relative to the previous voice. P1/P5/P8 always allowed.
                    </p>
                </div>
            </div>

            <button 
                onClick={onSearch}
                disabled={isSearching}
                className="w-full py-2 bg-brand-primary hover:bg-brand-secondary text-white font-bold rounded shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed text-sm uppercase tracking-wide"
            >
                {isSearching ? 'Processing Combinations...' : 'Run Search Algorithm'}
            </button>
        </div>
    );
}

import React from 'react';
import { StrettoChainResult } from '../../types';
import { getIntervalLabel } from '../services/midiSpelling';

interface StrettoResultsListProps {
    results: StrettoChainResult[];
    selectedId: string | null;
    onSelect: (res: StrettoChainResult) => void;
}

export default function StrettoResultsList({ results, selectedId, onSelect }: StrettoResultsListProps) {
    if (results.length === 0) {
        return <div className="text-center text-gray-500 py-10">No chains found yet. Run the search to begin.</div>;
    }

    return (
        <div className="overflow-y-auto max-h-[500px]">
            {results.map((res, i) => {
                const dists = res.entries.slice(1).map((e, idx) => (e.startBeat - res.entries[idx].startBeat).toFixed(1));
                const entryBadges = res.entries.map((e, idx) => {
                    const transLabel = idx === 0 ? 'P1' : getIntervalLabel(e.transposition - res.entries[idx-1].transposition);
                    let color = 'bg-gray-700';
                    if (e.type === 'I') color = 'bg-blue-900 text-blue-200';
                    if (e.length < 100) color = 'bg-orange-900 text-orange-200'; // heuristic for trunc

                    const tooltip = idx === 0 ? "Voice 1 (Original)" : `Voice ${idx+1} vs Voice ${idx}: ${transLabel}`;

                    return (
                        <span key={idx} className={`text-[10px] px-1 rounded ${color} mr-1 cursor-help`} title={tooltip}>
                            {idx === 0 ? 'V1' : transLabel}
                        </span>
                    );
                });

                return (
                    <div 
                        key={res.id}
                        onClick={() => onSelect(res)}
                        className={`p-3 border-b border-gray-700 cursor-pointer hover:bg-gray-800 transition-colors ${selectedId === res.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                    >
                        <div className="flex justify-between items-center mb-1">
                            <span className="font-bold text-gray-300 text-sm">Config #{i + 1}</span>
                            <span className="text-[10px] bg-black/30 px-2 rounded text-gray-500">Score: {res.score}</span>
                        </div>
                        <div className="flex flex-wrap mb-1">{entryBadges}</div>
                        <div className="text-[10px] text-gray-500 font-mono flex gap-2">
                            <span>Distances:</span>
                            <span className="text-gray-400">{dists.join(' → ')}</span>
                        </div>
                    </div>
                );
            })}
        </div>
    );
}

import { RawNote } from '../../types';

// Standard ABC Pitch Mapping
// C = 48 (C below middle C)
// c = 60 (Middle C)
const BASE_PITCHES: Record<string, number> = {
    'C': 48, 'D': 50, 'E': 52, 'F': 53, 'G': 55, 'A': 57, 'B': 59,
    'c': 60, 'd': 62, 'e': 64, 'f': 65, 'g': 67, 'a': 69, 'b': 71
};

// Key Signature Definitions (Sharps/Flats to apply)
const KEY_SIGNATURES: Record<string, Record<string, number>> = {
    'C': {}, 'Am': {},
    'G': { 'f': 1, 'F': 1 }, 'Em': { 'f': 1, 'F': 1 },
    'D': { 'f': 1, 'F': 1, 'c': 1, 'C': 1 }, 'Bm': { 'f': 1, 'F': 1, 'c': 1, 'C': 1 },
    'A': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1 }, 'F#m': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1 },
    'E': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1 }, 'C#m': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1 },
    'B': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1, 'a': 1, 'A': 1 },
    'F': { 'b': -1, 'B': -1 }, 'Dm': { 'b': -1, 'B': -1 },
    'Bb': { 'b': -1, 'B': -1, 'e': -1, 'E': -1 }, 'Gm': { 'b': -1, 'B': -1, 'e': -1, 'E': -1 },
    'Eb': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1 }, 'Cm': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1 },
    'Ab': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1 }, 'Fm': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1 },
};

function getBaseMidi(char: string): number {
    return BASE_PITCHES[char] || 60;
}

export function parseSimpleAbc(abcString: string, ppq: number = 480): RawNote[] {
    const lines = abcString.split(/\r?\n/);

    // Default Context
    let keyAccidentals: Record<string, number> = {};
    let defaultNoteLength = 1/8; // Standard ABC default if L: is missing but often depends on Meter. We default to 1/8.

    const notes: RawNote[] = [];
    let currentTick = 0;

    // 1. Parse Headers First
    let bodyStartLine = 0;
    for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trim();
        if (line.length === 0) continue;

        // Check for Header (Letter + Colon + Value)
        const headerMatch = line.match(/^([A-Za-z]):\s*(.*)/);
        if (headerMatch) {
            const field = headerMatch[1];
            const value = headerMatch[2].trim();

            if (field === 'K') {
                // Parse Key: K:G, K:Gm, K:Bb
                // Remove 'maj' if present, handle minor 'm'
                const keyClean = value.replace('maj', '').split(' ')[0]; 
                if (KEY_SIGNATURES[keyClean]) {
                    keyAccidentals = { ...KEY_SIGNATURES[keyClean] };
                }
            } else if (field === 'L') {
                // Parse Unit Length: L:1/4, L:1/8
                const parts = value.split('/');
                if (parts.length === 2) {
                    const num = parseFloat(parts[0]);
                    const den = parseFloat(parts[1]);
                    if (!isNaN(num) && !isNaN(den) && den !== 0) {
                        defaultNoteLength = num / den;
                    }
                }
            } else if (field === 'M') {
                // If M is set but L is not, standard ABC rules apply:
                // If meter < 0.75 (e.g. 2/4=0.5, 3/4=0.75, 4/4=1.0, 6/8=0.75), default L is 1/16. 
                // Wait, logic is: if Meter < 0.75, L=1/16. Else L=1/8.
                // 2/4 = 0.5 -> L=1/16. 3/4 = 0.75 -> L=1/8. 4/4 = 1.0 -> L=1/8. 6/8 = 0.75 -> L=1/8.
                // For simplicity in this bridge, we assume the user sets L explicitly if they want control, 
                // but we default to 1/8 (common for leadsheets) or keep user provided.
            }
        } else {
            // Found a non-header line, assuming body starts here
            bodyStartLine = i;
            break;
        }
    }

    // Combine body lines
    const bodyText = lines.slice(bodyStartLine).join(' ').replace(/\|/g, ' ').replace(/\s+/g, ' ');

    // 2. Parse Notes
    // Token Regex: 
    // (Accidental)? (NoteLetter) (Octave)? (Duration)?
    // Accidental: ^, ^^, _, __, =
    // Note: A-G, a-g, z, Z, x, X
    // Octave: ', ,,
    // Duration: /, //, 2, /2, 3/2
    const regex = /([\^=_]*)?([a-gA-GzZxX])([,']*)?([0-9]*\/?[0-9]*)?/g;

    let match;

    // Ticks per Whole Note (4 * ppq)
    const wholeNoteTicks = ppq * 4;

    while ((match = regex.exec(bodyText)) !== null) {
        if (match[0] === '') continue;

        const accStr = match[1] || '';
        const letter = match[2];
        const octStr = match[3] || '';
        const lenStr = match[4] || '';

        // Calculate Duration Multiplier relative to L
        let durMult = 1.0;
        if (lenStr) {
            if (lenStr === '/') durMult = 0.5;
            else if (lenStr === '//') durMult = 0.25;
            else if (lenStr.startsWith('/')) {
                durMult = 1 / parseFloat(lenStr.substring(1));
            } else if (lenStr.includes('/')) {
                const [n, d] = lenStr.split('/');
                const num = n === '' ? 1 : parseFloat(n);
                const den = d === '' ? 1 : parseFloat(d); // ABC allows "3/" -> 3/2? No, usually "3/2". "3" -> 3.
                durMult = num / den;
            } else {
                durMult = parseFloat(lenStr);
            }
        }

        // Calculate actual ticks: (WholeNoteTicks * DefaultLengthRatio * TokenMultiplier)
        const durationTicks = Math.round(wholeNoteTicks * defaultNoteLength * durMult);

        if (['z', 'Z', 'x', 'X'].includes(letter)) {
            currentTick += durationTicks;
            continue;
        }

        let midi = getBaseMidi(letter);

        // Key Signature
        // Apply key signature accidental if no explicit natural is present
        // (Simplified: In strict ABC, explicit accidentals reset per bar. 
        // Here we just apply key sig unless overridden inline).

        let accidentalOffset = 0;

        // 1. Explicit Accidental
        if (accStr.includes('^^')) accidentalOffset = 2;
        else if (accStr.includes('^')) accidentalOffset = 1;
        else if (accStr.includes('__')) accidentalOffset = -2;
        else if (accStr.includes('_')) accidentalOffset = -1;
        else if (accStr.includes('=')) accidentalOffset = 0; // Natural forces 0 offset relative to white keys
        else {
            // 2. Implicit Key Signature (only if no explicit accidental)
            // Note: 'c' matches 'c' in keysig, 'C' matches 'C' (we populated both cases in map)
            if (keyAccidentals[letter]) {
                accidentalOffset = keyAccidentals[letter];
            }
        }

        midi += accidentalOffset;

        // Octaves
        if (octStr) {
            const up = (octStr.match(/'/g) || []).length;
            const down = (octStr.match(/,/g) || []).length;
            midi += (up * 12) - (down * 12);
        }

        notes.push({
            midi,
            ticks: currentTick,
            durationTicks,
            velocity: 0.8,
            name: `${accStr}${letter}${octStr}`,
            isOrnament: false
        });

        currentTick += durationTicks;
    }

    return notes;
}

import React, { useState, useMemo } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; // Import Generator
import { Spinner } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoSearchPanel from './stretto/StrettoSearchPanel'; // Import Search Panel
import StrettoResultsList from './stretto/StrettoResultsList'; // Import Results List

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
}

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("L:1/4\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('pairwise'); // Toggle View

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        targetVoices: 4, 
        truncationMode: 'Max 1',
        truncationPercent: 60,
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65 // F4
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        configIntervals.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, ppq, ts, searchRes, viewMode]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSelectedChain(null);

        // Timeout to allow UI render
        setTimeout(async () => {
            try {
                const results = await searchStrettoChains(subjectNotes, searchOptions, ppq);
                setChainResults(results);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    // We reuse the Inspector by converting a Chain Result into a "Candidate" format temporarily
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        // Flatten all notes
        let allNotes: RawNote[] = [];
        // Helper to normalize subject
        const sortedSubj = [...subjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach(entry => {
            // Re-generate notes for this entry
            // This is a simplified reconstruction for visualization
            const entryStartTick = Math.round(entry.startBeat * ppq);
            // NOTE: Inversion logic duplication here - ideally share utility
            // For simple viz, we assume normal or simple chromatic inversion if type I
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                // Simple inversion around pivot if needed (replicate logic or simplify)
                if (entry.type === 'I') {
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, // Re-align time
                    midi: pitch,
                    name: "N", // Calc later
                    voiceIndex: entry.voiceIndex,
                    // Truncation check
                    durationTicks: n.durationTicks // Simplified, actual generator handles ticks precisely
                };
            });

            // Apply truncation by filtering end time
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            allNotes = [...allNotes, ...clipped];
        });

        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], // Visualization logic will recalculate regions
            notes: allNotes
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.map(n => ({
            name: n.name, // Name might need regeneration if not strict
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6">
                    <div className="flex justify-between items-center mb-2">
                        <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                        <span className="text-[10px] text-gray-500 font-mono">Supports K: (Key) and L: (Length) headers</span>
                    </div>
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="L:1/4\nK:C\nc2 G c d e f g"
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            selectedId={selectedCandidate?.id || null}
                            onSelect={setSelectedCandidate}
                            checkedIds={checkedIds}
                            onToggleCheck={toggleCheck}
                        />

                        <StrettoInspector 
                            candidate={selectedCandidate}
                            ppq={ppq}
                            ts={ts}
                            isPlaying={isPlaying}
                            onPlay={handlePlay}
                            assemblyResult={assemblyResult}
                            assemblyLog={assemblyLog}
                            onClearAssembly={() => setAssemblyResult('')}
                            onDownloadChain={() => {}} // Not implemented for single pair yet
                        />
                    </div>

                    <StrettoFooter 
                        selectedCandidates={getSelectedCandidates()}
                        onDownloadMidi={() => {}}
                        onAssemble={triggerAssembly}
                        isAssembling={isAssembling}
                        onRemoveCandidate={toggleCheck}
                    />
                </>
            ) : (
                <>
                    <StrettoSearchPanel 
                        options={searchOptions} 
                        setOptions={setSearchOptions}
                        onSearch={handleChainSearch}
                        isSearching={isSearching}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                        <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                            <h3 className="p-3 text-xs font-bold text-gray-400 border-b border-gray-700 bg-gray-800">FOUND CHAINS ({chainResults.length})</h3>
                            <StrettoResultsList 
                                results={chainResults}
                                selectedId={selectedChain?.id || null}
                                onSelect={setSelectedChain}
                            />
                        </div>
                        <div className="lg:col-span-2">
                            <StrettoInspector 
                                candidate={chainToCandidate}
                                ppq={ppq}
                                ts={ts}
                                isPlaying={isPlaying}
                                onPlay={handlePlay}
                                assemblyResult={""}
                                assemblyLog={[]}
                                onClearAssembly={() => {}}
                                onDownloadChain={() => {
                                    // TODO: Implement Download for Chain
                                    alert("Download Chain not yet linked.");
                                }}
                            />
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

import { RawNote } from '../../types';

// Standard ABC Pitch Mapping
// C = 48 (C below middle C)
// c = 60 (Middle C)
const BASE_PITCHES: Record<string, number> = {
    'C': 48, 'D': 50, 'E': 52, 'F': 53, 'G': 55, 'A': 57, 'B': 59,
    'c': 60, 'd': 62, 'e': 64, 'f': 65, 'g': 67, 'a': 69, 'b': 71
};

// Key Signature Definitions (Sharps/Flats to apply)
const KEY_SIGNATURES: Record<string, Record<string, number>> = {
    'C': {}, 'Am': {},
    'G': { 'f': 1, 'F': 1 }, 'Em': { 'f': 1, 'F': 1 },
    'D': { 'f': 1, 'F': 1, 'c': 1, 'C': 1 }, 'Bm': { 'f': 1, 'F': 1, 'c': 1, 'C': 1 },
    'A': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1 }, 'F#m': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1 },
    'E': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1 }, 'C#m': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1 },
    'B': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1, 'a': 1, 'A': 1 },
    'F': { 'b': -1, 'B': -1 }, 'Dm': { 'b': -1, 'B': -1 },
    'Bb': { 'b': -1, 'B': -1, 'e': -1, 'E': -1 }, 'Gm': { 'b': -1, 'B': -1, 'e': -1, 'E': -1 },
    'Eb': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1 }, 'Cm': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1 },
    'Ab': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1 }, 'Fm': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1 },
};

function getBaseMidi(char: string): number {
    return BASE_PITCHES[char] || 60;
}

export function parseSimpleAbc(abcString: string, ppq: number = 480): RawNote[] {
    const lines = abcString.split(/\r?\n/);

    // Default Context
    let keyAccidentals: Record<string, number> = {};
    let defaultNoteLength = 1/8; 
    let tempo = 120; // Default Q

    const notes: RawNote[] = [];
    let currentTick = 0;

    // 1. Parse Headers First
    let bodyStartLine = 0;
    for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trim();
        if (line.length === 0) continue;

        // Check for Header (Letter + Colon + Value)
        const headerMatch = line.match(/^([A-Za-z]):\s*(.*)/);
        if (headerMatch) {
            const field = headerMatch[1];
            const value = headerMatch[2].trim();

            if (field === 'K') {
                const keyClean = value.replace('maj', '').split(' ')[0]; 
                if (KEY_SIGNATURES[keyClean]) {
                    keyAccidentals = { ...KEY_SIGNATURES[keyClean] };
                }
            } else if (field === 'L') {
                const parts = value.split('/');
                if (parts.length === 2) {
                    const num = parseFloat(parts[0]);
                    const den = parseFloat(parts[1]);
                    if (!isNaN(num) && !isNaN(den) && den !== 0) {
                        defaultNoteLength = num / den;
                    }
                }
            } else if (field === 'Q') {
                // Parse Q: 1/4=120 or just 120
                if (value.includes('=')) {
                    tempo = parseFloat(value.split('=')[1]);
                } else {
                    tempo = parseFloat(value);
                }
            } else if (field === 'M') {
                // Parse Meter M: 4/4
                // Not strictly used for note calculation but good for context if we expanded
            }
        } else {
            // Found a non-header line, assuming body starts here
            bodyStartLine = i;
            break;
        }
    }

    // Combine body lines
    const bodyText = lines.slice(bodyStartLine).join(' ').replace(/\|/g, ' ').replace(/\s+/g, ' ');

    // 2. Parse Notes
    const regex = /([\^=_]*)?([a-gA-GzZxX])([,']*)?([0-9]*\/?[0-9]*)?/g;

    let match;

    // Ticks per Whole Note (4 * ppq)
    const wholeNoteTicks = ppq * 4;

    while ((match = regex.exec(bodyText)) !== null) {
        if (match[0] === '') continue;

        const accStr = match[1] || '';
        const letter = match[2];
        const octStr = match[3] || '';
        const lenStr = match[4] || '';

        // Calculate Duration Multiplier relative to L
        let durMult = 1.0;
        if (lenStr) {
            if (lenStr === '/') durMult = 0.5;
            else if (lenStr === '//') durMult = 0.25;
            else if (lenStr.startsWith('/')) {
                durMult = 1 / parseFloat(lenStr.substring(1));
            } else if (lenStr.includes('/')) {
                const [n, d] = lenStr.split('/');
                const num = n === '' ? 1 : parseFloat(n);
                const den = d === '' ? 1 : parseFloat(d); 
                durMult = num / den;
            } else {
                durMult = parseFloat(lenStr);
            }
        }

        // Calculate actual ticks
        const durationTicks = Math.round(wholeNoteTicks * defaultNoteLength * durMult);

        if (['z', 'Z', 'x', 'X'].includes(letter)) {
            currentTick += durationTicks;
            continue;
        }

        let midi = getBaseMidi(letter);

        let accidentalOffset = 0;

        // 1. Explicit Accidental
        if (accStr.includes('^^')) accidentalOffset = 2;
        else if (accStr.includes('^')) accidentalOffset = 1;
        else if (accStr.includes('__')) accidentalOffset = -2;
        else if (accStr.includes('_')) accidentalOffset = -1;
        else if (accStr.includes('=')) accidentalOffset = 0; 
        else {
            // 2. Implicit Key Signature
            if (keyAccidentals[letter]) {
                accidentalOffset = keyAccidentals[letter];
            }
        }

        midi += accidentalOffset;

        // Octaves
        if (octStr) {
            const up = (octStr.match(/'/g) || []).length;
            const down = (octStr.match(/,/g) || []).length;
            midi += (up * 12) - (down * 12);
        }

        notes.push({
            midi,
            ticks: currentTick,
            durationTicks,
            velocity: 0.8,
            name: `${accStr}${letter}${octStr}`,
            isOrnament: false
        });

        currentTick += durationTicks;
    }

    return notes;
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode } from '../../types';
import { getIntervalLabel, getStrictPitchName } from './midiSpelling';

// Constants
const DISSONANT_SIMPLE = new Set([1, 2, 6, 10, 11]); // m2, M2, TT, m7, M7

// Transposition Sets
const TRAD_TRANS = new Set([0, 12, -12, 24, -24, 7, 19, -5, -17, 5, 17, -7, -19]);
const THIRD_SIXTH_TRANS = new Set([3, 4, 8, 9, -3, -4, -8, -9, 15, 16, 20, 21, -15, -16, -20, -21]);

// --- Helper Functions ---

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; // P4 against bass
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

// Inversion Logic
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

// --- Timeline & Validation ---

interface Timeline {
    [tick16: number]: { [voiceIdx: number]: number }; // tick -> voice -> pitch
}

interface InternalSubjectNote {
    relTick16: number; // 16th note grid relative to start
    dur16: number;
    pitch: number;
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalSubjectNote[] {
    const sorted = [...notes].sort((a,b) => a.ticks - b.ticks);
    if (sorted.length === 0) return [];
    const startTick = sorted[0].ticks;
    const ticksPer16 = ppq / 4;

    return sorted.map(n => ({
        relTick16: Math.round((n.ticks - startTick) / ticksPer16),
        dur16: Math.max(1, Math.round(n.durationTicks / ticksPer16)),
        pitch: n.midi
    }));
}

function getSubjectNotes(
    type: 'N' | 'I', 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    length16: number
): InternalSubjectNote[] {
    const source = type === 'N' ? baseSubject : invertedSubject;
    // Filter by length
    return source.filter(n => n.relTick16 < length16).map(n => ({
        ...n,
        dur16: Math.min(n.dur16, length16 - n.relTick16)
    }));
}

function buildTimeline(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): Timeline {
    const tl: Timeline = {};

    specs.forEach((spec, vIdx) => {
        const notes = getSubjectNotes(spec.type, baseSubject, invertedSubject, spec.length);
        const start16 = Math.round(spec.startBeat * 4); // beats to 16ths

        notes.forEach(n => {
            for (let t = 0; t < n.dur16; t++) {
                const absTick = start16 + n.relTick16 + t;
                if (!tl[absTick]) tl[absTick] = {};
                tl[absTick][vIdx] = n.pitch + spec.transposition;
            }
        });
    });

    return tl;
}

function checkRules(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): { valid: boolean, warnings: string[] } {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const warnings: string[] = [];
    const numVoices = specs.length;

    for (let i = 0; i < numVoices; i++) {
        for (let j = i + 1; j < numVoices; j++) {
            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[i] !== undefined && v[j] !== undefined) {
                    const minAll = Math.min(...Object.values(v));
                    const lo = Math.min(v[i], v[j]);
                    const hi = Math.max(v[i], v[j]);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1: v[i], p2: v[j] });
                }
            });

            if (sounding.length < 2) continue;

            // RULE 1: Parallel Perfect
            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];

                if (curr.t - prev.t > 1) continue;
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;

                if (isParallelPerfect(prev.lo, prev.hi) && isParallelPerfect(curr.lo, curr.hi)) {
                    const int1 = (prev.hi - prev.lo) % 12;
                    const int2 = (curr.hi - curr.lo) % 12;
                    if (int1 === int2) return { valid: false, warnings: [] };
                }
            }

            // RULE 2: Dissonance Runs
            let k = 0;
            while (k < sounding.length) {
                const startEv = sounding[k];
                if (!isDissonant(startEv.lo, startEv.hi, startEv.lowerIsBass)) {
                    k++; continue;
                }

                let segStart = k;
                while (k < sounding.length) {
                    const curr = sounding[k];
                    if (!isDissonant(curr.lo, curr.hi, curr.lowerIsBass)) break;

                    if ((curr.t - sounding[segStart].t + 1) >= 4) { // 1 Beat threshold
                        const distinctPitches = new Set<string>();
                        for(let m = segStart; m <= k; m++) distinctPitches.add(`${sounding[m].p1}-${sounding[m].p2}`);
                        if (distinctPitches.size > 1) return { valid: false, warnings: [] }; 
                    }
                    k++;
                }
            }
        }
    }

    return { valid: true, warnings };
}

// --- Search Algorithm ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoChainResult[]> {

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) return [];

    const subjectLen16 = Math.max(...baseSubject.map(n => n.relTick16 + n.dur16));
    const subjectBeats = subjectLen16 / 4;
    const truncLen16 = Math.floor(subjectLen16 * (options.truncationPercent / 100)); 

    // Constraints: Start 40%, Min Remaining 20%
    const maxStart16 = Math.floor(subjectLen16 * 0.40); // Must start by 40%
    const minRemaining16 = Math.floor(subjectLen16 * 0.20); // Must have 20% left

    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        baseSubject.forEach(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi);
            if (inv !== null) invertedSubject.push({ ...n, pitch: inv });
        });
    }

    const results: StrettoChainResult[] = [];
    const MAX_RESULTS = 50;

    const validTranspositions = new Set(TRAD_TRANS);
    if (options.thirdSixthMode !== 'None') {
        THIRD_SIXTH_TRANS.forEach(t => validTranspositions.add(t));
    }

    const isBudgetAvailable = (mode: StrettoConstraintMode, currentUsage: number) => {
        if (mode === 'None') return false;
        if (mode === 'Max 1') return currentUsage < 1;
        return true; 
    };

    async function solve(chain: StrettoChainOption[], nInv: number, n3rd: number, nTrunc: number) {
        if (results.length >= MAX_RESULTS) return;

        if (chain.length === options.targetVoices) {
            const { valid, warnings } = checkRules(chain, baseSubject, invertedSubject);
            if (valid) {
                const dists = chain.map((c, i) => i === 0 ? 0 : c.startBeat - chain[i-1].startBeat);
                const distinctDists = new Set(dists.slice(1)).size;
                const score = distinctDists * 10 - warnings.length;
                results.push({
                    id: `chain-${Date.now()}-${results.length}`,
                    entries: [...chain],
                    warnings,
                    score
                });
            }
            return;
        }

        const lastEntry = chain[chain.length - 1];

        // --- Distance Strategy ---
        // Iterate valid musical times (Eighth Note steps = 0.5 beat)
        // 1. Max Delay based on "Generally Decreasing" or Previous Distance
        let maxSearchDistBeats = 0;
        if (chain.length === 1) {
            // First Entry (V1->V2): Max is 40% of subject
            maxSearchDistBeats = maxStart16 / 4; 
        } else {
            // Decreasing rule: cannot exceed previous distance + small margin
            const prevDist = chain[chain.length-1].startBeat - chain[chain.length-2].startBeat;
            maxSearchDistBeats = prevDist + 0.5;
        }

        // Convert to Eighth Note steps (0.5 beats)
        const maxSteps = Math.floor(maxSearchDistBeats * 2);

        // Iterate DOWNWARDS (Prefer larger gaps for distinctness, but respect constraints)
        for (let s = maxSteps; s >= 1; s--) {
            const distBeats = s * 0.5;
            const newStart = lastEntry.startBeat + distBeats;

            // Min Remaining Check
            // Effective length of this voice depends on whether it is truncated or full
            // But the rule is "start with at least 20% of subject remaining" - meaning overlap with previous?
            // "with at least 20% of subject remaining" usually implies the *previous* voice must still be playing.
            // Let's assume: The ENTRY point must be before the PREVIOUS voice ends by at least 20% of subject length.
            const prevEnd = lastEntry.startBeat + (lastEntry.length / 4);
            const remaining = prevEnd - newStart;
            const minRemBeats = minRemaining16 / 4;

            if (remaining < minRemBeats) continue; // Too late, not enough overlap

            const candidateTrans: number[] = [];
            validTranspositions.forEach(t => candidateTrans.push(t + lastEntry.transposition)); 

            for (const absTrans of candidateTrans) {
                // Interval Constraints
                const relToPrev = absTrans - lastEntry.transposition;
                const is3rd = THIRD_SIXTH_TRANS.has(relToPrev);
                if (is3rd && !isBudgetAvailable(options.thirdSixthMode, n3rd)) continue;

                // Type Options
                const types: {type: 'N'|'I', len: number, costInv: number, costTrunc: number}[] = [];

                types.push({ type: 'N', len: subjectLen16, costInv: 0, costTrunc: 0 });

                if (isBudgetAvailable(options.inversionMode, nInv)) {
                    types.push({ type: 'I', len: subjectLen16, costInv: 1, costTrunc: 0 });
                }
                if (isBudgetAvailable(options.truncationMode, nTrunc)) {
                    types.push({ type: 'N', len: truncLen16, costInv: 0, costTrunc: 1 });
                }
                if (isBudgetAvailable(options.inversionMode, nInv) && isBudgetAvailable(options.truncationMode, nTrunc)) {
                    types.push({ type: 'I', len: truncLen16, costInv: 1, costTrunc: 1 });
                }

                for (const tOpt of types) {
                    const newEntry: StrettoChainOption = {
                        startBeat: newStart,
                        transposition: absTrans,
                        type: tOpt.type,
                        length: tOpt.len,
                        voiceIndex: chain.length
                    };

                    const testChain = [...chain, newEntry];
                    const { valid } = checkRules(testChain, baseSubject, invertedSubject);

                    if (valid) {
                        await solve(testChain, nInv + tOpt.costInv, n3rd + (is3rd?1:0), nTrunc + tOpt.costTrunc);
                    }
                    if (results.length >= MAX_RESULTS) return;
                }
            }
            if (results.length >= MAX_RESULTS) return;
        }
    }

    const roots = [0, 12];
    for (const r of roots) {
        await solve([{
            startBeat: 0,
            transposition: r,
            type: 'N',
            length: subjectLen16,
            voiceIndex: 0
        }], 0, 0, 0);
    }

    return results.sort((a,b) => b.score - a.score);
}

import React from 'react';
import { StrettoChainResult } from '../../types';
import { getIntervalLabel } from '../services/midiSpelling';

interface StrettoResultsListProps {
    results: StrettoChainResult[];
    selectedId: string | null;
    onSelect: (res: StrettoChainResult) => void;
}

export default function StrettoResultsList({ results, selectedId, onSelect }: StrettoResultsListProps) {
    if (results.length === 0) {
        return <div className="text-center text-gray-500 py-10">No chains found yet. Run the search to begin.</div>;
    }

    return (
        <div className="overflow-y-auto max-h-[500px]">
            {results.map((res, i) => {
                const entries = res.entries;

                const badges = entries.map((e, idx) => {
                    if (idx === 0) {
                        return (
                            <div key={idx} className="flex flex-col items-center bg-gray-800 p-1 rounded border border-gray-700 min-w-[50px]">
                                <span className="text-[10px] font-bold text-gray-400">V1</span>
                                <span className="text-xs text-white font-mono">0.0</span>
                            </div>
                        );
                    }

                    const prev = entries[idx-1];
                    const relInt = e.transposition - prev.transposition;
                    const absInt = e.transposition - entries[0].transposition;

                    const relDist = e.startBeat - prev.startBeat;
                    const absDist = e.startBeat;

                    let typeLabel = e.type === 'I' ? 'INV' : 'NOR';
                    let lenLabel = e.length < entries[0].length ? 'TRC' : 'FUL';

                    const borderClass = (e.type === 'I' || lenLabel === 'TRC') ? 'border-brand-primary' : 'border-gray-600';

                    return (
                        <div key={idx} className={`flex flex-col bg-gray-800 p-1 rounded border ${borderClass} min-w-[60px]`}>
                            {/* Header: Type */}
                            <div className="flex justify-between border-b border-gray-700 pb-0.5 mb-0.5">
                                <span className={`text-[8px] font-bold ${e.type === 'I' ? 'text-blue-300' : 'text-gray-500'}`}>{typeLabel}</span>
                                <span className={`text-[8px] font-bold ${lenLabel === 'TRC' ? 'text-orange-300' : 'text-gray-500'}`}>{lenLabel}</span>
                            </div>

                            {/* Intervals */}
                            <div className="flex gap-1 text-[9px] mb-0.5" title={`Rel: ${getIntervalLabel(relInt)} / Abs: ${getIntervalLabel(absInt)}`}>
                                <span className="text-gray-300 w-1/2 text-center border-r border-gray-700">R:{getIntervalLabel(relInt)}</span>
                                <span className="text-brand-primary w-1/2 text-center">A:{getIntervalLabel(absInt)}</span>
                            </div>

                            {/* Distances */}
                            <div className="flex gap-1 text-[9px] font-mono" title={`Delay: +${relDist} / Start: @${absDist}`}>
                                <span className="text-gray-400 w-1/2 text-center border-r border-gray-700">+{relDist.toFixed(1)}</span>
                                <span className="text-white w-1/2 text-center">@{absDist.toFixed(1)}</span>
                            </div>
                        </div>
                    );
                });

                return (
                    <div 
                        key={res.id}
                        onClick={() => onSelect(res)}
                        className={`p-2 border-b border-gray-700 cursor-pointer hover:bg-gray-800 transition-colors ${selectedId === res.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                    >
                        <div className="flex justify-between items-center mb-2">
                            <span className="font-bold text-gray-300 text-xs">Chain #{i + 1}</span>
                            <span className="text-[9px] bg-black/30 px-1.5 rounded text-gray-500">Score: {res.score}</span>
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {badges}
                        </div>
                    </div>
                );
            })}
        </div>
    );
}

import React, { useState, useMemo } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; // Import Generator
import { Spinner } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoSearchPanel from './stretto/StrettoSearchPanel'; // Import Search Panel
import StrettoResultsList from './stretto/StrettoResultsList'; // Import Results List

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
}

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('pairwise'); // Toggle View

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        targetVoices: 4, 
        truncationMode: 'Max 1',
        truncationPercent: 60,
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65 // F4
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        configIntervals.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, ppq, ts, searchRes, viewMode]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSelectedChain(null);

        // Timeout to allow UI render
        setTimeout(async () => {
            try {
                const results = await searchStrettoChains(subjectNotes, searchOptions, ppq);
                setChainResults(results);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    // We reuse the Inspector by converting a Chain Result into a "Candidate" format temporarily
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        // Flatten all notes
        let allNotes: RawNote[] = [];
        // Helper to normalize subject
        const sortedSubj = [...subjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        // Calculate visualization regions (Vertical Interval Events)
        // Simplified: Just pass notes to inspector, inspector will recalc visuals if needed
        // But StrettoCore expects 2 voice interaction. For multi-voice, we might need a custom visualizer
        // For now, let's just render the notes. The StrettoInspector handles multi-voice piano roll okay.

        selectedChain.entries.forEach(entry => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    // Simple chromatic inversion relative to pivot
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, 
                    midi: pitch,
                    name: "N",
                    voiceIndex: entry.voiceIndex,
                    durationTicks: n.durationTicks 
                };
            });

            // Apply truncation
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            allNotes = [...allNotes, ...clipped];
        });

        // We create a dummy candidate structure to feed the Inspector
        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], 
            notes: allNotes,
            // We can optionally generate harmonic regions here if we want to visualize dissonances
            // But for chains, simple piano roll might be enough for now.
            regions: [] 
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.map(n => ({
            name: n.name, // Name might need regeneration if not strict
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
