import React, { useState, useMemo } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; // Import Generator
import { Spinner } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoSearchPanel from './stretto/StrettoSearchPanel'; // Import Search Panel
import StrettoResultsList from './stretto/StrettoResultsList'; // Import Results List

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
}

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('pairwise'); // Toggle View

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        targetVoices: 4, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65 // F4
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        configIntervals.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, ppq, ts, searchRes, viewMode]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSelectedChain(null);

        // Timeout to allow UI render
        setTimeout(async () => {
            try {
                const results = await searchStrettoChains(subjectNotes, searchOptions, ppq);
                setChainResults(results);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    // We reuse the Inspector by converting a Chain Result into a "Candidate" format temporarily
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        // Flatten all notes
        let allNotes: RawNote[] = [];
        // Helper to normalize subject
        const sortedSubj = [...subjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        // Calculate visualization regions (Vertical Interval Events)
        // Simplified: Just pass notes to inspector, inspector will recalc visuals if needed
        // But StrettoCore expects 2 voice interaction. For multi-voice, we might need a custom visualizer
        // For now, let's just render the notes. The StrettoInspector handles multi-voice piano roll okay.

        selectedChain.entries.forEach(entry => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    // Simple chromatic inversion relative to pivot
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, 
                    midi: pitch,
                    name: "N",
                    voiceIndex: entry.voiceIndex,
                    durationTicks: n.durationTicks 
                };
            });

            // Apply truncation
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            allNotes = [...allNotes, ...clipped];
        });

        // We create a dummy candidate structure to feed the Inspector
        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], 
            notes: allNotes,
            // We can optionally generate harmonic regions here if we want to visualize dissonances
            // But for chains, simple piano roll might be enough for now.
            regions: [] 
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.map(n => ({
            name: n.name, // Name might need regeneration if not strict
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6">
                    <div className="flex justify-between items-center mb-2">
                        <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                        <span className="text-[10px] text-gray-500 font-mono">Supports M: (Meter), L: (Length), Q: (Tempo), K: (Key)</span>
                    </div>
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="M:4/4\nL:1/4\nK:C\nc2 G c d e f g"
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            selectedId={selectedCandidate?.id || null}
                            onSelect={setSelectedCandidate}
                            checkedIds={checkedIds}
                            onToggleCheck={toggleCheck}
                        />

                        <StrettoInspector 
                            candidate={selectedCandidate}
                            ppq={ppq}
                            ts={ts}
                            isPlaying={isPlaying}
                            onPlay={handlePlay}
                            assemblyResult={assemblyResult}
                            assemblyLog={assemblyLog}
                            onClearAssembly={() => setAssemblyResult('')}
                            onDownloadChain={() => {}} // Not implemented for single pair yet
                        />
                    </div>

                    <StrettoFooter 
                        selectedCandidates={getSelectedCandidates()}
                        onDownloadMidi={() => {}}
                        onAssemble={triggerAssembly}
                        isAssembling={isAssembling}
                        onRemoveCandidate={toggleCheck}
                    />
                </>
            ) : (
                <>
                    <StrettoSearchPanel 
                        options={searchOptions} 
                        setOptions={setSearchOptions}
                        onSearch={handleChainSearch}
                        isSearching={isSearching}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                        <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                            <h3 className="p-3 text-xs font-bold text-gray-400 border-b border-gray-700 bg-gray-800">FOUND CHAINS ({chainResults.length})</h3>
                            <StrettoResultsList 
                                results={chainResults}
                                selectedId={selectedChain?.id || null}
                                onSelect={setSelectedChain}
                            />
                        </div>
                        <div className="lg:col-span-2">
                            <StrettoInspector 
                                candidate={chainToCandidate}
                                ppq={ppq}
                                ts={ts}
                                isPlaying={isPlaying}
                                onPlay={handlePlay}
                                assemblyResult={""}
                                assemblyLog={[]}
                                onClearAssembly={() => {}}
                                onDownloadChain={() => {
                                    // TODO: Implement Download for Chain
                                    alert("Download Chain not yet linked.");
                                }}
                            />
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode } from '../../types';
import { getQuantizationTickValue } from './midiTransform';

// Constants
const DISSONANT_SIMPLE = new Set([1, 2, 6, 10, 11]); // m2, M2, TT, m7, M7

// Transposition Sets
const TRAD_TRANS = new Set([0, 12, -12, 24, -24, 7, 19, -5, -17, 5, 17, -7, -19]);
const THIRD_SIXTH_TRANS = new Set([3, 4, 8, 9, -3, -4, -8, -9, 15, 16, 20, 21, -15, -16, -20, -21]);

// --- Helper Functions ---

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; // P4 against bass
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

// Inversion Logic
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

// --- Timeline & Validation ---

interface Timeline {
    [tick16: number]: { [voiceIdx: number]: number }; // tick -> voice -> pitch
}

interface InternalSubjectNote {
    relTick16: number; // 16th note grid relative to start
    dur16: number;
    pitch: number;
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalSubjectNote[] {
    const sorted = [...notes].sort((a,b) => a.ticks - b.ticks);
    if (sorted.length === 0) return [];
    const startTick = sorted[0].ticks;
    const ticksPer16 = ppq / 4;

    return sorted.map(n => ({
        relTick16: Math.round((n.ticks - startTick) / ticksPer16),
        dur16: Math.max(1, Math.round(n.durationTicks / ticksPer16)),
        pitch: n.midi
    }));
}

function getSubjectNotes(
    type: 'N' | 'I', 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    length16: number
): InternalSubjectNote[] {
    const source = type === 'N' ? baseSubject : invertedSubject;
    // Filter by length
    return source.filter(n => n.relTick16 < length16).map(n => ({
        ...n,
        dur16: Math.min(n.dur16, length16 - n.relTick16)
    }));
}

function buildTimeline(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): Timeline {
    const tl: Timeline = {};

    specs.forEach((spec, vIdx) => {
        const notes = getSubjectNotes(spec.type, baseSubject, invertedSubject, spec.length);
        const start16 = Math.round(spec.startBeat * 4); // beats to 16ths

        notes.forEach(n => {
            for (let t = 0; t < n.dur16; t++) {
                const absTick = start16 + n.relTick16 + t;
                if (!tl[absTick]) tl[absTick] = {};
                tl[absTick][vIdx] = n.pitch + spec.transposition;
            }
        });
    });

    return tl;
}

function checkRules(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): { valid: boolean, warnings: string[] } {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const warnings: string[] = [];
    const numVoices = specs.length;

    for (let i = 0; i < numVoices; i++) {
        for (let j = i + 1; j < numVoices; j++) {
            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[i] !== undefined && v[j] !== undefined) {
                    const minAll = Math.min(...Object.values(v));
                    const lo = Math.min(v[i], v[j]);
                    const hi = Math.max(v[i], v[j]);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1: v[i], p2: v[j] });
                }
            });

            if (sounding.length < 2) continue;

            // RULE 1: Parallel Perfect
            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];

                if (curr.t - prev.t > 1) continue;
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;

                if (isParallelPerfect(prev.lo, prev.hi) && isParallelPerfect(curr.lo, curr.hi)) {
                    const int1 = (prev.hi - prev.lo) % 12;
                    const int2 = (curr.hi - curr.lo) % 12;
                    if (int1 === int2) return { valid: false, warnings: [] };
                }
            }

            // RULE 2: Dissonance Runs
            let k = 0;
            while (k < sounding.length) {
                const startEv = sounding[k];
                if (!isDissonant(startEv.lo, startEv.hi, startEv.lowerIsBass)) {
                    k++; continue;
                }

                let segStart = k;
                while (k < sounding.length) {
                    const curr = sounding[k];
                    if (!isDissonant(curr.lo, curr.hi, curr.lowerIsBass)) break;

                    if ((curr.t - sounding[segStart].t + 1) >= 4) { // 1 Beat threshold
                        const distinctPitches = new Set<string>();
                        for(let m = segStart; m <= k; m++) distinctPitches.add(`${sounding[m].p1}-${sounding[m].p2}`);
                        if (distinctPitches.size > 1) return { valid: false, warnings: [] }; 
                    }
                    k++;
                }
            }
        }
    }

    return { valid: true, warnings };
}

// --- Search Algorithm ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoChainResult[]> {

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) return [];

    const subjectLen16 = Math.max(...baseSubject.map(n => n.relTick16 + n.dur16));
    const subjectDurationBeats = subjectLen16 / 4;

    // Truncation Length Calculation (Fixed Musical Time)
    const truncMusicalTicks = getQuantizationTickValue(options.truncationMusicalValue, ppq);
    const truncLen16 = Math.max(1, Math.round(truncMusicalTicks / (ppq / 4)));

    // Window Logic for FIRST Answer (V2): [40% ... 80%] of Subject Length
    const minStart16 = Math.floor(subjectLen16 * 0.40);
    const maxStart16 = Math.floor(subjectLen16 * 0.80);

    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        baseSubject.forEach(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi);
            if (inv !== null) invertedSubject.push({ ...n, pitch: inv });
        });
    }

    const results: StrettoChainResult[] = [];
    const MAX_RESULTS = 50;

    const validTranspositions = new Set(TRAD_TRANS);
    if (options.thirdSixthMode !== 'None') {
        THIRD_SIXTH_TRANS.forEach(t => validTranspositions.add(t));
    }

    const isBudgetAvailable = (mode: StrettoConstraintMode, currentUsage: number) => {
        if (mode === 'None') return false;
        if (mode === 'Max 1') return currentUsage < 1;
        return true; 
    };

    async function solve(chain: StrettoChainOption[], nInv: number, n3rd: number, nTrunc: number) {
        if (results.length >= MAX_RESULTS) return;

        if (chain.length === options.targetVoices) {
            const { valid, warnings } = checkRules(chain, baseSubject, invertedSubject);
            if (valid) {
                const dists = chain.map((c, i) => i === 0 ? 0 : c.startBeat - chain[i-1].startBeat);
                const distinctDists = new Set(dists.slice(1)).size;
                const score = distinctDists * 10 - warnings.length;
                results.push({
                    id: `chain-${Date.now()}-${results.length}`,
                    entries: [...chain],
                    warnings,
                    score
                });
            }
            return;
        }

        const lastEntry = chain[chain.length - 1];

        // --- Distance Strategy ---
        let rangeStart = 0;
        let rangeEnd = 0;

        if (chain.length === 1) {
            // First Entry (V2): Window [40% .. 80%] of subject length
            rangeStart = minStart16 / 4; 
            rangeEnd = maxStart16 / 4;
        } else {
            // Subsequent Entries: Progressively Closer with limited widening
            const prevEntry = chain[chain.length - 1];
            const prevPrevEntry = chain[chain.length - 2];
            const prevDist = prevEntry.startBeat - prevPrevEntry.startBeat;

            // Base rule: next distance <= previous distance
            let maxDist = prevDist; 

            // Exception: Widen by 1 beat IF previous distance was short (<40% subject) AND no consecutive widening
            const threshold = subjectDurationBeats * 0.4;

            if (prevDist < threshold) {
                let consecutiveWiden = false;
                if (chain.length >= 3) {
                    const pppEntry = chain[chain.length - 3];
                    const prevPrevDist = prevPrevEntry.startBeat - pppEntry.startBeat;
                    if (prevDist > prevPrevDist) {
                        consecutiveWiden = true;
                    }
                }

                if (!consecutiveWiden) {
                    maxDist = prevDist + 1.0; 
                }
            }

            rangeStart = 0.5; // Min 1/8th note spacing
            rangeEnd = maxDist;
        }

        // Convert to Eighth Note steps (0.5 beats) for iteration
        const startStep = Math.floor(rangeStart * 2);
        const endStep = Math.floor(rangeEnd * 2);

        // Iterate DOWNWARDS (High to Low) to favor "distant end" as requested
        for (let s = endStep; s >= startStep; s--) {
            const distBeats = s * 0.5;
            const newStart = lastEntry.startBeat + distBeats;

            // Check: Ensure we don't start after the previous voice has finished?
            // "at least 20% of subject remaining" rule applies to V1->V2. 
            // For general stretto, overlap is key.
            // If V_prev is truncated, ensure we still overlap reasonably. 
            const prevEnd = lastEntry.startBeat + (lastEntry.length / 4);
            if (newStart >= prevEnd) continue; // No overlap

            const candidateTrans: number[] = [];
            validTranspositions.forEach(t => candidateTrans.push(t + lastEntry.transposition)); 

            for (const absTrans of candidateTrans) {
                // Interval Constraints
                const relToPrev = absTrans - lastEntry.transposition;
                const is3rd = THIRD_SIXTH_TRANS.has(relToPrev);
                if (is3rd && !isBudgetAvailable(options.thirdSixthMode, n3rd)) continue;

                // Type Options
                const types: {type: 'N'|'I', len: number, costInv: number, costTrunc: number}[] = [];

                types.push({ type: 'N', len: subjectLen16, costInv: 0, costTrunc: 0 });

                if (isBudgetAvailable(options.inversionMode, nInv)) {
                    types.push({ type: 'I', len: subjectLen16, costInv: 1, costTrunc: 0 });
                }
                // Only allow truncation if enabled
                if (isBudgetAvailable(options.truncationMode, nTrunc)) {
                    // Check if truncated length is valid (must be > 0)
                    if (truncLen16 > 0 && truncLen16 < subjectLen16) {
                        types.push({ type: 'N', len: truncLen16, costInv: 0, costTrunc: 1 });
                        if (isBudgetAvailable(options.inversionMode, nInv)) {
                            types.push({ type: 'I', len: truncLen16, costInv: 1, costTrunc: 1 });
                        }
                    }
                }

                for (const tOpt of types) {
                    const newEntry: StrettoChainOption = {
                        startBeat: newStart,
                        transposition: absTrans,
                        type: tOpt.type,
                        length: tOpt.len,
                        voiceIndex: chain.length
                    };

                    // Optimistic check: only verify strict rules if we haven't failed early
                    const testChain = [...chain, newEntry];
                    const { valid } = checkRules(testChain, baseSubject, invertedSubject);

                    if (valid) {
                        await solve(testChain, nInv + tOpt.costInv, n3rd + (is3rd?1:0), nTrunc + tOpt.costTrunc);
                    }
                    if (results.length >= MAX_RESULTS) return;
                }
            }
            if (results.length >= MAX_RESULTS) return;
        }
    }

    const roots = [0, 12];
    for (const r of roots) {
        await solve([{
            startBeat: 0,
            transposition: r,
            type: 'N',
            length: subjectLen16,
            voiceIndex: 0
        }], 0, 0, 0);
    }

    return results.sort((a,b) => b.score - a.score);
}

import { RawNote, StrettoCandidate, StrettoError, StrettoGrade, HarmonicRegion } from '../../types';
import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel } from './midiSpelling';

const SEMIS_P8 = 12;
const SEMIS_P5 = 7;
const SEMIS_P4 = 5;

// Strict counterpoint intervals
const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7
const PERFECT_CONSONANCES = [0, 7]; // P1, P5 (P8 is 0 mod 12)
const IMPERFECT_CONSONANCES = [3, 4, 8, 9]; // m3, M3, m6, M6

export interface VoiceEvent {
    tick: number;
    pitch1: number; // Subject
    pitch2: number; // Answer (Transposed Subject)
    hasAttack1: boolean;
    hasAttack2: boolean;
}

export function getVerticalIntervals(subject: RawNote[], answer: RawNote[]): VoiceEvent[] {
    const timePoints = new Set<number>();
    [...subject, ...answer].forEach(n => {
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks); // Also check release points
    });

    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);
    const events: VoiceEvent[] = [];

    // Filter points that are just releases of the very last note
    const endOfMusic = Math.max(...[...subject, ...answer].map(n => n.ticks + n.durationTicks));

    sortedPoints.forEach(t => {
        if (t >= endOfMusic) return;

        const n1 = subject.find(n => n.ticks <= t && (n.ticks + n.durationTicks) > t);
        const n2 = answer.find(n => n.ticks <= t && (n.ticks + n.durationTicks) > t);

        if (n1 && n2) {
            events.push({
                tick: t,
                pitch1: n1.midi,
                pitch2: n2.midi,
                hasAttack1: n1.ticks === t,
                hasAttack2: n2.ticks === t
            });
        }
    });

    return events;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; // Downbeat
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function generateHarmonicRegions(events: VoiceEvent[]): HarmonicRegion[] {
    const regions: HarmonicRegion[] = [];
    let previousState: 'consonance' | 'dissonance' = 'consonance';

    // For Motion checking
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    for (let i = 0; i < events.length; i++) {
        const ev = events[i];
        const nextEv = events[i+1];
        const duration = nextEv ? nextEv.tick - ev.tick : 0;

        if (duration <= 0) continue;

        const p1 = ev.pitch1;
        const p2 = ev.pitch2;
        const interval = Math.abs(p1 - p2);
        const intervalClass = interval % 12;
        const isBass1 = p1 < p2;
        const upperPitch = isBass1 ? p2 : p1;
        const prevUpperPitch = isBass1 ? (prevP2) : (prevP1);

        // Determine Interval Type
        const isP4 = intervalClass === 5; // P4 dissonant in 2-part if no bass support (strict: always diss)
        const isDiss = DISSONANT_INTERVALS.includes(intervalClass) || isP4;

        let regionType: HarmonicRegion['type'];

        if (isDiss) {
            if (previousState === 'consonance') {
                regionType = 'dissonance_1'; // Deep Blueish Purple
            } else {
                regionType = 'dissonance_consecutive'; // Reddish Purple
            }
            previousState = 'dissonance';
        } else {
            if (PERFECT_CONSONANCES.includes(intervalClass)) {
                regionType = 'perfect_consonance'; // Turquoise
            } else {
                regionType = 'imperfect_consonance'; // Lime Green
            }
            previousState = 'consonance';
        }

        // Determine Error Overlay (Parallel/Direct)
        let errorType: HarmonicRegion['errorType'] = null;

        if (prevP1 !== null && prevP2 !== null) {
            const isParallelMotion = (p1 - prevP1) * (p2 - prevP2) > 0;
            const isPerfect = intervalClass === 0 || intervalClass === 7;

            // Check Parallel
            if (isPerfect && isParallelMotion) {
                const prevInterval = Math.abs(prevP1 - prevP2);
                const prevClass = prevInterval % 12;
                if (prevClass === intervalClass) {
                    errorType = 'parallel';
                }
            }

            // Check Direct (Hidden) Perfects
            // Definition: Similar motion into a perfect interval, where the upper voice leaps
            if (!errorType && isPerfect && isParallelMotion) {
                // Check leap size of upper voice
                if (prevUpperPitch !== null) {
                    const upperMove = Math.abs(upperPitch - prevUpperPitch);
                    if (upperMove > 2) { // Leap > Major 2nd
                        errorType = 'direct';
                    }
                }
            }
        }

        const name1 = getStrictPitchName(p1);
        const name2 = getStrictPitchName(p2);
        const label = getIntervalLabel(interval);

        regions.push({
            startTick: ev.tick,
            endTick: nextEv ? nextEv.tick : ev.tick + 100, // Fallback for last note
            type: regionType,
            errorType: errorType,
            intervalLabel: label,
            description: `${label}: ${name1}, ${name2}`
        });

        if (ev.hasAttack1 || ev.hasAttack2) {
            prevP1 = p1;
            prevP2 = p2;
        }
    }

    return regions;
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number }
): StrettoCandidate {

    const answer: RawNote[] = subject.map(n => ({
        ...n,
        ticks: n.ticks + delayTicks,
        midi: n.midi + intervalSemis,
        name: getStrictPitchName(n.midi + intervalSemis),
        voiceIndex: 1
    }));

    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(...subject.map(n => n.ticks + n.durationTicks));
    const endOverlap = subjectEnd;

    if (startOverlap >= endOverlap) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [{ tick: 0, timeFormatted: '-', type: 'Consecutive Dissonance', details: 'No overlap', severity: 'fatal' }],
            notes: []
        };
    }

    const events = getVerticalIntervals(subject, answer).filter(e => e.tick >= startOverlap);

    // Generate Visualization Regions
    const harmonicRegions = generateHarmonicRegions(events);

    // Generate Standard Errors (Filtering from regions for text report)
    const errors: StrettoError[] = [];

    harmonicRegions.forEach(r => {
        const timeStr = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(r.startTick, ppq, ts.num, ts.den);

        if (r.errorType === 'parallel') {
            errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Parallel 5th' : 'Parallel 8ve',
                details: `Parallel motion into ${r.intervalLabel}`,
                severity: onStrong ? 'fatal' : 'warning'
            });
        }
        if (r.errorType === 'direct') {
             errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Direct 5th' : 'Direct 8ve',
                details: `Direct motion into ${r.intervalLabel} (Upper leap)`,
                severity: 'warning'
            });
        }
        if (r.type === 'dissonance_consecutive' && onStrong) {
             errors.push({
                 tick: r.startTick, timeFormatted: timeStr,
                 type: 'Consecutive Dissonance',
                 details: 'Consecutive dissonance',
                 severity: 'fatal'
             });
        }
    });

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(Math.abs(intervalSemis));
    if (intervalSemis < 0) intLabel = '-' + intLabel;
    else if (intervalSemis > 0) intLabel = '+' + intLabel;

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: [...subject, ...answer],
        regions: harmonicRegions
    };
}

import React, { useState, useMemo } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; // Import Generator
import { Spinner } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoSearchPanel from './stretto/StrettoSearchPanel'; // Import Search Panel
import StrettoResultsList from './stretto/StrettoResultsList'; // Import Results List

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
}

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('pairwise'); // Toggle View

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        targetVoices: 4, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65 // F4
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        configIntervals.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, ppq, ts, searchRes, viewMode]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSelectedChain(null);

        // Timeout to allow UI render
        setTimeout(async () => {
            try {
                const results = await searchStrettoChains(subjectNotes, searchOptions, ppq);
                setChainResults(results);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        // Flatten all notes and group by voice for analysis
        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];

        const sortedSubj = [...subjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry, idx) => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    // Simple chromatic inversion relative to pivot
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, 
                    midi: pitch,
                    name: "N",
                    voiceIndex: entry.voiceIndex,
                    durationTicks: n.durationTicks 
                };
            });

            // Apply truncation
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            voices.push(clipped);
            allNotes = [...allNotes, ...clipped];
        });

        // Generate Harmonic Regions for Adjacent Voices (Chain Links)
        // V1-V2, V2-V3, etc.
        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const vA = voices[i];
            const vB = voices[i+1];
            // Get raw intervals
            const events = getVerticalIntervals(vA, vB);
            // Get regions
            const regions = generateHarmonicRegions(events);
            // Filter only interesting events (Dissonances or Perfects) to avoid clutter?
            // Or just keep all. The PianoRoll handles overlapping visually by simple z-order.
            chainRegions = [...chainRegions, ...regions];
        }

        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], 
            notes: allNotes,
            regions: chainRegions 
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.map(n => ({
            name: n.name, // Name might need regeneration if not strict
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6">
                    <div className="flex justify-between items-center mb-2">
                        <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                        <span className="text-[10px] text-gray-500 font-mono">Supports M: (Meter), L: (Length), Q: (Tempo), K: (Key)</span>
                    </div>
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="M:4/4\nL:1/4\nK:C\nc2 G c d e f g"
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            selectedId={selectedCandidate?.id || null}
                            onSelect={setSelectedCandidate}
                            checkedIds={checkedIds}
                            onToggleCheck={toggleCheck}
                        />

                        <StrettoInspector 
                            candidate={selectedCandidate}
                            ppq={ppq}
                            ts={ts}
                            isPlaying={isPlaying}
                            onPlay={handlePlay}
                            assemblyResult={assemblyResult}
                            assemblyLog={assemblyLog}
                            onClearAssembly={() => setAssemblyResult('')}
                            onDownloadChain={() => {}} // Not implemented for single pair yet
                        />
                    </div>

                    <StrettoFooter 
                        selectedCandidates={getSelectedCandidates()}
                        onDownloadMidi={() => {}}
                        onAssemble={triggerAssembly}
                        isAssembling={isAssembling}
                        onRemoveCandidate={toggleCheck}
                    />
                </>
            ) : (
                <>
                    <StrettoSearchPanel 
                        options={searchOptions} 
                        setOptions={setSearchOptions}
                        onSearch={handleChainSearch}
                        isSearching={isSearching}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                        <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                            <h3 className="p-3 text-xs font-bold text-gray-400 border-b border-gray-700 bg-gray-800">FOUND CHAINS ({chainResults.length})</h3>
                            <StrettoResultsList 
                                results={chainResults}
                                selectedId={selectedChain?.id || null}
                                onSelect={setSelectedChain}
                            />
                        </div>
                        <div className="lg:col-span-2">
                            <StrettoInspector 
                                candidate={chainToCandidate}
                                ppq={ppq}
                                ts={ts}
                                isPlaying={isPlaying}
                                onPlay={handlePlay}
                                assemblyResult={""}
                                assemblyLog={[]}
                                onClearAssembly={() => {}}
                                onDownloadChain={() => {
                                    // TODO: Implement Download for Chain
                                    alert("Download Chain not yet linked.");
                                }}
                            />
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

