                {/* 4. Intervals (Col 3) */}
                <div className="lg:col-span-3">
                    {renderConstraintSelector("Intervals (from Prev)", "thirdSixthMode", options.thirdSixthMode)}
                    <div className="mt-2 flex items-center px-1">
                        <label className="flex items-center cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={options.requireConsonantEnd} 
                                onChange={(e) => handleChange('requireConsonantEnd', e.target.checked)} 
                                className="h-3 w-3 rounded bg-gray-900 border-gray-600 text-brand-primary focus:ring-0"
                            />
                            <span className="ml-2 text-[10px] font-bold text-gray-300">Require Consonant End</span>
                        </label>
                    </div>
                </div>
            </div>

            <button 
                onClick={onSearch}
                disabled={isSearching}
                className="w-full py-2 bg-brand-primary hover:bg-brand-secondary text-white font-bold rounded shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed text-sm uppercase tracking-wide"
            >
                {isSearching ? 'Processing Combinations...' : 'Run Search Algorithm'}
            </button>
        </div>
    );
}

import { RawNote, StrettoCandidate, StrettoError, StrettoGrade, HarmonicRegion } from '../../types';
import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel } from './midiSpelling';

const SEMIS_P8 = 12;
const SEMIS_P5 = 7;
const SEMIS_P4 = 5;

// Strict counterpoint intervals
const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7
const PERFECT_CONSONANCES = [0, 7]; // P1, P5 (P8 is 0 mod 12)
const IMPERFECT_CONSONANCES = [3, 4, 8, 9]; // m3, M3, m6, M6

export interface VoiceEvent {
    tick: number;
    endTick: number; // New field for exact duration tracking
    pitch1: number; // Subject
    pitch2: number; // Answer (Transposed Subject)
    hasAttack1: boolean;
    hasAttack2: boolean;
}

export function getVerticalIntervals(subject: RawNote[], answer: RawNote[]): VoiceEvent[] {
    const timePoints = new Set<number>();
    [...subject, ...answer].forEach(n => {
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks); // Also check release points
    });

    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);
    const events: VoiceEvent[] = [];

    // Filter points that are just releases of the very last note
    const endOfMusic = Math.max(...[...subject, ...answer].map(n => n.ticks + n.durationTicks));

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const t = sortedPoints[i];
        if (t >= endOfMusic) break;

        // Check active notes at this time segment (t to nextPoint)
        // We use t + epsilon to check inside the window
        const checkTime = t; 

        const n1 = subject.find(n => n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);
        const n2 = answer.find(n => n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);

        if (n1 && n2) {
            events.push({
                tick: t,
                endTick: sortedPoints[i+1], // The state is valid until the next timeline event
                pitch1: n1.midi,
                pitch2: n2.midi,
                hasAttack1: n1.ticks === t,
                hasAttack2: n2.ticks === t
            });
        }
    }

    return events;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; // Downbeat
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function generateHarmonicRegions(events: VoiceEvent[]): HarmonicRegion[] {
    const regions: HarmonicRegion[] = [];
    let previousState: 'consonance' | 'dissonance' = 'consonance';

    // For Motion checking
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    for (let i = 0; i < events.length; i++) {
        const ev = events[i];
        const duration = ev.endTick - ev.tick;

        if (duration <= 0) continue;

        const p1 = ev.pitch1;
        const p2 = ev.pitch2;
        const interval = Math.abs(p1 - p2);
        const intervalClass = interval % 12;
        const isBass1 = p1 < p2;
        const upperPitch = isBass1 ? p2 : p1;
        const prevUpperPitch = isBass1 ? (prevP2) : (prevP1);

        // Determine Interval Type
        const isP4 = intervalClass === 5; // P4 dissonant in 2-part if no bass support (strict: always diss)
        const isDiss = DISSONANT_INTERVALS.includes(intervalClass) || isP4;

        let regionType: HarmonicRegion['type'];

        if (isDiss) {
            if (previousState === 'consonance') {
                regionType = 'dissonance_1'; // Deep Blueish Purple
            } else {
                regionType = 'dissonance_consecutive'; // Reddish Purple
            }
            previousState = 'dissonance';
        } else {
            if (PERFECT_CONSONANCES.includes(intervalClass)) {
                regionType = 'perfect_consonance'; // Turquoise
            } else {
                regionType = 'imperfect_consonance'; // Lime Green
            }
            previousState = 'consonance';
        }

        // Determine Error Overlay (Parallel/Direct)
        let errorType: HarmonicRegion['errorType'] = null;

        if (prevP1 !== null && prevP2 !== null) {
            const isParallelMotion = (p1 - prevP1) * (p2 - prevP2) > 0;
            const isPerfect = intervalClass === 0 || intervalClass === 7;

            // Check Parallel
            if (isPerfect && isParallelMotion) {
                const prevInterval = Math.abs(prevP1 - prevP2);
                const prevClass = prevInterval % 12;
                if (prevClass === intervalClass) {
                    errorType = 'parallel';
                }
            }

            // Check Direct (Hidden) Perfects
            // Definition: Similar motion into a perfect interval, where the upper voice leaps
            if (!errorType && isPerfect && isParallelMotion) {
                // Check leap size of upper voice
                if (prevUpperPitch !== null) {
                    const upperMove = Math.abs(upperPitch - prevUpperPitch);
                    if (upperMove > 2) { // Leap > Major 2nd
                        errorType = 'direct';
                    }
                }
            }
        }

        const name1 = getStrictPitchName(p1);
        const name2 = getStrictPitchName(p2);
        const label = getIntervalLabel(interval);

        regions.push({
            startTick: ev.tick,
            endTick: ev.endTick, 
            type: regionType,
            errorType: errorType,
            intervalLabel: label,
            description: `${label}: ${name1}, ${name2}`
        });

        if (ev.hasAttack1 || ev.hasAttack2) {
            prevP1 = p1;
            prevP2 = p2;
        }
    }

    return regions;
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number }
): StrettoCandidate {

    const answer: RawNote[] = subject.map(n => ({
        ...n,
        ticks: n.ticks + delayTicks,
        midi: n.midi + intervalSemis,
        name: getStrictPitchName(n.midi + intervalSemis),
        voiceIndex: 1
    }));

    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(...subject.map(n => n.ticks + n.durationTicks));
    const endOverlap = subjectEnd;

    if (startOverlap >= endOverlap) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [{ tick: 0, timeFormatted: '-', type: 'Consecutive Dissonance', details: 'No overlap', severity: 'fatal' }],
            notes: []
        };
    }

    const events = getVerticalIntervals(subject, answer).filter(e => e.tick >= startOverlap);

    // Generate Visualization Regions
    const harmonicRegions = generateHarmonicRegions(events);

    // Generate Standard Errors (Filtering from regions for text report)
    const errors: StrettoError[] = [];

    harmonicRegions.forEach(r => {
        const timeStr = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(r.startTick, ppq, ts.num, ts.den);

        if (r.errorType === 'parallel') {
            errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Parallel 5th' : 'Parallel 8ve',
                details: `Parallel motion into ${r.intervalLabel}`,
                severity: onStrong ? 'fatal' : 'warning'
            });
        }
        if (r.errorType === 'direct') {
             errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Direct 5th' : 'Direct 8ve',
                details: `Direct motion into ${r.intervalLabel} (Upper leap)`,
                severity: 'warning'
            });
        }
        if (r.type === 'dissonance_consecutive' && onStrong) {
             errors.push({
                 tick: r.startTick, timeFormatted: timeStr,
                 type: 'Consecutive Dissonance',
                 details: 'Consecutive dissonance',
                 severity: 'fatal'
             });
        }
    });

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(Math.abs(intervalSemis));
    if (intervalSemis < 0) intLabel = '-' + intLabel;
    else if (intervalSemis > 0) intLabel = '+' + intLabel;

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: [...subject, ...answer],
        regions: harmonicRegions
    };
}

import React, { useState, useMemo, useEffect } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; // Import Generator
import { getStrictPitchName } from './services/midiSpelling'; // Import for naming
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoSearchPanel from './stretto/StrettoSearchPanel'; // Import Search Panel
import StrettoResultsList from './stretto/StrettoResultsList'; // Import Results List

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('pairwise'); // Toggle View

    // -- Library State --
    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        targetVoices: 4, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, // F4
        requireConsonantEnd: true // Default ON
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Load Library on Mount
    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try {
                setSavedSubjects(JSON.parse(saved));
            } catch (e) {
                console.error("Failed to load library", e);
            }
        }
    }, []);

    // Save Library Logic
    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = {
            id: Date.now().toString(),
            name: saveName.trim(),
            data: abcInput
        };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => {
        setAbcInput(data);
    };

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        configIntervals.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, ppq, ts, searchRes, viewMode]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSelectedChain(null);

        // Timeout to allow UI render
        setTimeout(async () => {
            try {
                const results = await searchStrettoChains(subjectNotes, searchOptions, ppq);
                setChainResults(results);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        // Flatten all notes and group by voice for analysis
        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];

        const sortedSubj = [...subjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry, idx) => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    // Simple chromatic inversion relative to pivot
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, 
                    midi: pitch,
                    name: getStrictPitchName(pitch), // CRITICAL FIX: Ensure valid note name for playback
                    voiceIndex: entry.voiceIndex,
                    durationTicks: n.durationTicks 
                };
            });

            // Apply truncation
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            voices.push(clipped);
            allNotes = [...allNotes, ...clipped];
        });

        // Generate Harmonic Regions for Adjacent Voices (Chain Links)
        // V1-V2, V2-V3, etc.
        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const vA = voices[i];
            const vB = voices[i+1];
            // Get raw intervals
            const events = getVerticalIntervals(vA, vB);
            // Get regions
            const regions = generateHarmonicRegions(events);
            // Filter only interesting events (Dissonances or Perfects) to avoid clutter?
            // Or just keep all. The PianoRoll handles overlapping visually by simple z-order.
            chainRegions = [...chainRegions, ...regions];
        }

        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], 
            notes: allNotes,
            regions: chainRegions 
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.map(n => ({
            name: n.name, // Name might need regeneration if not strict
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                            <span className="text-[10px] text-gray-500 font-mono hidden sm:inline">Supports M: (Meter), L: (Length), Q: (Tempo), K: (Key)</span>
                        </div>
                        <button 
                            onClick={() => setShowLibrary(!showLibrary)}
