import React from 'react';
import { AppState } from './types';
import { useMidiController } from './hooks/useMidiController';
import Header from './components/Header';
import FileUpload from './components/FileUpload';
import TrackList from './components/TrackList';
import Modal from './components/Modal';
import PianoRoll from './components/PianoRoll';
import TrackAnalysis from './components/TrackAnalysis';
import Notification from './components/Notification';
import ConversionSettings from './components/ConversionSettings';
import AnalysisSettings from './components/AnalysisSettings'; 
import ActionPanel from './components/ActionPanel';
import StrettoView from './components/StrettoView'; // Import Stretto View
import { DownloadIcon } from './components/Icons';

export default function App() {
  const { state, settings, setters, actions } = useMidiController();
  const { 
    appState, errorMessage, successMessage, fileName, trackInfo, selectedTracks, 
    playingTrackId, eventCounts, quantizationWarning, midiData,
    isPianoRollVisible, pianoRollTrackData, generatedScore, auditLog, isLoadedState,
    analyzedTrackData, isAnalysisModalOpen
  } = state;

  const [currentView, setCurrentView] = useState<'analysis' | 'stretto'>('analysis');

  // Helper to get notes for Stretto View (using first selected track or empty)
  const getStrettoNotes = () => {
      if (!midiData) return [];
      // Prefer selected track
      if (selectedTracks.size > 0) {
          const id = Array.from(selectedTracks)[0];
          return midiData.tracks[id]?.notes.map(n => ({...n} as any)) || [];
      }
      // Fallback to first track with notes
      const t = midiData.tracks.find(t => t.notes.length > 0);
      return t ? t.notes.map(n => ({...n} as any)) : [];
  };

  const ppq = midiData?.header.ppq || 480;
  const ts = midiData?.header.timeSignatures[0]?.timeSignature || [4, 4];

  // Logic to determine what to render in the main area
  const renderMainContent = () => {
      if (currentView === 'stretto') {
          return (
              <StrettoView 
                  notes={getStrettoNotes()} 
                  ppq={ppq} 
                  ts={{ num: ts[0], den: ts[1] }} 
                  voiceNames={settings.voiceNames}
              />
          );
      }

      // Analysis View Logic
      if (!isLoadedState) {
          return (
              <div className="w-full max-w-lg text-center">
                  <FileUpload onFileUpload={actions.handleFileUpload} isLoading={appState === AppState.LOADING} />
                  {appState === AppState.ERROR && (
                      <div className="mt-4 p-4 bg-red-900/50 border border-red-700 text-red-300 rounded-lg animate-fade-in">
                          <p className="font-bold">An Error Occurred</p>
                          <p>{errorMessage}</p>
                      </div>
                  )}
              </div>
          );
      }

      return (
          <>
              <TrackList
                tracks={trackInfo}
                selectedTracks={selectedTracks}
                onTrackSelect={actions.handleTrackSelect}
                onSelectAll={actions.handleSelectAllTracks}
                onReset={actions.handleReset}
                fileName={fileName}
                playingTrackId={playingTrackId}
                onPreviewTrack={actions.handlePreviewTrack}
                onShowPianoRoll={actions.handleShowPianoRoll}
                onAnalyzeTrack={actions.handleAnalyzeTrack}
              />

              {/* Data Preparation Settings */}
              <ConversionSettings 
                settings={settings}
                setters={setters}
                eventCounts={eventCounts}
                onEventFilterToggle={actions.handleEventFilterToggle}
                quantizationWarning={quantizationWarning}
              />

              {/* Analysis Context & Range */}
              <AnalysisSettings 
                sections={settings.analysisSections}
                setSections={setters.setAnalysisSections}
                contextText={settings.contextText}
                setContextText={setters.setContextText}
                voiceNames={settings.voiceNames}
                setVoiceNames={setters.setVoiceNames}
                voiceCountEstimate={settings.maxVoices || 4}
                midiData={midiData}
                trackInfo={trackInfo}
                selectedTracks={selectedTracks}
                voiceAssignmentMode={settings.voiceAssignmentMode}
              />

              {(successMessage || errorMessage) && (
                  <div className="my-4">
                    <Notification 
                        message={successMessage || errorMessage || ''} 
                        type={successMessage ? 'success' : 'error'} 
                        onDismiss={actions.clearMessages} 
                    />
                  </div>
              )}

              <ActionPanel 
                 onGenerateScore={actions.handleGenerateScore}
                 onDownloadScore={actions.handleDownloadScore}
                 onDownloadAudit={actions.handleDownloadAuditLog}
                 isGenerating={appState === AppState.GENERATING}
                 canProcess={selectedTracks.size >= 1}
                 selectedCount={selectedTracks.size}
                 hasResult={!!generatedScore}
                 hasAudit={!!auditLog}
              />

              {/* Score Output */}
              {generatedScore && (
                  <div className="w-full bg-gray-dark p-6 rounded-2xl shadow-2xl border border-gray-medium mt-6 animate-slide-up">
                      <div className="flex justify-between items-center mb-4">
                          <h3 className="text-xl font-bold text-gray-light">Generated Analysis & Score</h3>
                          <div className="flex gap-2">
                              <button 
                                onClick={actions.handleDownloadScore}
                                className="flex items-center gap-2 text-sm bg-gray-700 hover:bg-gray-600 text-white px-3 py-1 rounded transition-colors"
                              >
                                  <DownloadIcon className="w-4 h-4" /> Download
                              </button>
                              <button 
                                onClick={() => navigator.clipboard.writeText(generatedScore)}
                                className="text-sm bg-brand-primary hover:bg-brand-secondary text-white px-3 py-1 rounded transition-colors"
                              >
                                  Copy to Clipboard
                              </button>
                          </div>
                      </div>
                      <textarea 
                        readOnly 
                        value={generatedScore} 
                        className="w-full h-96 bg-black border border-gray-700 text-gray-300 font-mono text-xs p-4 rounded-lg focus:outline-none"
                      />
                  </div>
              )}

              {/* Separate Audit Log Panel */}
              {auditLog && (
                  <div className="w-full bg-gray-900/80 p-6 rounded-2xl shadow-2xl border-2 border-amber-600/50 mt-6 animate-slide-up">
                      <div className="flex justify-between items-center mb-4">
                          <div className="flex flex-col">
                              <h3 className="text-xl font-bold text-amber-500">HIA v2.2 Deep Audit Log</h3>
                              <p className="text-xs text-gray-400">Technical decision trace for Harmonic Implication Algorithm.</p>
                          </div>
                          <div className="flex gap-2">
                              <button 
                                onClick={actions.handleDownloadAuditLog}
                                className="flex items-center gap-2 text-sm bg-amber-800 hover:bg-amber-700 text-white px-3 py-1 rounded transition-colors"
                              >
                                  <DownloadIcon className="w-4 h-4" /> Download Audit
                              </button>
                              <button 
                                onClick={() => navigator.clipboard.writeText(auditLog)}
                                className="text-sm bg-gray-700 hover:bg-gray-600 text-white px-3 py-1 rounded transition-colors"
                              >
                                  Copy Log
                              </button>
                          </div>
                      </div>
                      <textarea 
                        readOnly 
                        value={auditLog} 
                        className="w-full h-64 bg-black border border-amber-900/50 text-amber-200/80 font-mono text-xs p-4 rounded-lg focus:outline-none"
                      />
                  </div>
              )}
          </>
      );
  };

  return (
    <>
      <div className="min-h-screen bg-gray-darker flex flex-col items-center p-4 sm:p-6 lg:p-8 font-sans">
        <Header currentView={currentView} onViewChange={setCurrentView} />

        <main className="w-full max-w-4xl mx-auto flex-grow flex flex-col items-center justify-center">
            <div className="w-full animate-fade-in pb-12">
                {renderMainContent()}
            </div>
        </main>
        <footer className="w-full max-w-4xl mx-auto text-center py-4 mt-8 border-t border-gray-medium text-gray-medium">
          <p>Built with React, Tailwind CSS, and @tonejs/midi</p>
        </footer>
      </div>

      {isPianoRollVisible && pianoRollTrackData && (
        <Modal
          isOpen={isPianoRollVisible}
          onClose={() => setters.setIsPianoRollVisible(false)}
          title={`Piano Roll: ${pianoRollTrackData.name}`}
        >
          <PianoRoll trackData={pianoRollTrackData} />
        </Modal>
      )}

      {isAnalysisModalOpen && analyzedTrackData && (
        <Modal
          isOpen={isAnalysisModalOpen}
          onClose={() => setters.setIsAnalysisModalOpen(false)}
          title={`Track Analysis: ${analyzedTrackData.trackName}`}
        >
          <TrackAnalysis data={analyzedTrackData} />
        </Modal>
      )}
    </>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { Midi } from '@tonejs/midi';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; // Import Generator
import { getStrictPitchName } from './services/midiSpelling'; // Import for naming
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoSearchPanel from './stretto/StrettoSearchPanel'; // Import Search Panel
import StrettoResultsList from './stretto/StrettoResultsList'; // Import Results List

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>('midi');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('pairwise'); // Toggle View

    // -- Library State --
    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, // Tenor (0=S, 1=A, 2=T, 3=B)
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, // F4
        requireConsonantEnd: true
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Load Library on Mount
    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try {
                setSavedSubjects(JSON.parse(saved));
            } catch (e) {
                console.error("Failed to load library", e);
            }
        }
    }, []);

    // Save Library Logic
    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = {
            id: Date.now().toString(),
            name: saveName.trim(),
            data: abcInput
        };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => {
        setAbcInput(data);
    };

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        configIntervals.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts));
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, ppq, ts, searchRes, viewMode]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSelectedChain(null);

        // Timeout to allow UI render
        setTimeout(async () => {
            try {
                const results = await searchStrettoChains(subjectNotes, searchOptions, ppq);
                setChainResults(results);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        // Flatten all notes and group by voice for analysis
        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];

        const sortedSubj = [...subjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry, idx) => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    // Simple chromatic inversion relative to pivot
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, 
                    midi: pitch,
                    name: getStrictPitchName(pitch), // CRITICAL FIX: Ensure valid note name for playback
                    voiceIndex: entry.voiceIndex,
                    durationTicks: n.durationTicks 
                };
            });

            // Apply truncation
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            voices.push(clipped);
            allNotes = [...allNotes, ...clipped];
        });

        // Generate Harmonic Regions for Adjacent Voices (Chain Links)
        // Note: For multi-voice, we can check adjacent indices (e.g. 0-1, 1-2, 2-3) if sorted by voice index
        // But entries are time-sorted. Let's just do standard pairwise on flattened notes
        // Actually, PianoRoll expects harmonic regions.
        // We'll just generate them for all overlapping notes to show conflicts.
        // For clearer visualization, maybe just Voice 0 vs Voice 1 of each pairwise link in chain?
        // Let's stick to full dissonance scan.

        let chainRegions: HarmonicRegion[] = [];
        // Flattened pairwise check is too expensive for many notes.
        // Let's just check the "Chain Links" (Entry i vs Entry i+1) as that's the stretto logic
        for (let i = 0; i < voices.length - 1; i++) {
            const vA = voices[i];
            const vB = voices[i+1];
            const events = getVerticalIntervals(vA, vB);
            const regions = generateHarmonicRegions(events);
            chainRegions = [...chainRegions, ...regions];
        }

        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], 
            notes: allNotes,
            regions: chainRegions 
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.map(n => ({
            name: n.name, // Name might need regeneration if not strict
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                            <span className="text-[10px] text-gray-500 font-mono hidden sm:inline">Supports M: (Meter), L: (Length), Q: (Tempo), K: (Key)</span>
                        </div>
                        <button 
                            onClick={() => setShowLibrary(!showLibrary)}
                            className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors"
                        >
                            <DocumentTextIcon className="w-3 h-3" />
                            {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>

                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input 
                                    type="text" 
                                    placeholder="Subject Name..." 
                                    value={saveName}
                                    onChange={(e) => setSaveName(e.target.value)}
                                    className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white focus:border-brand-primary outline-none"
                                />
                                <button 
                                    onClick={handleSaveSubject}
                                    disabled={!saveName.trim()}
                                    className="bg-brand-primary hover:bg-brand-secondary disabled:bg-gray-600 text-white px-4 py-1 rounded text-sm font-bold transition-colors"
                                >
                                    Save
                                </button>
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length === 0 ? (
                                    <p className="text-xs text-gray-500 col-span-full text-center py-2">No saved subjects yet.</p>
                                ) : (
                                    savedSubjects.map(s => (
                                        <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
                                            <span className="text-sm font-bold text-gray-300 truncate mr-2" title={s.name}>{s.name}</span>
                                            <div className="flex gap-1 opacity-50 group-hover:opacity-100 transition-opacity">
                                                <button 
                                                    onClick={() => handleLoadSubject(s.data)}
                                                    className="text-[10px] bg-brand-secondary/50 hover:bg-brand-secondary text-white px-2 py-0.5 rounded"
                                                >
                                                    Load
                                                </button>
                                                <button 
                                                    onClick={() => handleDeleteSubject(s.id)}
                                                    className="text-[10px] bg-red-900/50 hover:bg-red-700 text-red-200 px-2 py-0.5 rounded"
                                                >
                                                    ×
                                                </button>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}

                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="M:4/4\nL:1/4\nK:C\nc2 G c d e f g"
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            selectedId={selectedCandidate?.id || null}
                            onSelect={setSelectedCandidate}
                            checkedIds={checkedIds}
                            onToggleCheck={toggleCheck}
                        />

                        <StrettoInspector 
                            candidate={selectedCandidate}
                            ppq={ppq}
                            ts={ts}
                            isPlaying={isPlaying}
                            onPlay={handlePlay}
                            assemblyResult={assemblyResult}
                            assemblyLog={assemblyLog}
                            onClearAssembly={() => setAssemblyResult('')}
                            onDownloadChain={() => {}} // Not implemented for single pair yet
                        />
                    </div>

                    <StrettoFooter 
                        selectedCandidates={getSelectedCandidates()}
                        onDownloadMidi={() => {}}
                        onAssemble={triggerAssembly}
                        isAssembling={isAssembling}
                        onRemoveCandidate={toggleCheck}
                    />
                </>
            ) : (
                <>
                    <StrettoSearchPanel 
                        options={searchOptions} 
                        setOptions={setSearchOptions}
                        onSearch={handleChainSearch}
                        isSearching={isSearching}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                        <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                            <h3 className="p-3 text-xs font-bold text-gray-400 border-b border-gray-700 bg-gray-800">FOUND CHAINS ({chainResults.length})</h3>
                            <StrettoResultsList 
                                results={chainResults}
                                selectedId={selectedChain?.id || null}
                                onSelect={setSelectedChain}
                                voiceNames={voiceNames}
                            />
                        </div>
                        <div className="lg:col-span-2">
                            <StrettoInspector 
                                candidate={chainToCandidate}
                                ppq={ppq}
                                ts={ts}
                                isPlaying={isPlaying}
                                onPlay={handlePlay}
                                assemblyResult={""}
                                assemblyLog={[]}
                                onClearAssembly={() => {}}
                                onDownloadChain={() => {
                                    // TODO: Implement Download for Chain
                                    alert("Download Chain not yet linked.");
                                }}
                            />
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

import React, { useState } from 'react';
import { StrettoChainResult, StrettoChainOption, ScoreLog } from '../../types';
import { getIntervalLabel } from '../services/midiSpelling';

interface StrettoResultsListProps {
    results: StrettoChainResult[];
    selectedId: string | null;
    onSelect: (res: StrettoChainResult) => void;
    voiceNames?: Record<number, string>;
}

export default function StrettoResultsList({ results, selectedId, onSelect, voiceNames }: StrettoResultsListProps) {
    const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());
    const [scoreTooltipId, setScoreTooltipId] = useState<string | null>(null);

    if (results.length === 0) {
        return <div className="text-center text-gray-500 py-10">No chains found yet. Run the search to begin.</div>;
    }

    const toggleExpand = (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setExpandedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const formatInterval = (semis: number) => {
        const label = getIntervalLabel(Math.abs(semis));
        const sign = semis > 0 ? '+' : semis < 0 ? '-' : '';
        return `${sign}${label}`;
    };

    const getVoiceCode = (idx: number) => {
        if (voiceNames && voiceNames[idx]) return voiceNames[idx];
        const map = ['S', 'A', 'T', 'B'];
        return map[idx] || `V${idx+1}`;
    };

    const renderScoreTooltip = (log?: ScoreLog) => {
        if (!log) return null;
        return (
            <div className="absolute right-0 top-full mt-2 z-50 w-64 bg-black border border-gray-600 rounded p-3 shadow-xl text-xs text-gray-300">
                <div className="font-bold text-gray-200 border-b border-gray-600 pb-1 mb-2">Score Breakdown ({log.total.toFixed(0)})</div>
                <div className="flex justify-between mb-1"><span>Base</span><span>{log.base}</span></div>
                {log.bonuses.map((b, i) => (
                    <div key={`b-${i}`} className="flex justify-between text-green-400"><span>+ {b.reason}</span><span>{b.points}</span></div>
                ))}
                {log.penalties.map((p, i) => (
                    <div key={`p-${i}`} className="flex justify-between text-red-400"><span>- {p.reason}</span><span>{p.points}</span></div>
                ))}
            </div>
        );
    };

    const renderChainBadges = (entries: StrettoChainOption[], isSub: boolean = false) => {
        return entries.map((e, idx) => {
            const vCode = getVoiceCode(e.voiceIndex);

            if (idx === 0) {
                return (
                    <div key={idx} className={`flex flex-col items-center bg-gray-800 p-1 rounded border border-gray-700 ${isSub ? 'min-w-[40px] scale-90 origin-left' : 'min-w-[50px]'}`}>
                        <span className="text-[10px] font-bold text-brand-primary truncate max-w-[50px]" title={vCode}>{vCode}</span>
                        <span className="text-xs text-white font-mono">Subj</span>
                    </div>
                );
            }

            const absInt = e.transposition; // Absolute from Subject

            const prev = entries[idx-1];
            const relDist = e.startBeat - prev.startBeat;
            const absDist = e.startBeat;

            let typeLabel = e.type === 'I' ? 'INV' : 'NOR';
            let lenLabel = e.length < entries[0].length ? 'TRC' : 'FUL';

            const borderClass = (e.type === 'I' || lenLabel === 'TRC') ? 'border-brand-primary' : 'border-gray-600';

            return (
                <div key={idx} className={`flex flex-col bg-gray-800 p-1 rounded border ${borderClass} ${isSub ? 'min-w-[50px] scale-90 origin-left' : 'min-w-[60px]'}`}>
                    <div className="flex justify-between border-b border-gray-700 pb-0.5 mb-0.5">
                        <span className="text-[9px] font-bold text-gray-300 truncate max-w-[40px]" title={vCode}>{vCode}</span>
                        <span className={`text-[8px] font-bold ${lenLabel === 'TRC' ? 'text-orange-300' : 'text-gray-500'}`}>{lenLabel}</span>
                    </div>

                    <div className="flex flex-col items-center mb-0.5">
                        <span className="text-[10px] text-brand-primary font-bold">{formatInterval(absInt)}</span>
                        {e.type === 'I' && <span className="text-[8px] text-blue-300">INVERT</span>}
                    </div>

                    <div className="flex gap-1 text-[9px] font-mono" title={`Delay: +${relDist} / Start: @${absDist}`}>
                        <span className="text-gray-400 w-1/2 text-center border-r border-gray-700">+{relDist.toFixed(1)}</span>
                        <span className="text-white w-1/2 text-center">@{absDist.toFixed(1)}</span>
                    </div>
                </div>
            );
        });
    };

    return (
        <div className="overflow-y-auto max-h-[500px] pb-20">
            {results.map((res, i) => {
                const hasVariations = res.variations && res.variations.length > 0;
                const isExpanded = expandedIds.has(res.id);
                const isSelected = selectedId === res.id;
                const showTooltip = scoreTooltipId === res.id;

                return (
                    <div key={res.id} className="border-b border-gray-700 bg-gray-900/50 relative">
                        {/* Leader Row */}
                        <div 
                            onClick={() => onSelect(res)}
                            className={`p-2 cursor-pointer hover:bg-gray-800 transition-colors flex flex-col gap-2 ${isSelected ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}
                        >
                            <div className="flex justify-between items-center">
                                <div className="flex items-center gap-2">
                                    {hasVariations && (
                                        <button 
                                            onClick={(e) => toggleExpand(e, res.id)}
                                            className="text-gray-400 hover:text-white text-xs bg-gray-700 px-1.5 rounded"
                                        >
                                            {isExpanded ? '▼' : '▶'}
                                        </button>
                                    )}
                                    <span className="font-bold text-gray-300 text-xs">Chain #{i + 1}</span>
                                    {hasVariations && (
                                        <span className="text-[10px] bg-brand-primary/20 text-brand-primary px-1.5 rounded">
                                            +{res.variations?.length} Vars
                                        </span>
                                    )}
                                </div>
                                <div className="relative">
                                    <button 
                                        onMouseEnter={() => setScoreTooltipId(res.id)}
                                        onMouseLeave={() => setScoreTooltipId(null)}
                                        className="text-[9px] bg-black/30 px-1.5 rounded text-gray-500 hover:text-white cursor-help"
                                    >
                                        Score: {res.score.toFixed(0)}
                                    </button>
                                    {showTooltip && renderScoreTooltip(res.scoreLog)}
                                </div>
                            </div>

                            <div className="flex flex-wrap gap-2">
                                {renderChainBadges(res.entries)}
                            </div>
                        </div>

                        {/* Variations Sub-list */}
                        {hasVariations && isExpanded && (
                            <div className="bg-black/30 border-t border-gray-800 pl-4 py-1">
                                {res.variations!.map((v, vIdx) => {
                                    const isVarSelected = selectedId === v.id;
                                    return (
                                        <div 
                                            key={v.id} 
                                            onClick={() => onSelect(v)}
                                            className={`p-2 border-l border-gray-700 hover:bg-gray-800/50 cursor-pointer transition-colors ${isVarSelected ? 'bg-gray-800/80 border-l-2 border-l-brand-secondary' : ''}`}
                                        >
                                            <div className="flex justify-between items-center mb-1">
                                                <span className="text-[10px] font-bold text-gray-500">Variation {vIdx + 1}</span>
                                                <span className="text-[9px] text-gray-600">Score: {v.score.toFixed(0)}</span>
                                            </div>
                                            <div className="flex flex-wrap gap-1 opacity-90">
                                                {renderChainBadges(v.entries, true)}
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, ScoreLog } from '../../types';
import { getQuantizationTickValue } from './midiTransform';

// Constants
const DISSONANT_SIMPLE = new Set([1, 2, 6, 10, 11]); // m2, M2, TT, m7, M7
// 0(P1), 3(m3), 4(M3), 5(P4 - sometimes), 7(P5), 8(m6), 9(M6), 12(P8)
const CONSONANT_SET = new Set([0, 3, 4, 7, 8, 9, 12]);

// Transposition Sets
const TRAD_TRANS = new Set([0, 12, -12, 24, -24, 7, 19, -5, -17, 5, 17, -7, -19]);
const THIRD_SIXTH_TRANS = new Set([3, 4, 8, 9, -3, -4, -8, -9, 15, 16, 20, 21, -15, -16, -20, -21]);

// --- Helper Functions ---

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; // P4 against bass
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

// Inversion Logic
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

// --- Timeline & Validation ---

interface Timeline {
    [tick16: number]: { [voiceIdx: number]: number }; // tick -> voice -> pitch
}

interface InternalSubjectNote {
    relTick16: number; // 16th note grid relative to start
    dur16: number;
    pitch: number;
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalSubjectNote[] {
    const sorted = [...notes].sort((a,b) => a.ticks - b.ticks);
    if (sorted.length === 0) return [];
    const startTick = sorted[0].ticks;
    const ticksPer16 = ppq / 4;

    return sorted.map(n => ({
        relTick16: Math.round((n.ticks - startTick) / ticksPer16),
        dur16: Math.max(1, Math.round(n.durationTicks / ticksPer16)),
        pitch: n.midi
    }));
}

function getEffectiveSubjectLength16(notes: InternalSubjectNote[]): number {
    if (notes.length === 0) return 0;
    // Calculate the end tick of the last note sounding
    let maxEnd = 0;
    notes.forEach(n => {
        const end = n.relTick16 + n.dur16;
        if (end > maxEnd) maxEnd = end;
    });
    return maxEnd;
}

function getSubjectNotes(
    type: 'N' | 'I', 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    length16: number
): InternalSubjectNote[] {
    const source = type === 'N' ? baseSubject : invertedSubject;
    // Filter by length
    return source.filter(n => n.relTick16 < length16).map(n => ({
        ...n,
        dur16: Math.min(n.dur16, length16 - n.relTick16)
    }));
}

function buildTimeline(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): Timeline {
    const tl: Timeline = {};

    specs.forEach((spec) => {
        const notes = getSubjectNotes(spec.type, baseSubject, invertedSubject, spec.length);
        const start16 = Math.round(spec.startBeat * 4); // beats to 16ths

        notes.forEach(n => {
            for (let t = 0; t < n.dur16; t++) {
                const absTick = start16 + n.relTick16 + t;
                if (!tl[absTick]) tl[absTick] = {};
                // Assign pitch to the specific voice index of the entry
                tl[absTick][spec.voiceIndex] = n.pitch + spec.transposition;
            }
        });
    });

    return tl;
}

interface ValidationResult {
    valid: boolean;
    warnings: string[];
    // Stats for Scoring
    polyphonyIntegral: number; // Sum of (ActiveVoices - 1.5) * Duration
    totalDuration: number;
    polyphonicDuration: number;
    bassDissDuration: number;
    upperDissDuration: number;
}

function checkRulesAndStats(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[],
    requireConsonantEnd: boolean
): ValidationResult {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const warnings: string[] = [];

    // Get unique voice indices used
    const usedVoices = new Set<number>();
    specs.forEach(s => usedVoices.add(s.voiceIndex));
    const voices = Array.from(usedVoices).sort((a,b) => a-b);

    // Stats accumulators
    let polyphonyIntegral = 0;
    let totalDuration = 0;
    let polyphonicDuration = 0;
    let bassDissDuration = 0;
    let upperDissDuration = 0;

    const dummyResult: ValidationResult = { valid: false, warnings: [], polyphonyIntegral: 0, totalDuration: 0, polyphonicDuration: 0, bassDissDuration: 0, upperDissDuration: 0 };

    // Need to iterate continuously to calculate duration integral
    if (ticks.length > 0) {
        const minT = ticks[0];
        const maxT = ticks[ticks.length - 1];
        totalDuration = maxT - minT + 1;

        // Iterate per 16th tick unit
        for (let t = minT; t <= maxT; t++) {
            const activeVoiceMap = tl[t];

            if (!activeVoiceMap) continue; // Silence

            const activeCount = Object.keys(activeVoiceMap).length;

            // Polyphony Score Calculation
            if (activeCount > 0) {
                // Formula: (active - 1.5) per unit
                // If 1 voice: -0.5
                // If 2 voices: 0.5
                // If 4 voices: 2.5
                polyphonyIntegral += (activeCount - 1.5);
            }

            if (activeCount < 2) continue; // Monophonic, no dissonance possible

            polyphonicDuration += 1;

            const pitches = Object.values(activeVoiceMap).sort((a,b) => a-b);
            const bassPitch = pitches[0];
            const bassVoiceIdx = parseInt(Object.keys(activeVoiceMap).find(k => activeVoiceMap[parseInt(k)] === bassPitch) || "-1");

            // Check Intervals pairwise
            const activeIndices = Object.keys(activeVoiceMap).map(Number);

            // Check Dissonance for stats
            for (let i = 0; i < activeIndices.length; i++) {
                for (let j = i + 1; j < activeIndices.length; j++) {
                    const vA = activeIndices[i];
                    const vB = activeIndices[j];
                    const p1 = activeVoiceMap[vA];
                    const p2 = activeVoiceMap[vB];

                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);

                    // Is one of these the bass of the total texture?
                    const isBassPair = (vA === bassVoiceIdx || vB === bassVoiceIdx);

                    if (isDissonant(lo, hi, isBassPair)) {
                        if (isBassPair) bassDissDuration += 1; // 1 unit
                        else upperDissDuration += 1;
                    }
                }
            }
        }
    }

    // --- Validation Checks (Parallel/Runs) ---
    // We can reuse the timeline iteration or the simplified check
    // Re-running the event-based check for rule validation
    for (let i = 0; i < voices.length; i++) {
        for (let j = i + 1; j < voices.length; j++) {
            const vA = voices[i];
            const vB = voices[j];

            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[vA] !== undefined && v[vB] !== undefined) {
                    const minAll = Math.min(...Object.values(v));
                    const lo = Math.min(v[vA], v[vB]);
                    const hi = Math.max(v[vA], v[vB]);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1: v[vA], p2: v[vB] });
                }
            });

            if (sounding.length < 2) continue;

            // RULE 1: Parallel Perfect
            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];

                if (curr.t - prev.t > 1) continue;
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;

                if (isParallelPerfect(prev.lo, prev.hi) && isParallelPerfect(curr.lo, curr.hi)) {
                    const int1 = (prev.hi - prev.lo) % 12;
                    const int2 = (curr.hi - curr.lo) % 12;
                    if (int1 === int2) return dummyResult; // FAIL
                }
            }

            // RULE 2: Dissonance Runs
            let k = 0;
            while (k < sounding.length) {
                const startEv = sounding[k];
                if (!isDissonant(startEv.lo, startEv.hi, startEv.lowerIsBass)) {
                    k++; continue;
                }

                let segStart = k;
                while (k < sounding.length) {
                    const curr = sounding[k];
                    if (!isDissonant(curr.lo, curr.hi, curr.lowerIsBass)) break;

                    if ((curr.t - sounding[segStart].t + 1) >= 4) { // 1 Beat threshold
                        const distinctPitches = new Set<string>();
                        for(let m = segStart; m <= k; m++) distinctPitches.add(`${sounding[m].p1}-${sounding[m].p2}`);
                        if (distinctPitches.size > 1) return dummyResult; // FAIL
                    }
                    k++;
                }
            }
        }
    }

    // --- 3. Check Consonant Termination (New Rule) ---
    if (requireConsonantEnd) {
        for (const spec of specs) {
            const start16 = Math.round(spec.startBeat * 4);
            const end16 = start16 + spec.length; 

            // Check state at end16 - 1 (last sounding 16th)
            const checkTick = end16 - 1;
            const activeVoices = tl[checkTick];

            // If only this voice is active, it ends consonant with silence (valid)
            if (!activeVoices || Object.keys(activeVoices).length < 2) continue;

            const myPitch = activeVoices[spec.voiceIndex];
            if (myPitch === undefined) continue;

            let hasConsonance = false;

            for (const otherVStr in activeVoices) {
                const otherV = parseInt(otherVStr);
                if (otherV === spec.voiceIndex) continue;
                const otherPitch = activeVoices[otherV];
                const interval = Math.abs(myPitch - otherPitch) % 12;
                if (CONSONANT_SET.has(interval)) {
                    hasConsonance = true;
                    break;
                }
            }

            if (!hasConsonance) {
                return dummyResult; // FAIL
            }
        }
    }

    return { 
        valid: true, 
        warnings, 
        polyphonyIntegral, 
        totalDuration, 
        polyphonicDuration,
        bassDissDuration,
        upperDissDuration 
    };
}

// --- Search Algorithm ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoChainResult[]> {

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) return [];

    // Effective Length (excluding trailing rests)
    const effectiveLen16 = getEffectiveSubjectLength16(baseSubject);
    const subjectDurationBeats = effectiveLen16 / 4;

    const truncMusicalTicks = getQuantizationTickValue(options.truncationMusicalValue, ppq);
    const truncLen16 = Math.max(1, Math.round(truncMusicalTicks / (ppq / 4)));

    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        baseSubject.forEach(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi);
            if (inv !== null) invertedSubject.push({ ...n, pitch: inv });
        });
    }

    const rawResults: StrettoChainResult[] = [];
    const MAX_RAW_RESULTS = 500; 

    // Define Available Capacity
    const ensembleTotal = options.ensembleTotal;
    const targetChainLength = options.targetChainLength;

    const validTranspositions = new Set(TRAD_TRANS);
    if (options.thirdSixthMode !== 'None') {
        THIRD_SIXTH_TRANS.forEach(t => validTranspositions.add(t));
    }

    const isBudgetAvailable = (mode: StrettoConstraintMode, currentUsage: number) => {
        if (mode === 'None') return false;
        if (mode === 'Max 1') return currentUsage < 1;
        return true; 
    };

    // Recursive Solver
    async function solve(
        chain: StrettoChainOption[], 
        nInv: number, n3rd: number, nTrunc: number,
        voiceEndTimes16: number[] 
    ) {
        if (rawResults.length >= MAX_RAW_RESULTS) return;

        // Success Condition
        if (chain.length === targetChainLength) {
            const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd);

            if (validation.valid) {
                // Scoring
                const log: ScoreLog = {
                    base: 0,
                    penalties: [],
                    bonuses: [],
                    total: 0
                };

                let score = 0; // Rebased to 0

                // 1. Polyphony Score
                // 300 * sum(active-1.5) / totalDuration
                if (validation.totalDuration > 0) {
                    const polyScore = 300 * (validation.polyphonyIntegral / validation.totalDuration);
                    score += polyScore;
                    log.bonuses.push({ reason: `Polyphony Density`, points: Math.round(polyScore) });
                }

                // 2. Dissonance Score
                if (validation.polyphonicDuration > 0) {
                    const weightedDiss = (1.0 * validation.bassDissDuration) + (0.8 * validation.upperDissDuration);
                    const ratio = weightedDiss / validation.polyphonicDuration;

                    if (ratio > 0.5) {
                        score -= 500;
                        log.penalties.push({ reason: `Excessive Dissonance (${(ratio*100).toFixed(0)}%)`, points: 500 });
                    } else if (ratio >= 0.2) {
                        // Sweet spot reward (0.2 to 0.4)
                        score += 300;
                        log.bonuses.push({ reason: `Rich Harmony (${(ratio*100).toFixed(0)}%)`, points: 300 });
                    } else if (ratio < 0.1) {
                        // Too bland
                        score -= 100;
                        log.penalties.push({ reason: `Bland Harmony (<10%)`, points: 100 });
                    }
                }

                // Penalties
                if (validation.warnings.length > 0) {
                    const p = validation.warnings.length * 100;
                    score -= p;
                    log.penalties.push({ reason: `${validation.warnings.length} Warnings`, points: p });
                }

                // Truncation Penalty
                chain.forEach((e, idx) => {
                    const diff16 = effectiveLen16 - e.length;
                    if (diff16 > 0) {
                        const p = (diff16 / 4) * 20;
                        score -= p;
                        log.penalties.push({ reason: `Truncation (V${idx+1})`, points: p });
                    }
                });

                // Analysis
                const intervals = new Set<number>();
                const intervalCounts: Record<number, number> = {};
                const distanceCounts: Record<string, number> = {};

                chain.forEach((e, i) => {
                    if (i === 0) return;
                    const prev = chain[i-1];

                    // Distance Calculations
                    const dist = e.startBeat - prev.startBeat;
                    const distStr = dist.toFixed(2);
                    distanceCounts[distStr] = (distanceCounts[distStr] || 0) + 1;

                    // Clumping Check (Repetitive distance)
                    if (i > 1) {
                        const prevPrev = chain[i-2];
                        const prevDist = prev.startBeat - prevPrev.startBeat;
                        if (Math.abs(dist - prevDist) < 0.01) {
                            score -= 100;
                            log.penalties.push({ reason: "Distance Clumping", points: 100 });
                        } else if (dist > prevDist) {
                            // "Punish mildly each increasing in distance"
                            score -= 50;
                            log.penalties.push({ reason: "Distance Expansion", points: 50 });
                        }
                    }

                    // Compactness Bonuses
                    const ratio = dist / subjectDurationBeats;
                    if (ratio <= 0.25) {
                        score += 50;
                        log.bonuses.push({ reason: `Hyper-Stretto (V${i+1})`, points: 50 });
                    } else if (ratio <= 0.5) {
                        score += 25;
                        log.bonuses.push({ reason: `Tight Stretto (V${i+1})`, points: 25 });
                    }

                    // Interval Analysis (Relative)
                    const relInt = e.transposition - prev.transposition;
                    intervals.add(relInt);
                    intervalCounts[relInt] = (intervalCounts[relInt] || 0) + 1;

                    // Absolute Analysis (for Variety)
                    const absInt = e.transposition;
                    const absSemi = Math.abs(absInt % 12);
                    if ([3,4,8,9].includes(absSemi)) {
                        score += 30;
                        log.bonuses.push({ reason: `3rd/6th Entry (V${i+1})`, points: 30 });
                    }
                });

                // Distance Variety Reward
                const uniqueDistances = Object.keys(distanceCounts).length;
                if (uniqueDistances > 1) {
                    const b = (uniqueDistances - 1) * 30;
                    score += b;
                    log.bonuses.push({ reason: `Distance Variety`, points: b });
                }

                const uniqueCount = intervals.size;
                if (uniqueCount > 1) {
                    const b = (uniqueCount - 1) * 40;
                    score += b;
                    log.bonuses.push({ reason: `Interval Variety (+${uniqueCount-1})`, points: b });
                }

                const totalLinks = chain.length - 1;
                if (totalLinks > 2) {
                    for (const k in intervalCounts) {
                        if (intervalCounts[k] > totalLinks * 0.5) {
                            score -= 100;
                            log.penalties.push({ reason: "Monotony (Interval Clumping)", points: 100 });
                            break;
                        }
                    }
                }

                if (nInv > 0) {
                    score += (nInv * 100);
                    log.bonuses.push({ reason: `${nInv} Inversions`, points: nInv * 100 });
                }

                const chainLenBonus = (chain.length - 2) * 10;
                if (chainLenBonus > 0) {
                    score += chainLenBonus;
                    log.bonuses.push({ reason: "Length Bonus", points: chainLenBonus });
                }

                log.total = Math.max(0, score);

                rawResults.push({
                    id: `chain-${Date.now()}-${rawResults.length}`,
                    entries: [...chain],
                    warnings: validation.warnings,
                    score: log.total,
                    scoreLog: log
                });
            }
            return;
        }

        const lastEntry = chain[chain.length - 1];

        // --- Elastic Distance Constraint ---
        // Rule: Delay can be up to 1 beat wider than previous delay.
        // BUT: If it expanded last time, it MUST contract this time.
        // ABSOLUTE LIMIT: Delay <= Subject Length / 2

        const halfSubject = subjectDurationBeats / 2;
        let maxDist = halfSubject; 
        let minDist = 0.5; // Minimum 1/8th note delay usually, set to 0.5 beat

        if (chain.length >= 2) {
            const prevEntry = chain[chain.length - 1];
            const prevPrevEntry = chain[chain.length - 2];
            const prevDelay = prevEntry.startBeat - prevPrevEntry.startBeat; 

            let expandedLastTime = false;

            // Check history for previous expansion
            if (chain.length >= 3) {
                const pppEntry = chain[chain.length - 3];
                const pppDelay = prevPrevEntry.startBeat - pppEntry.startBeat;
                if (prevDelay > pppDelay + 0.01) {
                    expandedLastTime = true;
                }
            }

            if (expandedLastTime) {
                // Mandatory Contraction: Must be strictly less than the expanded delay
                // To force contraction towards the original baseline
                maxDist = Math.max(minDist, prevDelay - 0.5); 
            } else {
                // Elastic Expansion: Can act up to prevDelay + 1
                const expansionLimit = prevDelay + 1.0;
                maxDist = Math.min(halfSubject, expansionLimit);
            }
        } else {
            // First entry distance constraints
            maxDist = halfSubject;
        }

        const startStep = Math.floor(minDist * 2);
        const endStep = Math.floor(maxDist * 2);

        // Loop backwards (prefer wider gaps to maximize cover, or narrower? 
        // Standard search usually prefers tightest first. Let's go tight->wide)
        for (let s = startStep; s <= endStep; s++) {
            const distBeats = s * 0.5;
            const newStart = lastEntry.startBeat + distBeats;

            // Check absolute transposition options
            // CONSTRAINT: "Intervals are always relative to the initial voice in terms of what is allowed"
            // Means we iterate validTranspositions as ABSOLUTE values, not relative to prev.

            const candidateTrans: number[] = Array.from(validTranspositions); 

            for (const absTrans of candidateTrans) {
                // CONSTRAINT: No Unison Chains (Relative P1 forbidden)
                if (absTrans === lastEntry.transposition) continue;

                // Voice Selection Logic
                // If T > 0: High Voice (0 to Subj-1)
                // If T < 0: Low Voice (Subj+1 to Total-1)
                // If T == 0: Any except Subj

                const validVoiceIndices: number[] = [];
                if (absTrans > 0) {
                    for(let v=0; v < options.subjectVoiceIndex; v++) validVoiceIndices.push(v);
                } else if (absTrans < 0) {
                    for(let v=options.subjectVoiceIndex+1; v < ensembleTotal; v++) validVoiceIndices.push(v);
                } else {
                    for(let v=0; v < ensembleTotal; v++) if(v !== options.subjectVoiceIndex) validVoiceIndices.push(v);
                }

                if (validVoiceIndices.length === 0) continue;

                // Check Voice Availability
                // Overlap Allowance: 1 beat (4 ticks of 16th grid at quarter=4) -> 4 units of 16th
                // Actually 1 beat = 1/4 note. Our timeline is 16ths. 1 beat = 4 units.
                const start16 = Math.round(newStart * 4);
                let assignedVoice = -1;

                // Pick FIRST available valid voice
                for (const v of validVoiceIndices) {
                    const lastEnd16 = voiceEndTimes16[v];
                    // Allow 1 beat overlap
                    const allowedStart16 = Math.max(0, lastEnd16 - 4); 

                    if (start16 >= allowedStart16) {
                        assignedVoice = v;
                        break;
                    }
                }

                if (assignedVoice === -1) continue; 

                // Budget Checks
                // Check if this Absolute Transposition implies a 3rd/6th relative to Subject?
                // Yes, absTrans IS relative to subject.
                // Or checking relative to previous?
                // User said "restrictions on 7ths and 2nds" and "Intervals always relative to initial".
                // So if absTrans is a 3rd or 6th, it consumes budget.

                const absSemi = Math.abs(absTrans % 12);
                const is3rd = [3,4,8,9].includes(absSemi);

                if (is3rd && !isBudgetAvailable(options.thirdSixthMode, n3rd)) continue;

                const types: {type: 'N'|'I', len: number, costInv: number, costTrunc: number}[] = [];
                types.push({ type: 'N', len: effectiveLen16, costInv: 0, costTrunc: 0 });
                if (isBudgetAvailable(options.inversionMode, nInv)) {
                    types.push({ type: 'I', len: effectiveLen16, costInv: 1, costTrunc: 0 });
                }
                if (isBudgetAvailable(options.truncationMode, nTrunc)) {
                    if (truncLen16 > 0 && truncLen16 < effectiveLen16) {
                        types.push({ type: 'N', len: truncLen16, costInv: 0, costTrunc: 1 });
                        if (isBudgetAvailable(options.inversionMode, nInv)) {
                            types.push({ type: 'I', len: truncLen16, costInv: 1, costTrunc: 1 });
                        }
                    }
                }

                for (const tOpt of types) {
                    const newEntry: StrettoChainOption = {
                        startBeat: newStart,
                        transposition: absTrans,
                        type: tOpt.type,
                        length: tOpt.len,
                        voiceIndex: assignedVoice
                    };

                    const testChain = [...chain, newEntry];
                    // Note: Full validation is expensive, done at end. 
                    // Intermediate steps just need basic voice availability which we checked.

                    // Update voice timeline
                    const newVoiceState = [...voiceEndTimes16];
                    const entryEnd16 = start16 + tOpt.len;
                    newVoiceState[assignedVoice] = Math.max(newVoiceState[assignedVoice], entryEnd16);

                    await solve(
                        testChain, 
                        nInv + tOpt.costInv, 
                        n3rd + (is3rd?1:0), 
                        nTrunc + tOpt.costTrunc,
                        newVoiceState
                    );

                    if (rawResults.length >= MAX_RAW_RESULTS) return;
                }
            }
            if (rawResults.length >= MAX_RAW_RESULTS) return;
        }
    }

    // Init Voice State
    const initialVoiceState = new Array(ensembleTotal).fill(0);
    // Set Subject Voice state
    initialVoiceState[options.subjectVoiceIndex] = effectiveLen16;

    // Start recursion
    await solve([{
        startBeat: 0,
        transposition: 0,
        type: 'N',
        length: effectiveLen16,
        voiceIndex: options.subjectVoiceIndex
    }], 0, 0, 0, initialVoiceState);

    const groups = new Map<string, StrettoChainResult[]>();

    rawResults.forEach(res => {
        const rhythmKey = res.entries.map(e => e.startBeat.toFixed(2)).join('|');
        if (!groups.has(rhythmKey)) groups.set(rhythmKey, []);
        groups.get(rhythmKey)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];

    groups.forEach((group) => {
        group.sort((a,b) => b.score - a.score);
        const leader = group[0];
        if (group.length > 1) leader.variations = group.slice(1);

        // Bonus for having variations (flexible chain)
        const flexBonus = Math.min(5, group.length - 1);
        if (flexBonus > 0 && leader.scoreLog) {
            leader.score += flexBonus;
            leader.scoreLog.bonuses.push({ reason: "Flexibility Bonus", points: flexBonus });
            leader.scoreLog.total += flexBonus;
        }

        finalResults.push(leader);
    });

    return finalResults.sort((a,b) => b.score - a.score).slice(0, 50);
}

import React, { useState } from 'react';
import { AppState } from './types';
