import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, ScoreLog } from '../../types';
import { getQuantizationTickValue } from './midiTransform';
import { SCORING, INTERVALS } from './strettoConstants';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';

// --- Helper Functions ---

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (INTERVALS.DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; // P4 against bass
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

// Inversion Logic
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

// --- Timeline & Validation ---

interface Timeline {
    // tick -> voice -> { pitch, dur16 (total duration of note in 16ths) }
    [tick16: number]: { [voiceIdx: number]: { pitch: number, dur16: number } }; 
}

interface InternalSubjectNote {
    relTick16: number; // 16th note grid relative to start
    dur16: number;
    pitch: number;
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalSubjectNote[] {
    const sorted = [...notes].sort((a,b) => a.ticks - b.ticks);
    if (sorted.length === 0) return [];
    const startTick = sorted[0].ticks;
    const ticksPer16 = ppq / 4;

    return sorted.map(n => ({
        relTick16: Math.round((n.ticks - startTick) / ticksPer16),
        dur16: Math.max(1, Math.round(n.durationTicks / ticksPer16)),
        pitch: n.midi
    }));
}

function getEffectiveSubjectLength16(notes: InternalSubjectNote[]): number {
    if (notes.length === 0) return 0;
    let maxEnd = 0;
    notes.forEach(n => {
        const end = n.relTick16 + n.dur16;
        if (end > maxEnd) maxEnd = end;
    });
    return maxEnd;
}

function getSubjectNotes(
    type: 'N' | 'I', 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    length16: number
): InternalSubjectNote[] {
    const source = type === 'N' ? baseSubject : invertedSubject;
    return source.filter(n => n.relTick16 < length16).map(n => ({
        ...n,
        dur16: Math.min(n.dur16, length16 - n.relTick16)
    }));
}

function buildTimeline(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): Timeline {
    const tl: Timeline = {};

    specs.forEach((spec) => {
        const notes = getSubjectNotes(spec.type, baseSubject, invertedSubject, spec.length);
        const start16 = Math.round(spec.startBeat * 4); // beats to 16ths

        notes.forEach(n => {
            for (let t = 0; t < n.dur16; t++) {
                const absTick = start16 + n.relTick16 + t;
                if (!tl[absTick]) tl[absTick] = {};
                tl[absTick][spec.voiceIndex] = { 
                    pitch: n.pitch + spec.transposition,
                    dur16: n.dur16 // Storing full duration for harmony filter
                };
            }
        });
    });

    return tl;
}

interface ValidationResult {
    isValid: boolean;
    errors: string[];
    warnings: string[];
    polyphonyIntegral: number;
    totalDuration: number;
    polyphonicDuration: number;
    bassDissDuration: number;
    upperDissDuration: number;
    harmonicReward: number;
    harmonicPenalty: number;
    detectedChords: string[];
}

function checkRulesAndStats(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[],
    requireConsonantEnd: boolean
): ValidationResult {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const errors: string[] = [];
    const warnings: string[] = [];

    const usedVoices = new Set<number>();
    specs.forEach(s => usedVoices.add(s.voiceIndex));
    const voices = Array.from(usedVoices).sort((a,b) => a-b);

    let polyphonyIntegral = 0;
    let totalDuration = 0;
    let polyphonicDuration = 0;
    let bassDissDuration = 0;
    let upperDissDuration = 0;

    // 1. Calculate Polyphony and Dissonance
    if (ticks.length > 0) {
        const minT = ticks[0];
        const maxT = ticks[ticks.length - 1];
        totalDuration = maxT - minT + 1;

        for (let t = minT; t <= maxT; t++) {
            const activeVoiceMap = tl[t];
            if (!activeVoiceMap) continue; 

            const activeCount = Object.keys(activeVoiceMap).length;

            if (activeCount > 0) {
                polyphonyIntegral += (activeCount - SCORING.POLYPHONY_OFFSET);
            }

            if (activeCount < 2) continue; 

            polyphonicDuration += 1;

            const pitches: number[] = [];
            const activeIndices = Object.keys(activeVoiceMap).map(Number);

            activeIndices.forEach(v => pitches.push(activeVoiceMap[v].pitch));
            pitches.sort((a,b) => a-b);

            const bassPitch = pitches[0];
            const bassVoiceIdx = parseInt(Object.keys(activeVoiceMap).find(k => activeVoiceMap[parseInt(k)].pitch === bassPitch) || "-1");

            // Check Intervals
            for (let i = 0; i < activeIndices.length; i++) {
                for (let j = i + 1; j < activeIndices.length; j++) {
                    const vA = activeIndices[i];
                    const vB = activeIndices[j];
                    const p1 = activeVoiceMap[vA].pitch;
                    const p2 = activeVoiceMap[vB].pitch;

                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    const isBassPair = (vA === bassVoiceIdx || vB === bassVoiceIdx);

                    if (isDissonant(lo, hi, isBassPair)) {
                        if (isBassPair) bassDissDuration += 1; 
                        else upperDissDuration += 1;
                    }
                }
            }
        }
    }

    // 2. Delegate Harmonic Analysis
    const { reward, penalty, chords } = analyzeStrettoHarmony(tl, ticks);

    // 3. Validation Checks (Parallel/Runs)
    for (let i = 0; i < voices.length; i++) {
        for (let j = i + 1; j < voices.length; j++) {
            const vA = voices[i];
            const vB = voices[j];

            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[vA] !== undefined && v[vB] !== undefined) {
                    const minAll = Math.min(...Object.values(v).map(d => d.pitch));
                    const p1 = v[vA].pitch;
                    const p2 = v[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1, p2 });
                }
            });

            if (sounding.length < 2) continue;

            // RULE 1: Parallel Perfect
            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];

                if (curr.t - prev.t > 1) continue;
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;

                if (isParallelPerfect(prev.lo, prev.hi) && isParallelPerfect(curr.lo, curr.hi)) {
                    const int1 = (prev.hi - prev.lo) % 12;
                    const int2 = (curr.hi - curr.lo) % 12;
                    if (int1 === int2) {
                        errors.push(`Parallel ${int1 === 7 ? '5th' : '8ve'} (V${vA+1}, V${vB+1})`);
                    }
                }
            }

            // RULE 2: Dissonance Runs
            let k = 0;
            while (k < sounding.length) {
                const startEv = sounding[k];
                if (!isDissonant(startEv.lo, startEv.hi, startEv.lowerIsBass)) {
                    k++; continue;
                }

                let segStart = k;
                while (k < sounding.length) {
                    const curr = sounding[k];
                    if (!isDissonant(curr.lo, curr.hi, curr.lowerIsBass)) break;

                    if ((curr.t - sounding[segStart].t + 1) >= 4) { // 1 Beat threshold
                        const distinctPitches = new Set<string>();
                        for(let m = segStart; m <= k; m++) distinctPitches.add(`${sounding[m].p1}-${sounding[m].p2}`);
                        if (distinctPitches.size > 1) {
                            errors.push(`Unresolved Dissonance Run (V${vA+1}, V${vB+1})`);
                            break; // Stop checking this run
                        }
                    }
                    k++;
                }
            }
        }
    }

    // 4. Consonant Termination
    if (requireConsonantEnd) {
        for (const spec of specs) {
            const start16 = Math.round(spec.startBeat * 4);
            const end16 = start16 + spec.length; 
            const checkTick = end16 - 1;
            const activeVoices = tl[checkTick];
            if (!activeVoices || Object.keys(activeVoices).length < 2) continue;

            const myData = activeVoices[spec.voiceIndex];
            if (!myData) continue;
            const myPitch = myData.pitch;

            let hasConsonance = false;
            for (const otherVStr in activeVoices) {
                const otherV = parseInt(otherVStr);
                if (otherV === spec.voiceIndex) continue;
                const otherPitch = activeVoices[otherV].pitch;
                const interval = Math.abs(myPitch - otherPitch) % 12;
                if (INTERVALS.CONSONANT.has(interval)) {
                    hasConsonance = true;
                    break;
                }
            }
            if (!hasConsonance) {
                errors.push(`Non-Consonant Ending (V${spec.voiceIndex+1})`);
            }
        }
    }

    return { 
        isValid: errors.length === 0, 
        errors,
        warnings, 
        polyphonyIntegral, 
        totalDuration, 
        polyphonicDuration,
        bassDissDuration,
        upperDissDuration,
        harmonicReward: reward,
        harmonicPenalty: penalty,
        detectedChords: chords
    };
}

// --- Search Algorithm ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoChainResult[]> {

    // Safety Break
    const START_TIME = Date.now();
    const TIME_LIMIT_MS = 10000;

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) return [];

    const effectiveLen16 = getEffectiveSubjectLength16(baseSubject);
    const subjectDurationBeats = effectiveLen16 / 4;

    const truncMusicalTicks = getQuantizationTickValue(options.truncationMusicalValue, ppq);
    const truncLen16 = Math.max(1, Math.round(truncMusicalTicks / (ppq / 4)));

    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        baseSubject.forEach(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi);
            if (inv !== null) invertedSubject.push({ ...n, pitch: inv });
        });
    }

    // Separate buffers for Valid and Invalid chains
    const validResults: StrettoChainResult[] = [];
    const invalidResults: StrettoChainResult[] = [];

    const MAX_VALID_RESULTS = 200; 
    const MAX_INVALID_BUFFER = 50; 

    const ensembleTotal = options.ensembleTotal;
    const targetChainLength = options.targetChainLength;

    const validTranspositions = new Set(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => validTranspositions.add(t));
    }

    const isBudgetAvailable = (mode: StrettoConstraintMode, currentUsage: number) => {
        if (mode === 'None') return false;
        if (mode === 'Max 1') return currentUsage < 1;
        return true; 
    };

    // Recursive Solver
    async function solve(
        chain: StrettoChainOption[], 
        nInv: number, n3rd: number, nTrunc: number,
        voiceEndTimes16: number[] 
    ) {
        if (validResults.length >= MAX_VALID_RESULTS) return;
        if (Date.now() - START_TIME > TIME_LIMIT_MS) return;

        // Success Condition
        if (chain.length === targetChainLength) {
            const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd);

            const log: ScoreLog = { base: 0, penalties: [], bonuses: [], total: 0 };
            let score = 0; 

            // 1. Polyphony
            if (validation.totalDuration > 0) {
                const avgScore = validation.polyphonyIntegral / validation.totalDuration;
                const polyScore = SCORING.POLYPHONY_BASE_MULT * avgScore;
                score += polyScore;
                log.bonuses.push({ reason: `Polyphony Density`, points: Math.round(polyScore) });
            }

            // 2. Dissonance
            if (validation.polyphonicDuration > 0) {
                const weightedDiss = (SCORING.DISS_WEIGHT_BASS * validation.bassDissDuration) + (SCORING.DISS_WEIGHT_UPPER * validation.upperDissDuration);
                const ratio = weightedDiss / validation.polyphonicDuration;

                if (ratio > SCORING.BUCKET_EXCESSIVE_THRESH) {
                    score += SCORING.BUCKET_EXCESSIVE_SCORE;
                    log.penalties.push({ reason: `Excessive Dissonance (${(ratio*100).toFixed(0)}%)`, points: Math.abs(SCORING.BUCKET_EXCESSIVE_SCORE) });
                } else if (ratio >= SCORING.BUCKET_SWEET_MIN && ratio <= SCORING.BUCKET_SWEET_MAX) {
                    score += SCORING.BUCKET_SWEET_SCORE;
                    log.bonuses.push({ reason: `Rich Harmony (${(ratio*100).toFixed(0)}%)`, points: SCORING.BUCKET_SWEET_SCORE });
                } else if (ratio < SCORING.BUCKET_BORING_THRESH) {
                    score += SCORING.BUCKET_BORING_SCORE;
                    log.penalties.push({ reason: `Bland Harmony (<10%)`, points: Math.abs(SCORING.BUCKET_BORING_SCORE) });
                }
            }

            // 3. Harmonic Quality
            if (validation.harmonicReward > 0) {
                score += validation.harmonicReward;
                log.bonuses.push({ reason: "Harmonic Quality", points: Math.round(validation.harmonicReward) });
            }
            if (validation.harmonicPenalty > 0) {
                score -= validation.harmonicPenalty;
                log.penalties.push({ reason: "NCT Clashing", points: Math.round(validation.harmonicPenalty) });
            }

            // 4. Distance/Structure
            const intervals = new Set<number>();
            const intervalCounts: Record<number, number> = {};
            const distanceCounts: Record<string, number> = {};

            chain.forEach((e, i) => {
                if (i === 0) return;
                const prev = chain[i-1];
                const dist = e.startBeat - prev.startBeat;
                const distStr = dist.toFixed(2);
                distanceCounts[distStr] = (distanceCounts[distStr] || 0) + 1;

                if (i > 1) {
                    const prevPrev = chain[i-2];
                    const prevDist = prev.startBeat - prevPrev.startBeat;
                    if (Math.abs(dist - prevDist) < 0.01) {
                        score += SCORING.DIST_CLUMPING_PENALTY;
                        log.penalties.push({ reason: "Distance Clumping", points: Math.abs(SCORING.DIST_CLUMPING_PENALTY) });
                    } else if (dist > prevDist) {
                        score += SCORING.DIST_EXPANSION_PENALTY;
                        log.penalties.push({ reason: "Distance Expansion", points: Math.abs(SCORING.DIST_EXPANSION_PENALTY) });
                    }
                }

                const ratio = dist / subjectDurationBeats;
                if (ratio <= SCORING.COMPACT_HYPER_THRESH) {
                    score += SCORING.COMPACT_HYPER_BONUS;
                    log.bonuses.push({ reason: `Hyper-Stretto (V${i+1})`, points: SCORING.COMPACT_HYPER_BONUS });
                } else if (ratio <= SCORING.COMPACT_TIGHT_THRESH) {
                    score += SCORING.COMPACT_TIGHT_BONUS;
                    log.bonuses.push({ reason: `Tight Stretto (V${i+1})`, points: SCORING.COMPACT_TIGHT_BONUS });
                }

                const relInt = e.transposition - prev.transposition;
                intervals.add(relInt);
                intervalCounts[relInt] = (intervalCounts[relInt] || 0) + 1;

                const absInt = e.transposition;
                const absSemi = Math.abs(absInt % 12);
                if ([3,4,8,9].includes(absSemi)) {
                    score += SCORING.IMPERFECT_CONS_BONUS;
                    log.bonuses.push({ reason: `3rd/6th Entry`, points: SCORING.IMPERFECT_CONS_BONUS });
                }
            });

            const uniqueDistances = Object.keys(distanceCounts).length;
            if (uniqueDistances > 1) {
                const b = (uniqueDistances - 1) * SCORING.DIST_VARIETY_BONUS;
                score += b;
                log.bonuses.push({ reason: `Distance Variety`, points: b });
            }

            if (nInv > 0) {
                score += (nInv * SCORING.INVERSION_BONUS);
                log.bonuses.push({ reason: `${nInv} Inversions`, points: nInv * SCORING.INVERSION_BONUS });
            }

            // --- Invalidity Penalties ---
            if (!validation.isValid) {
                // Apply massive penalty for fatal errors but still record it
                const fatalPenalty = validation.errors.length * 1000;
                score -= fatalPenalty;
                log.penalties.push({ reason: `${validation.errors.length} Fatal Rules Broken`, points: fatalPenalty });
            }

            log.total = Math.max(0, score);

            const resultObj: StrettoChainResult = {
                id: `chain-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
                entries: [...chain],
                warnings: [...validation.errors, ...validation.warnings], // Combine errors into warnings for display
                score: log.total,
                scoreLog: log,
                detectedChords: validation.detectedChords
            };

            if (validation.isValid) {
                validResults.push(resultObj);
            } else {
                // Manage Invalid Buffer: Keep only best N
                invalidResults.push(resultObj);
                invalidResults.sort((a,b) => b.score - a.score);
                if (invalidResults.length > MAX_INVALID_BUFFER) {
                    invalidResults.pop();
                }
            }
            return;
        }

        const lastEntry = chain[chain.length - 1];
        const halfSubject = subjectDurationBeats / 2;
        let maxDist = halfSubject; 
        let minDist = 0.5;

        if (chain.length >= 2) {
            const prevEntry = chain[chain.length - 1];
            const prevPrevEntry = chain[chain.length - 2];
            const prevDelay = prevEntry.startBeat - prevPrevEntry.startBeat; 

            let expandedLastTime = false;
            if (chain.length >= 3) {
                const pppEntry = chain[chain.length - 3];
                const pppDelay = prevPrevEntry.startBeat - pppEntry.startBeat;
                if (prevDelay > pppDelay + 0.01) expandedLastTime = true;
            }

            if (expandedLastTime) maxDist = Math.max(minDist, prevDelay - 0.5); 
            else maxDist = Math.min(halfSubject, prevDelay + 1.0);
        }

        const startStep = Math.floor(minDist * 2);
        const endStep = Math.floor(maxDist * 2);

        for (let s = startStep; s <= endStep; s++) {
            const distBeats = s * 0.5;
            const newStart = lastEntry.startBeat + distBeats;

            const candidateTrans: number[] = Array.from(validTranspositions); 

            for (const absTrans of candidateTrans) {
                if (absTrans === lastEntry.transposition) continue;

                // Simple voice selector (High vs Low)
                const validVoiceIndices: number[] = [];
                if (absTrans > 0) {
                    for(let v=0; v < options.subjectVoiceIndex; v++) validVoiceIndices.push(v);
                } else if (absTrans < 0) {
                    for(let v=options.subjectVoiceIndex+1; v < ensembleTotal; v++) validVoiceIndices.push(v);
                } else {
                    for(let v=0; v < ensembleTotal; v++) if(v !== options.subjectVoiceIndex) validVoiceIndices.push(v);
                }

                if (validVoiceIndices.length === 0) continue;

                const start16 = Math.round(newStart * 4);
                let assignedVoice = -1;

                // Pick FIRST available valid voice (Naive)
                for (const v of validVoiceIndices) {
                    const lastEnd16 = voiceEndTimes16[v];
                    const allowedStart16 = Math.max(0, lastEnd16 - 4); 
                    if (start16 >= allowedStart16) {
                        assignedVoice = v;
                        break;
                    }
                }

                if (assignedVoice === -1) continue; 

                // Budget Checks
                const absSemi = Math.abs(absTrans % 12);
                const is3rd = [3,4,8,9].includes(absSemi);
                if (is3rd && !isBudgetAvailable(options.thirdSixthMode, n3rd)) continue;

                const types: {type: 'N'|'I', len: number, costInv: number, costTrunc: number}[] = [];
                types.push({ type: 'N', len: effectiveLen16, costInv: 0, costTrunc: 0 });
                if (isBudgetAvailable(options.inversionMode, nInv)) {
                    types.push({ type: 'I', len: effectiveLen16, costInv: 1, costTrunc: 0 });
                }
                if (isBudgetAvailable(options.truncationMode, nTrunc)) {
                    if (truncLen16 > 0 && truncLen16 < effectiveLen16) {
                        types.push({ type: 'N', len: truncLen16, costInv: 0, costTrunc: 1 });
                        if (isBudgetAvailable(options.inversionMode, nInv)) {
                            types.push({ type: 'I', len: truncLen16, costInv: 1, costTrunc: 1 });
                        }
                    }
                }

                for (const tOpt of types) {
                    if (Date.now() - START_TIME > TIME_LIMIT_MS) return;

                    const newEntry: StrettoChainOption = {
                        startBeat: newStart,
                        transposition: absTrans,
                        type: tOpt.type,
                        length: tOpt.len,
                        voiceIndex: assignedVoice
                    };

                    const testChain = [...chain, newEntry];
                    const newVoiceState = [...voiceEndTimes16];
                    const entryEnd16 = start16 + tOpt.len;
                    newVoiceState[assignedVoice] = Math.max(newVoiceState[assignedVoice], entryEnd16);

                    await solve(
                        testChain, 
                        nInv + tOpt.costInv, 
                        n3rd + (is3rd?1:0), 
                        nTrunc + tOpt.costTrunc,
                        newVoiceState
                    );

                    if (validResults.length >= MAX_VALID_RESULTS) return;
                }
            }
        }
    }

    const initialVoiceState = new Array(ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = effectiveLen16;

    await solve([{
        startBeat: 0,
        transposition: 0,
        type: 'N',
        length: effectiveLen16,
        voiceIndex: options.subjectVoiceIndex
    }], 0, 0, 0, initialVoiceState);

    // Decision: If valid results exist, return them. Otherwise return best invalid.
    const resultsToReturn = validResults.length > 0 ? validResults : invalidResults;

    const groups = new Map<string, StrettoChainResult[]>();

    resultsToReturn.forEach(res => {
        const rhythmKey = res.entries.map(e => e.startBeat.toFixed(2)).join('|');
        if (!groups.has(rhythmKey)) groups.set(rhythmKey, []);
        groups.get(rhythmKey)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];

    groups.forEach((group) => {
        group.sort((a,b) => b.score - a.score);
        const leader = group[0];
        if (group.length > 1) leader.variations = group.slice(1);
        finalResults.push(leader);
    });

    return finalResults.sort((a,b) => b.score - a.score).slice(0, 50);
}

// Centralized constants for Stretto Generator

export const SCORING = {
    // 1. Polyphony
    // Formula: 300 * (Average Active Voices - 1.5)
    POLYPHONY_BASE_MULT: 300,
    POLYPHONY_OFFSET: 1.5,

    // 2. Dissonance (Proportional)
    DISS_WEIGHT_BASS: 1.0,
    DISS_WEIGHT_UPPER: 0.8,

    // New Proportional Logic
    DISS_PENALTY_START: 0.45, // Penalty kicks in at 45% dissonance ratio
    DISS_PENALTY_SLOPE: 2000, // Linear scalar for penalty (e.g. 55% = 0.1 over * 2000 = -200)

    BUCKET_SWEET_MIN: 0.2,
    BUCKET_SWEET_MAX: 0.4,
    BUCKET_SWEET_SCORE: 300,

    // 3. Distance / Rhythm
    DIST_CLUMPING_PENALTY: -400,   // Repeating same distance
    DIST_EXPANSION_PENALTY: -50,   // Increasing distance
    DIST_VARIETY_BONUS: 50,        // Per unique distance > 1

    // 4. Compactness (Bonuses)
    COMPACT_HYPER_THRESH: 0.25,
    COMPACT_HYPER_BONUS: 50,
    COMPACT_TIGHT_THRESH: 0.50,
    COMPACT_TIGHT_BONUS: 25,

    // 5. Structure
    INVERSION_BONUS: 100,
    CHAIN_LENGTH_BONUS: 10,
    TRUNCATION_PENALTY_PER_BEAT: 20,
    WARNING_PENALTY: 100,
    MONOTONY_PENALTY: 100, // Interval repetition
    IMPERFECT_CONS_BONUS: 30, // 3rds/6ths

    // 6. Harmonic Quality (New)
    HARMONY_ACTIVATION_VOICES: 3,
    HARMONY_MIN_DURATION_16THS: 2, // 8th note (assuming 4 16ths per beat)
    HARMONY_FULL_CHORD_REWARD: 20, // Per beat of full chord
    HARMONY_NCT_PENALTY_MULT: 10, // Per beat of NCT
};

export const INTERVALS = {
    // m2, M2, TT, m7, M7
    DISSONANT_SIMPLE: new Set([1, 2, 6, 10, 11]), 
    // P1, m3, M3, P5, m6, M6, P8
    CONSONANT: new Set([0, 3, 4, 7, 8, 9, 12]),

    THIRD_SIXTH_TRANSPOSITIONS: new Set([3, 4, 8, 9, -3, -4, -8, -9, 15, 16, 20, 21, -15, -16, -20, -21]),
    TRAD_TRANSPOSITIONS: new Set([0, 12, -12, 24, -24, 7, 19, -5, -17, 5, 17, -7, -19])
};

