import { getQuantizationTickValue } from './midiTransform';
import { SCORING, INTERVALS } from './strettoConstants';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';

// --- Helper Functions ---

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (INTERVALS.DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; // P4 against bass
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

// Inversion Logic
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

export function getAutoVoiceName(index: number, total: number): string {
    // Single Voice
    if (total <= 1) return "Voice 1";

    // Standard SATB
    if (total <= 4) {
        const standard = ["Soprano", "Alto", "Tenor", "Bass"];
        // Adjust map to fit count (e.g., 2 voices = S, B. 3 = S, A, B)
        if (total === 2) return index === 0 ? "Soprano" : "Bass";
        if (total === 3) return index === 2 ? "Bass" : standard[index];
        return standard[index];
    }

    // Extended Choral (S1, S2, A1, A2...)
    // Strategy: Distribute indices 0..N into buckets S, A, T, B
    const bucketSize = total / 4;
    const bucketIndex = Math.floor(index / bucketSize);
    const posInBucket = index - Math.floor(bucketIndex * bucketSize) + 1;

    let base = "";
    if (bucketIndex === 0) base = "Sop";
    else if (bucketIndex === 1) base = "Alt";
    else if (bucketIndex === 2) base = "Ten";
    else base = "Bass";

    // If bucket has more than 1 item, append number
    // Rough heuristic: with 8 voices, size=2. Index 0->S1, 1->S2.
    // With 5 voices, size=1.25. 0->S, 1->A, 2->A/T?, 3->T, 4->B.

    // Explicit 5-8 mapping for cleaner output
    if (total === 5) {
        return ["S1", "S2", "Alto", "Tenor", "Bass"][index];
    }
    if (total === 6) {
        return ["S1", "S2", "A1", "A2", "Ten", "Bass"][index];
    }
    if (total === 8) {
        return ["S1", "S2", "A1", "A2", "T1", "T2", "B1", "B2"][index];
    }

    return `${base}${posInBucket}`;
}

function getVoiceName(index: number, total: number, names?: Record<number, string>): string {
    if (names && names[index]) return names[index];
    return getAutoVoiceName(index, total);
}

// --- Timeline & Validation ---

interface Timeline {
    // tick -> voice -> { pitch, dur16 (total duration of note in 16ths) }
    [tick16: number]: { [voiceIdx: number]: { pitch: number, dur16: number } }; 
}

interface InternalSubjectNote {
    relTick16: number; // 16th note grid relative to start
    dur16: number;
    pitch: number;
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalSubjectNote[] {
    const sorted = [...notes].sort((a,b) => a.ticks - b.ticks);
    if (sorted.length === 0) return [];
    const startTick = sorted[0].ticks;
    const ticksPer16 = ppq / 4;

    return sorted.map(n => ({
        relTick16: Math.round((n.ticks - startTick) / ticksPer16),
        dur16: Math.max(1, Math.round(n.durationTicks / ticksPer16)),
        pitch: n.midi
    }));
}

function getEffectiveSubjectLength16(notes: InternalSubjectNote[]): number {
    if (notes.length === 0) return 0;
    let maxEnd = 0;
    notes.forEach(n => {
        const end = n.relTick16 + n.dur16;
        if (end > maxEnd) maxEnd = end;
    });
    return maxEnd;
}

function getSubjectNotes(
    type: 'N' | 'I', 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    length16: number
): InternalSubjectNote[] {
    const source = type === 'N' ? baseSubject : invertedSubject;
    return source.filter(n => n.relTick16 < length16).map(n => ({
        ...n,
        dur16: Math.min(n.dur16, length16 - n.relTick16)
    }));
}

function buildTimeline(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): Timeline {
    const tl: Timeline = {};

    specs.forEach((spec) => {
        const notes = getSubjectNotes(spec.type, baseSubject, invertedSubject, spec.length);
        const start16 = Math.round(spec.startBeat * 4); // beats to 16ths

        notes.forEach(n => {
            for (let t = 0; t < n.dur16; t++) {
                const absTick = start16 + n.relTick16 + t;
                if (!tl[absTick]) tl[absTick] = {};
                tl[absTick][spec.voiceIndex] = { 
                    pitch: n.pitch + spec.transposition,
                    dur16: n.dur16 // Storing full duration for harmony filter
                };
            }
        });
    });

    return tl;
}

interface ValidationResult {
    isValid: boolean;
    errors: string[];
    warnings: string[];
    polyphonyIntegral: number;
    totalDuration: number;
    polyphonicDuration: number;
    bassDissDuration: number;
    upperDissDuration: number;
    harmonicReward: number;
    harmonicPenalty: number;
    detectedChords: string[];
}

function checkRulesAndStats(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[],
    requireConsonantEnd: boolean,
    totalVoices: number,
    voiceNames?: Record<number, string>
): ValidationResult {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const errors: string[] = [];
    const warnings: string[] = [];

    const usedVoices = new Set<number>();
    specs.forEach(s => usedVoices.add(s.voiceIndex));
    const voices = Array.from(usedVoices).sort((a,b) => a-b);

    let polyphonyIntegral = 0;
    let totalDuration = 0;
    let polyphonicDuration = 0;
    let bassDissDuration = 0;
    let upperDissDuration = 0;

    // 1. Calculate Polyphony and Dissonance
    if (ticks.length > 0) {
        const minT = ticks[0];
        const maxT = ticks[ticks.length - 1];
        totalDuration = maxT - minT + 1;

        for (let t = minT; t <= maxT; t++) {
            const activeVoiceMap = tl[t];
            if (!activeVoiceMap) continue; 

            const activeCount = Object.keys(activeVoiceMap).length;

            if (activeCount > 0) {
                polyphonyIntegral += (activeCount - SCORING.POLYPHONY_OFFSET);
            }

            if (activeCount < 2) continue; 

            polyphonicDuration += 1;

            const pitches: number[] = [];
            const activeIndices = Object.keys(activeVoiceMap).map(Number);

            activeIndices.forEach(v => pitches.push(activeVoiceMap[v].pitch));
            pitches.sort((a,b) => a-b);

            const bassPitch = pitches[0];
            const bassVoiceIdx = parseInt(Object.keys(activeVoiceMap).find(k => activeVoiceMap[parseInt(k)].pitch === bassPitch) || "-1");

            // Check Intervals
            for (let i = 0; i < activeIndices.length; i++) {
                for (let j = i + 1; j < activeIndices.length; j++) {
                    const vA = activeIndices[i];
                    const vB = activeIndices[j];
                    const p1 = activeVoiceMap[vA].pitch;
                    const p2 = activeVoiceMap[vB].pitch;

                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    const isBassPair = (vA === bassVoiceIdx || vB === bassVoiceIdx);

                    if (isDissonant(lo, hi, isBassPair)) {
                        if (isBassPair) bassDissDuration += 1; 
                        else upperDissDuration += 1;
                    }
                }
            }
        }
    }

    // 2. Delegate Harmonic Analysis
    const { reward, penalty, chords } = analyzeStrettoHarmony(tl, ticks);

    // 3. Validation Checks (Parallel/Runs)
    for (let i = 0; i < voices.length; i++) {
        for (let j = i + 1; j < voices.length; j++) {
            const vA = voices[i];
            const vB = voices[j];

            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[vA] !== undefined && v[vB] !== undefined) {
                    const minAll = Math.min(...Object.values(v).map(d => d.pitch));
                    const p1 = v[vA].pitch;
                    const p2 = v[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1, p2 });
                }
            });

            if (sounding.length < 2) continue;

            // RULE 1: Parallel Perfect
            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];

                // Allow static intervals (no motion)
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;

                // Allow Oblique Motion (One voice static, other moving)
                const p1Moved = prev.p1 !== curr.p1;
                const p2Moved = prev.p2 !== curr.p2;
                if (!p1Moved || !p2Moved) continue; 

                // Check for Parallel Perfects (Both voices moving into a perfect interval)
                if (isParallelPerfect(curr.lo, curr.hi)) {
                    // Previous must also be perfect
                    if (isParallelPerfect(prev.lo, prev.hi)) {
                        const int1 = (prev.hi - prev.lo) % 12;
                        const int2 = (curr.hi - curr.lo) % 12;
                        if (int1 === int2) {
                            errors.push(`Parallel ${int1 === 7 ? '5th' : '8ve'} (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                        }
                    }
                }
            }

            // RULE 2: Dissonance Runs
            let k = 0;
            while (k < sounding.length) {
                const startEv = sounding[k];
                if (!isDissonant(startEv.lo, startEv.hi, startEv.lowerIsBass)) {
                    k++; continue;
                }

                let segStart = k;
                while (k < sounding.length) {
                    const curr = sounding[k];
                    if (!isDissonant(curr.lo, curr.hi, curr.lowerIsBass)) break;

                    if ((curr.t - sounding[segStart].t + 1) >= 4) { // 1 Beat threshold
                        const distinctPitches = new Set<string>();
                        for(let m = segStart; m <= k; m++) distinctPitches.add(`${sounding[m].p1}-${sounding[m].p2}`);
                        if (distinctPitches.size > 1) {
                            errors.push(`Unresolved Dissonance Run (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                            break; // Stop checking this run
                        }
                    }
                    k++;
                }
            }
        }
    }

    // 4. Consonant Termination
    if (requireConsonantEnd) {
        for (const spec of specs) {
            const start16 = Math.round(spec.startBeat * 4);
            const end16 = start16 + spec.length; 
            const checkTick = end16 - 1;
            const activeVoices = tl[checkTick];
            if (!activeVoices || Object.keys(activeVoices).length < 2) continue;

            const myData = activeVoices[spec.voiceIndex];
            if (!myData) continue;
            const myPitch = myData.pitch;

            let hasConsonance = false;
            for (const otherVStr in activeVoices) {
                const otherV = parseInt(otherVStr);
                if (otherV === spec.voiceIndex) continue;
                const otherPitch = activeVoices[otherV].pitch;
                const interval = Math.abs(myPitch - otherPitch) % 12;
                if (INTERVALS.CONSONANT.has(interval)) {
                    hasConsonance = true;
                    break;
                }
            }
            if (!hasConsonance) {
                errors.push(`Non-Consonant Ending (${getVoiceName(spec.voiceIndex, totalVoices, voiceNames)})`);
            }
        }
    }

    return { 
        isValid: errors.length === 0, 
        errors,
        warnings, 
        polyphonyIntegral, 
        totalDuration, 
        polyphonicDuration,
        bassDissDuration,
        upperDissDuration,
        harmonicReward: reward,
        harmonicPenalty: penalty,
        detectedChords: chords
    };
}

// --- Pre-Pass Discovery ---

interface ValidMove {
    transposition: number;
    delayBeats: number;
    type: 'N' | 'I';
    score: number;
}

function findValidPairwiseMoves(
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    options: StrettoSearchOptions, 
    validTranspositions: number[],
    effectiveLen16: number,
    subjectDurationBeats: number
): ValidMove[] {
    const validMoves: ValidMove[] = [];

    // We check Subject (Voice 0) vs Candidate (Voice 1)
    // Candidate enters at `delay` with `transposition`
    const voice0: StrettoChainOption = {
        startBeat: 0, transposition: 0, type: 'N', length: effectiveLen16, voiceIndex: 0
    };

    const delays: number[] = [];
    // UPDATED: Allow delays up to 2/3 of length (Subject + Entry 1,2,3 are allowed to be wide)
    const maxDelay = Math.max(0.5, subjectDurationBeats * (2/3));
    for(let d = 0.5; d <= maxDelay; d += 0.5) delays.push(d);

    const types: {type: 'N'|'I', source: InternalSubjectNote[]}[] = [];
    types.push({ type: 'N', source: baseSubject });
    if (options.inversionMode !== 'None' && invertedSubject.length > 0) {
        types.push({ type: 'I', source: invertedSubject });
    }

    // Optimization: Check every combination
    for (const d of delays) {
        for (const t of validTranspositions) {
            for (const typeObj of types) {
                // Construct pairwise check
                const voice1: StrettoChainOption = {
                    startBeat: d,
                    transposition: t,
                    type: typeObj.type,
                    length: effectiveLen16, // Use full length for check
                    voiceIndex: 1
                };

                const res = checkRulesAndStats([voice0, voice1], baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);

                if (res.isValid) {
                    // Heuristic scoring for sorting
                    // Prefer: High polyphony, Sweet Dissonance, Consonant End
                    let score = res.polyphonyIntegral;
                    if (res.bassDissDuration === 0) score += 50; 

                    validMoves.push({
                        transposition: t,
                        delayBeats: d,
                        type: typeObj.type,
                        score: score
                    });
                }
            }
        }
    }

    // Sort by best score
    return validMoves.sort((a,b) => b.score - a.score);
}

// --- Search Algorithm ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    // Safety Break
    const START_TIME = Date.now();
    const TIME_LIMIT_MS = 10000;
    const MAX_VISITED_NODES = 50000; 
    let nodesVisited = 0;
    let stopReason: 'Success' | 'Timeout' | 'NodeLimit' | 'Exhausted' = 'Exhausted';
    let maxDepthReached = 0;

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) {
        return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };
    }

    const effectiveLen16 = getEffectiveSubjectLength16(baseSubject);
    const subjectDurationBeats = effectiveLen16 / 4;

    const truncMusicalTicks = getQuantizationTickValue(options.truncationMusicalValue, ppq);
    const truncLen16 = Math.max(1, Math.round(truncMusicalTicks / (ppq / 4)));

    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        baseSubject.forEach(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi);
            if (inv !== null) invertedSubject.push({ ...n, pitch: inv });
        });
    }

    const validResults: StrettoChainResult[] = [];
    const invalidResults: StrettoChainResult[] = [];
    const partialResults: StrettoChainResult[] = [];

    const MAX_VALID_RESULTS = 200; 
    const MAX_INVALID_BUFFER = 50; 

    const ensembleTotal = options.ensembleTotal;
    const targetChainLength = options.targetChainLength;

    // Transpositions to check - Ordered with negatives early per user request
    const preferredOrder = [0, 12, -12, 7, -7, 5, -5, 24, -24];
    const validTranspositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS).sort((a,b) => {
        const idxA = preferredOrder.indexOf(a);
        const idxB = preferredOrder.indexOf(b);
        const valA = idxA === -1 ? 999 : idxA;
        const valB = idxB === -1 ? 999 : idxB;
        return valA - valB;
    });

    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => {
            if (!validTranspositions.includes(t)) validTranspositions.push(t);
        });
    }

    // 1. Perform Pairwise Pre-Pass
    const safeMoves = findValidPairwiseMoves(baseSubject, invertedSubject, options, validTranspositions, effectiveLen16, subjectDurationBeats);

    const isBudgetAvailable = (mode: StrettoConstraintMode, currentUsage: number) => {
        if (mode === 'None') return false;
        if (mode === 'Max 1') return currentUsage < 1;
        return true; 
    };

    function processChain(chain: StrettoChainOption[], validation: ValidationResult, targetList: StrettoChainResult[]) {
        const log: ScoreLog = { base: 0, penalties: [], bonuses: [], total: 0 };
        let score = 0; 

        // 1. Polyphony
        if (validation.totalDuration > 0) {
            const avgScore = validation.polyphonyIntegral / validation.totalDuration;
            const polyScore = SCORING.POLYPHONY_BASE_MULT * avgScore;
            score += polyScore;
            log.bonuses.push({ reason: `Polyphony Density`, points: Math.round(polyScore) });
        }

        // 2. Dissonance (Proportional)
        if (validation.polyphonicDuration > 0) {
            const weightedDiss = (SCORING.DISS_WEIGHT_BASS * validation.bassDissDuration) + (SCORING.DISS_WEIGHT_UPPER * validation.upperDissDuration);
            const ratio = weightedDiss / validation.polyphonicDuration;

            if (ratio > SCORING.DISS_PENALTY_START) {
                const excess = ratio - SCORING.DISS_PENALTY_START;
                const penalty = excess * SCORING.DISS_PENALTY_SLOPE;
                score -= penalty;
                log.penalties.push({ reason: `Dissonance ${(ratio*100).toFixed(0)}%`, points: Math.round(penalty) });
            } else if (ratio >= SCORING.BUCKET_SWEET_MIN && ratio <= SCORING.BUCKET_SWEET_MAX) {
                score += SCORING.BUCKET_SWEET_SCORE;
                log.bonuses.push({ reason: `Rich Harmony (${(ratio*100).toFixed(0)}%)`, points: SCORING.BUCKET_SWEET_SCORE });
            }
        }

        // 3. Harmonic Quality
        if (validation.harmonicReward > 0) {
            score += validation.harmonicReward;
            log.bonuses.push({ reason: "Harmonic Quality", points: Math.round(validation.harmonicReward) });
        }
        if (validation.harmonicPenalty > 0) {
            score -= validation.harmonicPenalty;
            log.penalties.push({ reason: "NCT Clashing", points: Math.round(validation.harmonicPenalty) });
        }

        // 4. Distance/Structure Scoring (For remaining valid chains)
        const distanceCounts: Record<string, number> = {};
        chain.forEach((e, i) => {
            if (i === 0) return;
            const prev = chain[i-1];
            const dist = e.startBeat - prev.startBeat;
            const distStr = dist.toFixed(2);
            distanceCounts[distStr] = (distanceCounts[distStr] || 0) + 1;

            const ratio = dist / subjectDurationBeats;
            if (ratio <= SCORING.COMPACT_HYPER_THRESH) {
                score += SCORING.COMPACT_HYPER_BONUS;
                log.bonuses.push({ reason: `Hyper-Stretto (V${i+1})`, points: SCORING.COMPACT_HYPER_BONUS });
            } else if (ratio <= SCORING.COMPACT_TIGHT_THRESH) {
                score += SCORING.COMPACT_TIGHT_BONUS;
                log.bonuses.push({ reason: `Tight Stretto (V${i+1})`, points: SCORING.COMPACT_TIGHT_BONUS });
            }

            const absInt = e.transposition;
            const absSemi = Math.abs(absInt % 12);
            if ([3,4,8,9].includes(absSemi)) {
                score += SCORING.IMPERFECT_CONS_BONUS;
                log.bonuses.push({ reason: `3rd/6th Entry`, points: SCORING.IMPERFECT_CONS_BONUS });
            }
        });

        const uniqueDistances = Object.keys(distanceCounts).length;
        if (uniqueDistances > 1) {
            const b = (uniqueDistances - 1) * SCORING.DIST_VARIETY_BONUS;
            score += b;
            log.bonuses.push({ reason: `Distance Variety`, points: b });
        }

        // --- Invalidity Penalties ---
        if (!validation.isValid) {
            const fatalPenalty = validation.errors.length * 1000;
            score -= fatalPenalty;
            log.penalties.push({ reason: `${validation.errors.length} Fatal Rules Broken`, points: fatalPenalty });
        }

        // Length Bonus (for partials)
        if (chain.length < targetChainLength) {
            const missing = targetChainLength - chain.length;
            score -= (missing * 50); // Penalty for shortness
        }

        log.total = Math.max(0, score);

        const resultObj: StrettoChainResult = {
            id: `chain-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            entries: [...chain],
            warnings: [...validation.errors, ...validation.warnings],
            score: log.total,
            scoreLog: log,
            detectedChords: validation.detectedChords
        };

        targetList.push(resultObj);
        targetList.sort((a,b) => b.score - a.score);
        if (targetList.length > MAX_INVALID_BUFFER) {
            targetList.pop();
        }
    }

    // Recursive Solver
    async function solve(
        chain: StrettoChainOption[], 
        nInv: number, n3rd: number, nTrunc: number,
        voiceEndTimes16: number[] 
    ) {
        nodesVisited++;
        if (chain.length > maxDepthReached) maxDepthReached = chain.length;

        if (validResults.length >= MAX_VALID_RESULTS) {
            stopReason = 'Success';
            return;
        }
        if (Date.now() - START_TIME > TIME_LIMIT_MS) {
            stopReason = 'Timeout';
            return;
        }
        if (nodesVisited > MAX_VISITED_NODES) {
            stopReason = 'NodeLimit';
            return;
        }

        // Leaf / Termination Check
        if (chain.length === targetChainLength) {
            const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
            if (validation.isValid) processChain(chain, validation, validResults);
            else processChain(chain, validation, invalidResults);
            return;
        }

        const lastEntry = chain[chain.length - 1];

        let extensionsFound = false;

        // --- Active Voice Transposition Map ---
        // Build map of the most recent transposition for every used voice in the chain
        const lastTranspositions = new Map<number, number>();
        chain.forEach(entry => {
            lastTranspositions.set(entry.voiceIndex, entry.transposition);
        });

        for (const move of safeMoves) {
            // Check global conditions first
            if (stopReason !== 'Exhausted') break;

            const newStart = lastEntry.startBeat + move.delayBeats;

            // --- DISTANCE LOGIC & CONSTRAINTS ---
            if (chain.length >= 2) {
                const prevDist = lastEntry.startBeat - chain[chain.length - 2].startBeat;
                const newDist = move.delayBeats;

                // 1. HARD: Global Uniqueness of Distance
                // No distance can be repeated anywhere in the chain.
                let isUnique = true;
                for (let k = 1; k < chain.length; k++) {
                    const existingDist = chain[k].startBeat - chain[k-1].startBeat;
                    if (Math.abs(existingDist - newDist) < 0.01) {
                        isUnique = false;
                        break;
                    }
                }
                if (!isUnique) continue;

                // 2. HARD: Elasticity Limit (Max +1.0)
                if (newDist > prevDist + 1.0 + 0.01) continue;

                // 3. HARD: Expansion Reaction
                if (chain.length >= 3) {
                    const prevPrevDist = chain[chain.length - 2].startBeat - chain[chain.length - 3].startBeat;
                    if (prevDist > prevPrevDist + 0.01) {
                        // Must contract
                        if (newDist > prevPrevDist - 1.0 + 0.01) continue;
                    }
                }
            }

            // 4. CONDITIONAL: Distance Cap (2/3 vs 1/2)
            // Indices 1..(Floor(N/2)) can be long (<= 2/3)
            // Indices (Floor(N/2)+1)..N must be short (<= 1/2)
            const entryIndex = chain.length + 1; // 1-based index (Subject is 1)
            const constraintThreshold = Math.floor(targetChainLength / 2) + 1;

            const maxDelayEarly = subjectDurationBeats * (2/3);
            const maxDelayLate = subjectDurationBeats * 0.5;
            const limit = entryIndex >= constraintThreshold ? maxDelayLate : maxDelayEarly;

            if (move.delayBeats > limit) continue;

            // Simple voice selector
            const absTrans = move.transposition; // Absolute

            if (absTrans === lastEntry.transposition) continue; // Unison chain constraint

            const start16 = Math.round(newStart * 4);
            let assignedVoice = -1;

            // --- STRICT VOICE ASSIGNMENT LOOP ---
            // Check every possible voice index
            for (let v = 0; v < ensembleTotal; v++) {
                // 1. Time Availability Check
                const lastEnd16 = voiceEndTimes16[v];
                const allowedStart16 = Math.max(0, lastEnd16 - 4); // 1 beat overlap allowed
                if (start16 < allowedStart16) continue; // Busy

                // 2. Crossing / Interval Constraints (Relative to neighbors)
                // Check Immediate Below (v+1)
                if (lastTranspositions.has(v + 1)) {
                    // T(v) >= T(v+1)
                    if (absTrans < lastTranspositions.get(v + 1)!) continue;
                }

                // Check Immediate Above (v-1)
                if (lastTranspositions.has(v - 1)) {
                    // T(v) <= T(v-1)
                    if (absTrans > lastTranspositions.get(v - 1)!) continue;
                }

                // Check Two Below (v+2)
                if (lastTranspositions.has(v + 2)) {
                    // T(v) >= T(v+2) + 12 (Octave clearance)
                    if (absTrans < lastTranspositions.get(v + 2)! + 12) continue;
                }

                // Check Two Above (v-2)
                if (lastTranspositions.has(v - 2)) {
                    // T(v) <= T(v-2) - 12 (Octave clearance)
                    if (absTrans > lastTranspositions.get(v - 2)! - 12) continue;
                }

                // If passed all checks, this voice is valid
                assignedVoice = v;
                break; // Take the first valid voice (usually highest available due to 0..N loop)
            }

            if (assignedVoice === -1) continue; 

            // Budget Checks
            const absSemi = Math.abs(absTrans % 12);
            const is3rd = [3,4,8,9].includes(absSemi);
            if (is3rd && !isBudgetAvailable(options.thirdSixthMode, n3rd)) continue;

            const costInv = move.type === 'I' ? 1 : 0;
            if (costInv > 0 && !isBudgetAvailable(options.inversionMode, nInv)) continue;

            const len = effectiveLen16; 

            const newEntry: StrettoChainOption = {
                startBeat: newStart,
                transposition: absTrans,
                type: move.type,
                length: len,
                voiceIndex: assignedVoice
            };

            const testChain = [...chain, newEntry];
            const newVoiceState = [...voiceEndTimes16];
            const entryEnd16 = start16 + len;
            newVoiceState[assignedVoice] = Math.max(newVoiceState[assignedVoice], entryEnd16);

            extensionsFound = true;
            await solve(
                testChain, 
                nInv + costInv, 
                n3rd + (is3rd?1:0), 
                nTrunc, // Not handling truncation in pre-pass yet
                newVoiceState
            );

            if (validResults.length >= MAX_VALID_RESULTS) return;
        }

        // Partial Chain Fallback
        if (!extensionsFound && chain.length >= 3) {
             const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
             processChain(chain, validation, partialResults);
        }
    }

    const initialVoiceState = new Array(ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = effectiveLen16;

    await solve([{
        startBeat: 0,
        transposition: 0,
        type: 'N',
        length: effectiveLen16,
        voiceIndex: options.subjectVoiceIndex
    }], 0, 0, 0, initialVoiceState);

    // Decision Logic: Valid > Partial > Invalid
    let resultsToReturn = validResults;
    if (resultsToReturn.length === 0) resultsToReturn = partialResults;
    if (resultsToReturn.length === 0) resultsToReturn = invalidResults;

    const groups = new Map<string, StrettoChainResult[]>();

    resultsToReturn.forEach(res => {
        const rhythmKey = res.entries.map(e => e.startBeat.toFixed(2)).join('|');
        if (!groups.has(rhythmKey)) groups.set(rhythmKey, []);
        groups.get(rhythmKey)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];

    groups.forEach((group) => {
        group.sort((a,b) => b.score - a.score);
        const leader = group[0];
        if (group.length > 1) leader.variations = group.slice(1);
        finalResults.push(leader);
    });

    return {
        results: finalResults.sort((a,b) => b.score - a.score).slice(0, 50),
        stats: {
            nodesVisited,
            timeMs: Date.now() - START_TIME,
            stopReason: validResults.length > 0 ? 'Success' : stopReason,
            maxDepthReached
        }
    };
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate } from './services/strettoExport';
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames }: StrettoViewProps) {
    // Default to ABC mode if no MIDI notes were passed in
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");

    // Default to Chain view
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    // -- Library State --
    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, 
        requireConsonantEnd: true
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Load Library on Mount
    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try {
                setSavedSubjects(JSON.parse(saved));
            } catch (e) {
                console.error("Failed to load library", e);
            }
        }
    }, []);

    // Save Library Logic
    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = {
            id: Date.now().toString(),
            name: saveName.trim(),
            data: abcInput
        };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => {
        setAbcInput(data);
    };

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const durationTicks = Math.max(...subjectNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                // Normal
                candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts, false, 60));
                // Inverted
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(subjectNotes, interval, Math.round(d), ppq, ts, true, searchOptions.pivotMidi));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode, searchOptions.pivotMidi]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSearchReport(null);
        setSelectedChain(null);

        setTimeout(async () => {
            try {
                // Merge voiceNames into searchOptions
                const optionsWithNames = { ...searchOptions, voiceNames };
                const report = await searchStrettoChains(subjectNotes, optionsWithNames, ppq);
                setChainResults(report.results);
                setSearchReport(report);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];

        const sortedSubj = [...subjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry, idx) => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, 
                    midi: pitch,
                    name: getStrictPitchName(pitch),
                    voiceIndex: entry.voiceIndex,
                    durationTicks: n.durationTicks 
                };
            });

            // Apply truncation
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            voices.push(clipped);
            allNotes = [...allNotes, ...clipped];
        });

        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const vA = voices[i];
            const vB = voices[i+1];
            const events = getVerticalIntervals(vA, vB);
            const regions = generateHarmonicRegions(events);
            chainRegions = [...chainRegions, ...regions];
        }

        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], 
            notes: allNotes,
            regions: chainRegions 
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.map(n => ({
            name: n.name, 
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    const handleDownloadChain = () => {
        if (chainToCandidate) {
            downloadStrettoCandidate(chainToCandidate, ppq);
        } else {
            alert("No chain selected.");
        }
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                            <span className="text-[10px] text-gray-500 font-mono hidden sm:inline">Supports M: (Meter), L: (Length), Q: (Tempo), K: (Key)</span>
                        </div>
                        <button 
                            onClick={() => setShowLibrary(!showLibrary)}
                            className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors"
                        >
                            <DocumentTextIcon className="w-3 h-3" />
                            {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>

                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input 
                                    type="text" 
                                    placeholder="Subject Name..." 
                                    value={saveName}
                                    onChange={(e) => setSaveName(e.target.value)}
                                    className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white focus:border-brand-primary outline-none"
                                />
                                <button 
                                    onClick={handleSaveSubject}
                                    disabled={!saveName.trim()}
                                    className="bg-brand-primary hover:bg-brand-secondary disabled:bg-gray-600 text-white px-4 py-1 rounded text-sm font-bold transition-colors"
                                >
                                    Save
                                </button>
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length === 0 ? (
                                    <p className="text-xs text-gray-500 col-span-full text-center py-2">No saved subjects yet.</p>
                                ) : (
                                    savedSubjects.map(s => (
                                        <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
                                            <span className="text-sm font-bold text-gray-300 truncate mr-2" title={s.name}>{s.name}</span>
                                            <div className="flex gap-1 opacity-50 group-hover:opacity-100 transition-opacity">
                                                <button 
                                                    onClick={() => handleLoadSubject(s.data)}
                                                    className="text-[10px] bg-brand-secondary/50 hover:bg-brand-secondary text-white px-2 py-0.5 rounded"
                                                >
                                                    Load
                                                </button>
                                                <button 
                                                    onClick={() => handleDeleteSubject(s.id)}
                                                    className="text-[10px] bg-red-900/50 hover:bg-red-700 text-red-200 px-2 py-0.5 rounded"
                                                >
                                                    ×
                                                </button>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}

                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="M:4/4\nL:1/4\nK:C\nc2 G c d e f g"
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                        includeInversions={includeInversions}
                        setIncludeInversions={setIncludeInversions}
                        includeExtensions={includeExtensions}
                        setIncludeExtensions={setIncludeExtensions}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            selectedId={selectedCandidate?.id || null}
                            onSelect={setSelectedCandidate}
                            checkedIds={checkedIds}
                            onToggleCheck={toggleCheck}
                        />

                        <StrettoInspector 
                            candidate={selectedCandidate}
                            ppq={ppq}
                            ts={ts}
                            isPlaying={isPlaying}
                            onPlay={handlePlay}
                            assemblyResult={assemblyResult}
                            assemblyLog={assemblyLog}
                            onClearAssembly={() => setAssemblyResult('')}
                            onDownloadChain={() => {}} 
                        />
                    </div>

                    <StrettoFooter 
                        selectedCandidates={getSelectedCandidates()}
                        onDownloadMidi={() => {}}
                        onAssemble={triggerAssembly}
                        isAssembling={isAssembling}
                        onRemoveCandidate={toggleCheck}
                    />
                </>
            ) : (
                <StrettoChainView 
                    searchOptions={searchOptions}
                    setSearchOptions={setSearchOptions}
                    onSearch={handleChainSearch}
                    isSearching={isSearching}
                    chainResults={chainResults}
                    selectedChain={selectedChain}
                    setSelectedChain={setSelectedChain}
                    voiceNames={voiceNames}
                    chainToCandidate={chainToCandidate}
                    ppq={ppq}
                    ts={ts}
                    isPlaying={isPlaying}
                    onPlay={handlePlay}
                    onDownloadChain={handleDownloadChain}
                    searchReport={searchReport}
                />
            )}
        </div>
    );
}

import React from 'react';
import { StrettoSearchOptions, StrettoChainResult, StrettoCandidate, RawNote, StrettoSearchReport } from '../../types';
import StrettoSearchPanel from './StrettoSearchPanel';
import StrettoResultsList from './StrettoResultsList';
import StrettoInspector from './StrettoInspector';

interface StrettoChainViewProps {
    searchOptions: StrettoSearchOptions;
    setSearchOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    chainResults: StrettoChainResult[];
    selectedChain: StrettoChainResult | null;
    setSelectedChain: (res: StrettoChainResult | null) => void;
    voiceNames?: Record<number, string>;

    // Inspector Props
    chainToCandidate: StrettoCandidate | null;
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    onDownloadChain: () => void;
    searchReport?: StrettoSearchReport | null;
}

export default function StrettoChainView({
    searchOptions, setSearchOptions, onSearch, isSearching,
    chainResults, selectedChain, setSelectedChain, voiceNames,
    chainToCandidate, ppq, ts, isPlaying, onPlay, onDownloadChain,
    searchReport
}: StrettoChainViewProps) {
    return (
        <>
            <StrettoSearchPanel 
                options={searchOptions} 
                setOptions={setSearchOptions}
                onSearch={onSearch}
                isSearching={isSearching}
            />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                    <div className="p-3 border-b border-gray-700 bg-gray-800 flex justify-between items-center">
                        <h3 className="text-xs font-bold text-gray-400">FOUND CHAINS ({chainResults.length})</h3>
                        {searchReport && (
                            <div className="text-[9px] text-gray-500 text-right">
                                {searchReport.stats.nodesVisited.toLocaleString()} nodes in {searchReport.stats.timeMs}ms
                            </div>
                        )}
                    </div>
                    {searchReport && searchReport.stats.stopReason !== 'Success' && (
                        <div className="bg-yellow-900/30 border-b border-yellow-800 p-2 text-[10px] text-yellow-300">
                            <strong>Search {searchReport.stats.stopReason}:</strong> No valid chains of length {searchOptions.targetChainLength} found.
                            Showing partial chains (Max Depth: {searchReport.stats.maxDepthReached}).
                        </div>
                    )}
                    <StrettoResultsList 
                        results={chainResults}
                        selectedId={selectedChain?.id || null}
                        onSelect={setSelectedChain}
                        voiceNames={voiceNames}
                    />
                </div>
                <div className="lg:col-span-2">
                    <StrettoInspector 
                        candidate={chainToCandidate}
                        ppq={ppq}
                        ts={ts}
                        isPlaying={isPlaying}
                        onPlay={onPlay}
                        assemblyResult={""}
                        assemblyLog={[]}
                        onClearAssembly={() => {}}
                        onDownloadChain={onDownloadChain}
                    />
                </div>
            </div>
        </>
    );
}

export interface TrackInfo {
  id: number;
  name: string;
  instrument: {
    name: string;
    number: number;
    family: string;
  };
  noteCount: number;
  ornamentCount?: number;
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  LOADED = 'LOADED',
  ERROR = 'ERROR',
  GENERATING = 'GENERATING', 
  SUCCESS = 'SUCCESS',
}

export type MidiEventType = 'pitchBend' | 'controlChange' | 'programChange';

export interface MidiEventCounts {
  pitchBend: number;
  controlChange: number;
  programChange: number;
}

export type TempoChangeMode = 'speed' | 'time';

export type InversionMode = 'off' | 'global' | '1beat' | '2beats' | 'measure' | '2measures' | '4measures' | '8measures';

export type OutputStrategy = 'combine' | 'separate_tracks' | 'separate_voices';

export type VoiceAssignmentMode = 'auto' | 'manual'; 

export type RhythmFamily = 'Simple' | 'Triple' | 'Quintuplet';

